/* AUTO-GENERATED — Alabama Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["AL"] = {"code":"AL","name":"Alabama","agency":"Alabama ALEA","agencyShort":"ALEA","handbook":"https://www.alea.gov/sites/default/files/CDL%20Manuals%204.9.24.pdf","links":{},"en":[{"q":"On Alabama highways with traffic lanes 12 feet or more in width, what is the maximum total outside width of a vehicle, including its load (excluding mirrors and safety devices)?","options":["96 inches","100 inches","102 inches","108 inches"],"answer":2,"explanation":"Alabama Code 32-9-20(1) sets the maximum width at 102 inches (8 feet 6 inches), including load, on highways with lanes 12 feet or wider, exclusive of mirrors and safety devices. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"What is the maximum legal height, including load, for a vehicle, semitrailer, or trailer on Alabama highways?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"answer":1,"explanation":"Alabama Code 32-9-20(2) prohibits any vehicle, semitrailer, or trailer from exceeding 13 1/2 feet (13 feet 6 inches) in height, including the load. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"In Alabama, what is the maximum gross weight imposed on the highway by the wheels of any one (single) axle?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"answer":1,"explanation":"Alabama Code 32-9-20(4) limits any single axle to 20,000 pounds, consistent with the federal standard under 23 U.S.C. 127. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"What is the maximum allowable weight on a tandem axle group on the Interstate Highway System in Alabama?","options":["32,000 pounds","34,000 pounds","36,000 pounds","38,000 pounds"],"answer":1,"explanation":"Alabama Code 32-9-20(4) limits tandem axle weight on the Interstate Highway System to 34,000 pounds, including all enforcement tolerances, matching the federal limit. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"What is the maximum overall gross weight for a vehicle or combination of vehicles on the Interstate Highway System in Alabama, including all enforcement tolerances?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"answer":1,"explanation":"Alabama Code 32-9-20(4) caps overall gross weight at 80,000 pounds, including all enforcement tolerances, on the Interstate System, consistent with 23 U.S.C. 127. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"What is the maximum length of a single (straight) vehicle on Alabama highways?","options":["35 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"Alabama Code 32-9-20(3) states that no single vehicle shall exceed 40 feet in length. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"In a truck tractor-semitrailer combination in Alabama, what is the maximum length of the semitrailer, including load?","options":["48 feet","53 feet","57 feet","65 feet"],"answer":2,"explanation":"Alabama Code 32-9-20(3) provides that the semitrailer, including load, used in a truck tractor-semitrailer combination shall not exceed 57 feet. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"On highways with traffic lanes LESS than 12 feet wide in Alabama, what is the maximum total outside width of a vehicle, including load?","options":["90 inches","96 inches","102 inches","108 inches"],"answer":1,"explanation":"Alabama Code 32-9-20(1) reduces the maximum width to 96 inches, including load, on highways whose traffic lanes are less than 12 feet wide. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"In a truck tractor-semitrailer-trailer (twin trailer) combination in Alabama, what is the maximum length of each semitrailer or trailer, including load?","options":["27 feet","28 1/2 feet","30 feet","33 feet"],"answer":1,"explanation":"Alabama Code 32-9-20(3) limits each semitrailer or trailer in a truck tractor-semitrailer-trailer (twin) combination to 28 1/2 feet, including load. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"What is the maximum length of a motor vehicle commonly called a motor home on Alabama highways?","options":["40 feet","45 feet","53 feet","57 feet"],"answer":1,"explanation":"Alabama Code 32-9-20(3) provides that motor vehicles commonly called motor homes shall not exceed 45 feet in length. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"When hauling forest products or culvert pipe on an Alabama highway, what is the maximum legal load width without a permit?","options":["96 inches","102 inches","108 inches","120 inches"],"answer":1,"explanation":"Alabama Code 32-9-20(1) specifically states that no vehicle hauling forest products or culvert pipe on any highway shall have a load exceeding 102 inches in width. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"Two consecutive sets of tandem axles in Alabama may each carry a gross load of 34,000 pounds provided the distance between the first and last axles of the consecutive sets is at least how many feet?","options":["30 feet","34 feet","36 feet","41 feet"],"answer":2,"explanation":"Alabama Code 32-9-20(4) allows two consecutive sets of tandem axles to each carry 34,000 pounds if the overall distance between the first and last axles is 36 feet or more, with overall gross weight not exceeding 80,000 pounds. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"Which formula does Alabama apply to determine the maximum allowable gross weight on a group of two or more consecutive axles?","options":["The federal bridge formula W = 500(LN/(N-1) + 12N + 36)","The horsepower-to-weight ratio formula","A flat 80,000-pound rule regardless of spacing","The stopping-distance proportionality formula"],"answer":0,"explanation":"Alabama Code 32-9-20(4)(c) adopts the federal bridge formula W = 500(LN/(N-1) + 12N + 36), where W is gross weight, L is the distance between extreme axles of the group, and N is the number of axles. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"For enforcement of axle and gross weight limits, Alabama allows a scale (enforcement) tolerance calculated by multiplying the prescribed weight by what factor?","options":["0.05 (5 percent)","0.10 (10 percent)","0.15 (15 percent)","0.20 (20 percent)"],"answer":1,"explanation":"Alabama Code 32-9-20(4)(d) permits a scale/enforcement tolerance equal to the prescribed weight multiplied by one-tenth (.10), i.e., 10 percent, before a violation is deemed to occur. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"Under Alabama law, two and three axle vehicles used exclusively to transport agricultural commodities to and from a farm are NOT required to conform to which requirement?","options":["The width and height limits","The single axle and gross weight requirements","The lighting and marking requirements","The length limits for combinations"],"answer":1,"explanation":"Alabama Code 32-9-20(4)(j) exempts two- and three-axle vehicles used exclusively for transporting agricultural commodities to and from a farm from the single axle requirements of paragraph (4)a and the gross weight requirements of paragraph (4)c. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"A vehicle using a functioning auxiliary power unit (APU) or idle-reduction technology in Alabama is allowed how much additional weight above the gross, axle, tandem, or bridge formula limits?","options":["250 pounds","400 pounds","550 pounds","1,000 pounds"],"answer":1,"explanation":"Alabama Code 32-9-20(b)(1) allows up to an additional 400 pounds (or the actual certified APU weight, whichever is less) for vehicles using auxiliary power or idle-reduction technology, mirroring the federal Energy Policy Act of 2005. Source: Alabama Code Section 32-9-20.","handbook":"","hbref":""},{"q":"An Alabama annual oversize/overweight permit may NOT authorize operation of a vehicle whose total gross weight exceeds what figure?","options":["100,000 pounds","120,000 pounds","150,000 pounds","200,000 pounds"],"answer":2,"explanation":"Alabama Code 32-9-29(b)(1) provides that an annual permit may not authorize a vehicle whose total gross weight exceeds 150,000 pounds, and gross weights over 100,000 pounds require advance routing by the department. Source: Alabama Code Section 32-9-29.","handbook":"","hbref":""},{"q":"Under an Alabama annual permit, the single axle weight of a permitted vehicle may not exceed what amount?","options":["20,000 pounds","22,000 pounds","25,000 pounds","27,000 pounds"],"answer":1,"explanation":"Alabama Code 32-9-29(b)(1) caps the single axle weight under an annual oversize/overweight permit at 22,000 pounds, including all enforcement tolerances. Source: Alabama Code Section 32-9-29.","handbook":"","hbref":""},{"q":"An Alabama annual oversize/overweight permit may not authorize a vehicle whose height exceeds what limit?","options":["13 feet 6 inches","14 feet","15 feet 6 inches","16 feet"],"answer":1,"explanation":"Alabama Code 32-9-29(b)(1) provides that an annual permit may not authorize operation of a vehicle whose height exceeds 14 feet. Source: Alabama Code Section 32-9-29.","handbook":"","hbref":""},{"q":"Under Alabama law, farm and agricultural commodities and equipment have what status regarding oversize/overweight permits for movement on the state highway system?","options":["They require a special annual farm permit","They are exempt from the requirement of obtaining permits","They require a single-trip permit only","They must obtain a permit but pay no fee"],"answer":1,"explanation":"Alabama Code 32-9-29(f) states that farm and agricultural commodities and equipment are exempt from the requirement of obtaining permits for movement on the state highway system of Alabama. Source: Alabama Code Section 32-9-29.","handbook":"","hbref":""},{"q":"In Alabama, a Class A CDL is required to operate any combination of vehicles with a gross combination weight rating (GCWR) of at least what value, when the towed unit's GVWR exceeds 10,000 pounds?","options":["16,001 pounds or more","26,001 pounds or more","10,001 pounds or more","36,001 pounds or more"],"answer":1,"explanation":"Alabama defines a Class A CDL as any combination of vehicles with a GCWR of 11,794 kilograms or more (26,001 pounds or more), provided the GVWR of the towed vehicle(s) exceeds 4,536 kg (10,000 lb). Source: ALEA Driver License Division, CDL classes/endorsements page and Alabama CDL Manual.","handbook":"","hbref":""},{"q":"Under Alabama rules, which CDL class covers a single vehicle with a GVWR of 26,001 pounds or more, or such a vehicle towing a unit not over 10,000 pounds GVWR?","options":["Class A","Class C","Class B","Class D"],"answer":2,"explanation":"Alabama defines Class B as any single vehicle with a GVWR of 11,794 kg or more (26,001 lb or more), or any such vehicle towing a vehicle not in excess of 4,536 kg (10,000 lb) GVWR. Source: ALEA CDL classes/endorsements page and Alabama CDL Manual.","handbook":"","hbref":""},{"q":"A vehicle that does not meet the Class A or Class B weight thresholds but is designed to carry 16 or more passengers (including the driver), or carries placarded hazardous materials, requires which Alabama CDL class?","options":["Class C","Class B","Class A","Class M"],"answer":0,"explanation":"Alabama Class C is any vehicle (or combination) not meeting the Class A or B definition but designed to transport 16 or more passengers including the driver, or used to transport hazardous materials requiring placarding under 49 CFR part 172 subpart F. Source: ALEA CDL classes/endorsements page.","handbook":"","hbref":""},{"q":"How many passengers (including the driver) must a vehicle be designed to carry before a passenger or school bus endorsement and the appropriate CDL are triggered in Alabama?","options":["12 or more","24 or more","16 or more","20 or more"],"answer":2,"explanation":"Alabama (following the federal standard) sets the threshold at 16 or more passengers including the driver for the Class C definition and for passenger/school bus endorsement purposes. Source: ALEA CDL classes/endorsements page; Alabama CDL Manual.","handbook":"","hbref":""},{"q":"On an Alabama CDL, which endorsement code authorizes the driver to operate a tank vehicle?","options":["T","N","H","X"],"answer":1,"explanation":"Alabama uses the federal endorsement codes: N is the Tank Vehicle (Tanker) endorsement. Source: ALEA CDL classes/endorsements page; Alabama CDL Manual.","handbook":"","hbref":""},{"q":"What does the 'T' endorsement on an Alabama CDL authorize?","options":["Transporting hazardous materials","Driving a tank vehicle","Operating double and triple trailers","Operating a tow truck"],"answer":2,"explanation":"In Alabama, the T endorsement authorizes operation of double/triple trailers and is obtained by passing a knowledge test only (no skills test). Source: ALEA CDL classes/endorsements page; Alabama CDL Manual.","handbook":"","hbref":""},{"q":"On an Alabama CDL, which single endorsement code represents the combination of Tank Vehicle AND Hazardous Materials?","options":["H","N","X","P"],"answer":2,"explanation":"Alabama uses code X for the combined Tank Vehicle/Hazardous Materials endorsement; H alone is HazMat and N alone is Tanker. Source: ALEA CDL classes/endorsements page.","handbook":"","hbref":""},{"q":"Before Alabama can issue a HazMat (H) endorsement on a CDL, the applicant must receive what from the federal Transportation Security Administration (TSA)?","options":["A Medical Examiner's Certificate","A Determination of No Security Threat","An FMCSA training certificate by mail","A waiver of the knowledge test"],"answer":1,"explanation":"No state may issue or renew a HazMat endorsement unless TSA returns a Determination of No Security Threat following fingerprinting and a security threat assessment. Alabama requires this TSA background check plus the HazMat knowledge test. Source: TSA/49 CFR 1572; ALEA HazMat endorsement requirements.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Alabama CDL for INTRASTATE (within Alabama only) commercial driving?","options":["21","19","18","16"],"answer":2,"explanation":"Alabama allows a CDL at age 18 for intrastate operation; interstate operation requires age 21. Source: ALEA CDL FAQ; Alabama CDL Manual.","handbook":"","hbref":""},{"q":"What is the minimum age required to drive a commercial motor vehicle across state lines (interstate) on an Alabama CDL?","options":["18","21","19","25"],"answer":1,"explanation":"Interstate commercial driving (and transporting hazardous materials or placardable loads across state lines) requires a minimum age of 21 in Alabama, consistent with federal rules. Source: ALEA CDL FAQ; 49 CFR 391.11.","handbook":"","hbref":""},{"q":"After being issued a Commercial Learner Permit (CLP), how long must an Alabama applicant hold the CLP before being allowed to take the CDL skills (road) test?","options":["30 days","14 days","10 days","60 days"],"answer":1,"explanation":"Federal law adopted by Alabama requires the CLP be held at least 14 days before the CDL skills test may be taken. Source: ALEA CDL FAQ; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is an Alabama Commercial Learner Permit (CLP) valid, and can it be renewed?","options":["180 days, and it can be renewed once","360 days, and it cannot be renewed","1 year, and it can be renewed annually","90 days, and it cannot be renewed"],"answer":1,"explanation":"An Alabama CLP is valid for 360 days and is not renewable; if it expires, the applicant must retake all written tests and pay for a new CLP. Source: ALEA CDL FAQ.","handbook":"","hbref":""},{"q":"What type of base driver license must an Alabama applicant already hold before applying for a Commercial Learner Permit or CDL?","options":["A valid Alabama Class D driver license","A valid Alabama Class M motorcycle license","Only a learner's permit","No prior license is required"],"answer":0,"explanation":"Alabama requires applicants to hold a valid Alabama Class D (regular) driver license before applying for a CLP or CDL. Source: ALEA CDL FAQ; Document Requirements page.","handbook":"","hbref":""},{"q":"Which agency issues commercial driver licenses in Alabama?","options":["The Alabama Department of Transportation (ALDOT)","The county probate office","The Alabama Law Enforcement Agency (ALEA) Driver License Division","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":2,"explanation":"CDLs in Alabama are issued by the Alabama Law Enforcement Agency (ALEA) through its Driver License Division, not a separate DMV or ALDOT. Source: ALEA Driver License Division.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required before a first-time Alabama CDL must be delivered by a provider listed where?","options":["The ALEA approved-school list only","The FMCSA Training Provider Registry (TPR)","Any private trucking company","The Alabama Community College System registry"],"answer":1,"explanation":"Since Feb 7, 2022, first-time CDL applicants (and certain upgrades/endorsements) must complete ELDT from a provider listed on the FMCSA Training Provider Registry, which must upload completion before Alabama allows testing. Source: ALEA CDL FAQ; 49 CFR part 380.","handbook":"","hbref":""},{"q":"Which CDL action does NOT, by itself, require Entry-Level Driver Training (ELDT) before testing in Alabama?","options":["Obtaining a CDL for the first time","Upgrading from Class B to Class A","Renewing a CDL with the same class and endorsements","Obtaining a first HazMat (H) endorsement"],"answer":2,"explanation":"ELDT applies to first-time CDLs, class upgrades, and first-time S, P, or H endorsements. A simple renewal that does not upgrade the class or add a covered endorsement does not trigger ELDT. Source: 49 CFR part 380; ALEA CDL FAQ.","handbook":"","hbref":""},{"q":"An Alabama CDL applicant who drives in interstate commerce and is required to meet federal medical standards self-certifies under which category?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"answer":1,"explanation":"The Non-Excepted Interstate category applies to drivers operating in interstate commerce who must maintain a valid DOT Medical Examiner's Certificate. Alabama requires self-certification into one of four categories per 49 CFR 383. Source: ALEA self-certification requirements; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"How many medical self-certification categories must an Alabama CDL holder choose from, and which requires keeping a current DOT medical card?","options":["Two categories; only the interstate one needs a medical card","Four categories; the Non-Excepted Interstate category requires a current DOT medical card","Three categories; none require a medical card","Four categories; the Excepted Intrastate category requires a current DOT medical card"],"answer":1,"explanation":"Alabama uses the four federal categories (Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, Excepted Intrastate). Drivers certifying Non-Excepted Interstate must provide and maintain a DOT Medical Examiner's Certificate from an FMCSA-certified examiner. Source: ALEA self-certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"When applying for an Alabama CDL or CLP, which set of documents must an applicant provide?","options":["Only a Social Security card","Proof of identity, proof of Social Security number, proof of Alabama residency, and (if not a U.S. citizen) proof of lawful presence","A passport and two utility bills only","Proof of identity and a high school diploma"],"answer":1,"explanation":"ALEA requires primary proof of identity, documented proof of the SSN, proof of Alabama residency, and proof of lawful presence for non-citizens; the same document cannot count for two requirements. Source: ALEA Document Requirements and Fees page.","handbook":"","hbref":""},{"q":"Because a school bus carrying 16 or more occupants is also a passenger vehicle, what does Alabama require in addition to the School Bus (S) endorsement?","options":["A separate Class A CDL","The Passenger (P) endorsement","The Tanker (N) endorsement","The Doubles/Triples (T) endorsement"],"answer":1,"explanation":"Alabama requires the Passenger (P) endorsement together with the School Bus (S) endorsement; applicants pass the General Knowledge, Passenger, and School Bus knowledge tests plus a skills test in a representative bus. Source: ALEA CDL classes/endorsements; Alabama CDL Manual.","handbook":"","hbref":""},{"q":"In Alabama, what is the lowest blood alcohol concentration (BAC) that makes it illegal to operate a commercial motor vehicle?","options":["0.02%","0.04%","0.08%","0.10%"],"answer":1,"explanation":"Alabama follows the federal CMV standard: it is illegal to operate a CMV if your BAC is 0.04% or more. Source: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Alabama's implied consent rule, what is assumed about a person who drives a commercial motor vehicle on Alabama roads?","options":["They have given consent to alcohol testing","They must carry a separate consent card","They waive the right to a hearing","They consent only if visibly impaired"],"answer":0,"explanation":"The Alabama CDL Manual states that if you operate a CMV you shall be deemed to have given your consent to alcohol testing. Source: Alabama CDL Manual (ALEA), Section 1.3.2; Ala. Code Title 32.","handbook":"","hbref":""},{"q":"In Alabama, how long will a CDL holder lose the CDL for a FIRST major offense, such as a CMV DUI or refusing the alcohol test (when not hauling placarded hazmat)?","options":["60 days","120 days","At least 1 year","At least 3 years"],"answer":2,"explanation":"A first major offense (DUI, 0.04+ BAC in a CMV, refusing the test, leaving the scene, etc.) results in loss of the CDL for at least one year. Source: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, a driver commits a first major offense while operating a CMV that is placarded for hazardous materials. How long is the disqualification?","options":["At least 1 year","At least 2 years","At least 3 years","Lifetime"],"answer":2,"explanation":"If a first major offense occurs while operating a CMV placarded for hazardous materials, the disqualification is at least three years instead of one. Source: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, what is the disqualification for a SECOND major offense (such as a second CMV DUI)?","options":["1 year","3 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in loss of the CDL for life. Source: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, refusing to submit to alcohol testing while operating a CMV is treated as what kind of violation?","options":["A serious traffic violation (60-day rule)","A major offense (at least 1-year loss)","A minor infraction with a fine only","An out-of-service order violation"],"answer":1,"explanation":"Refusing to undergo blood alcohol testing is listed as a major offense in Alabama, carrying at least a one-year disqualification for a first offense. Source: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is listed as a SERIOUS traffic violation in the Alabama CDL Manual?","options":["Driving 5 mph over the limit","Excessive speeding (15 mph or more over the posted limit)","An expired registration sticker","A burned-out taillight"],"answer":1,"explanation":"Serious traffic violations include excessive speeding, defined as 15 mph or more above the posted limit, along with reckless driving, improper lane changes, and following too closely. Source: Alabama CDL Manual (ALEA), Section 1.3.3.","handbook":"","hbref":""},{"q":"In Alabama, a CDL holder is convicted of TWO serious traffic violations in a CMV within a three-year period. What is the disqualification?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"Two serious traffic violations in a CMV within a three-year period result in loss of the CDL for at least 60 days. Source: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, a CDL holder is convicted of THREE serious traffic violations in a CMV within a three-year period. What is the disqualification?","options":["At least 60 days","At least 90 days","At least 120 days","At least 1 year"],"answer":2,"explanation":"Three or more serious traffic violations in a CMV within a three-year period result in loss of the CDL for at least 120 days. Source: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, what is the disqualification for a FIRST violation of an out-of-service order?","options":["At least 30 days","At least 90 days","At least 180 days","At least 1 year"],"answer":1,"explanation":"A first violation of an out-of-service order results in loss of the CDL for at least 90 days. Source: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, a driver commits TWO out-of-service order violations within a ten-year period. What is the disqualification?","options":["At least 120 days","At least 1 year","At least 3 years","At least 5 years"],"answer":1,"explanation":"Two out-of-service order violations within a ten-year period result in loss of the CDL for at least one year. Source: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, a driver commits THREE or more out-of-service order violations within a ten-year period. What is the disqualification?","options":["At least 1 year","At least 2 years","At least 3 years","Lifetime"],"answer":2,"explanation":"Three or more out-of-service order violations within a ten-year period result in loss of the CDL for at least three years. Source: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, what is the disqualification for a FIRST railroad-highway grade crossing violation in a CMV?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in loss of the CDL for at least 60 days. Source: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, a CDL holder receives a SECOND railroad-highway grade crossing violation within a three-year period. What is the disqualification?","options":["At least 60 days","At least 120 days","At least 6 months","At least 1 year"],"answer":1,"explanation":"A second railroad-highway grade crossing violation within a three-year period results in loss of the CDL for at least 120 days. Source: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, a CDL holder receives a THIRD railroad-highway grade crossing violation within a three-year period. What is the disqualification?","options":["At least 120 days","At least 180 days","At least 1 year","At least 3 years"],"answer":2,"explanation":"A third railroad-highway grade crossing violation within a three-year period results in loss of the CDL for at least one year. Source: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Alabama, what happens if a CMV driver is found with any detectable amount of alcohol that is still below 0.04%?","options":["Nothing, it is under the legal limit","Out-of-service for 24 hours","Immediate 1-year disqualification","A lifetime ban"],"answer":1,"explanation":"A CMV driver with any detectable amount of alcohol under 0.04% will be placed out-of-service for 24 hours. Source: Alabama CDL Manual (ALEA), Section 1.3.2.","handbook":"","hbref":""},{"q":"In Alabama, after how many convictions for using a hand-held mobile phone while driving a CMV does a driver's CDL get disqualified?","options":["One conviction","Two or more convictions","Four or more convictions","Six or more convictions"],"answer":1,"explanation":"A CDL is disqualified after two or more convictions of a state law on hand-held mobile phone use while operating a CMV: 60 days for the second offense within 3 years and 120 days for three or more within 3 years. Source: Alabama CDL Manual (ALEA), Section 2.9.4.","handbook":"","hbref":""},{"q":"Under the rules in the Alabama CDL Manual, texting while driving a CMV is prohibited. Driver convictions can carry a civil penalty up to what amount?","options":["Up to $500","Up to $1,000","Up to $2,750","Up to $11,000"],"answer":2,"explanation":"Each texting or hand-held phone violation by a CMV driver is subject to a civil penalty of up to $2,750 (employers may be fined up to $11,000). Source: Alabama CDL Manual (ALEA), Sections 2.9.4 and 2.9.5; 49 CFR 392.","handbook":"","hbref":""},{"q":"In Alabama, using a CMV to commit a felony involving controlled substances results in what penalty?","options":["A 60-day disqualification","A 1-year disqualification","A 3-year disqualification","Loss of the CDL for life"],"answer":3,"explanation":"Using a CMV to commit a felony involving controlled substances results in loss of the CDL for life, with no reinstatement. Source: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of these is a SERIOUS traffic violation under the Alabama CDL Manual rather than a major offense?","options":["Driving a CMV with a 0.04% BAC","Refusing a chemical alcohol test","Following a vehicle too closely","Leaving the scene of an accident"],"answer":2,"explanation":"Following a vehicle too closely is listed as a serious traffic violation (counting toward the 60/120-day rule), while DUI, test refusal, and leaving the scene are major offenses carrying at least a one-year disqualification. Source: Alabama CDL Manual (ALEA), Sections 1.3.2 and 1.3.3.","handbook":"","hbref":""},{"q":"When a placarded hazardous-materials vehicle must stop at a railroad-highway grade crossing in Alabama, how far from the nearest rail must the driver stop?","options":["Not less than 10 feet and not more than 25 feet","Not less than 15 feet and not more than 50 feet","Not less than 25 feet and not more than 75 feet","Not less than 5 feet and not more than 15 feet"],"answer":1,"explanation":"Alabama requires a placarded HazMat vehicle to stop 15 to 50 feet before the nearest rail, then proceed only when no train is coming and it can clear the tracks without stopping. Source: Alabama (ALEA) CDL Manual, Section 9.6 Railroad Crossings; Ala. Code 32-5A-150.","handbook":"","hbref":""},{"q":"Under Alabama's Move Over Act, when a driver on a multi-lane highway cannot safely vacate the lane nearest a stopped emergency or law enforcement vehicle showing flashing lights, what must the driver do?","options":["Slow to a speed at least 10 mph below the posted speed limit","Slow to a speed at least 20 mph below the posted speed limit","Stop completely until the emergency vehicle leaves","Slow to a speed at least 15 mph below the posted speed limit"],"answer":3,"explanation":"Under Alabama's Move Over Act, a driver who cannot safely change lanes must slow to a speed at least 15 mph less than the posted speed limit. Source: Ala. Code 32-5A-58.2 (Moving Over or Reducing Speed When Approaching Emergency Vehicles).","handbook":"","hbref":""},{"q":"What is the maximum speed limit on an interstate highway in Alabama (unless otherwise posted or authorized)?","options":["65 mph","75 mph","80 mph","70 mph"],"answer":3,"explanation":"Alabama law sets the maximum speed on interstate highways at 70 mph; on other highways with four or more lanes the maximum is 65 mph. Source: Ala. Code 32-5A-171 (Maximum Limits).","handbook":"","hbref":""},{"q":"In Alabama, if a commercial vehicle must stop on a one-way or divided highway, where must the three emergency warning devices be placed?","options":["10 feet, 50 feet, and 150 feet toward approaching traffic","25 feet, 100 feet, and 250 feet toward approaching traffic","10 feet, 100 feet, and 200 feet toward approaching traffic","5 feet, 75 feet, and 100 feet toward approaching traffic"],"answer":2,"explanation":"On a one-way or divided highway, Alabama directs that warning devices be placed 10 feet, 100 feet, and 200 feet toward the approaching traffic. Source: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices for Stopped Vehicles.","handbook":"","hbref":""},{"q":"Under Alabama's school bus law, when must the driver of a vehicle meeting or overtaking a stopped school bus with its visual signals operating come to a complete stop?","options":["Only when approaching from behind the bus, never from the front","Only when the bus is on the same side of the road as the driver","Only if children are visibly present in the roadway","When approaching from either direction on an ordinary two-lane or undivided roadway"],"answer":3,"explanation":"Alabama requires a driver meeting or overtaking a school bus from EITHER direction to stop when the bus has stopped to load or unload children with its visual signal in operation, except on a divided highway as defined by statute. Source: Ala. Code 32-5A-154.","handbook":"","hbref":""},{"q":"Which situation describes Alabama's ONLY exception to stopping for a stopped school bus that is loading or unloading children?","options":["Driving in any city with a posted speed limit of 30 mph or less","Any time the driver is more than 100 feet from the bus","Meeting the bus from the opposite roadway of a divided highway separated into two or more opposing lanes","Any four-lane road, whether divided or not"],"answer":2,"explanation":"Alabama excuses a driver from stopping only when meeting a school bus stopped in the opposing roadway of a DIVIDED highway having four or more lanes that permits at least two lanes of traffic to travel in opposite directions. On an undivided multi-lane road, all drivers must still stop. Source: Ala. Code 32-5A-154.","handbook":"","hbref":""},{"q":"A bus carrying passengers in Alabama must stop how far from the nearest rail at a railroad-highway crossing?","options":["Between 10 and 40 feet","Between 20 and 60 feet","Between 5 and 25 feet","Between 15 and 50 feet"],"answer":3,"explanation":"Alabama requires a passenger-carrying bus to stop between 15 and 50 feet before the nearest rail, listen and look both ways, then cross only when it can be done without stopping on the tracks. Source: Alabama (ALEA) CDL Manual, Section 4.3.5 Railroad-Highway Crossing Stops.","handbook":"","hbref":""},{"q":"On a two-lane Alabama road carrying traffic in both directions, where are the warning devices placed when a CMV is stopped?","options":["Within 10 feet of the vehicle, and 200 feet to the front and 200 feet to the rear","Within 25 feet of the vehicle, and 150 feet to the front and rear","All three placed 100 feet behind the vehicle only","Within 10 feet of the vehicle, and 100 feet to the front and 100 feet to the rear"],"answer":3,"explanation":"On a two-lane road carrying traffic both ways, Alabama directs one device within 10 feet of the vehicle and one 100 feet behind and one 100 feet ahead, on the shoulder or in the lane. Source: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices.","handbook":"","hbref":""},{"q":"What is the fine for a violation of Alabama's Move Over Act?","options":["$100","$500","$200","$50"],"answer":2,"explanation":"A violation of Alabama's Move Over law is a misdemeanor punishable by a fine of two hundred dollars ($200). Source: Ala. Code 32-5A-58.2.","handbook":"","hbref":""},{"q":"Besides law enforcement and emergency vehicles, which of these stopped vehicles displaying warning/flashing lights also triggers Alabama's Move Over requirements?","options":["A garbage, trash, refuse, or recycling collection vehicle","Any privately owned passenger car with hazard lights on","A school bus picking up children","A delivery van double-parked on a city street"],"answer":0,"explanation":"Alabama expanded the Move Over Act to cover wreckers, utility service vehicles, maintenance/construction/survey vehicles, AND garbage, trash, refuse, or recycling collection vehicles displaying flashing lights. Source: Ala. Code 32-5A-58.2.","handbook":"","hbref":""},{"q":"What is the maximum speed limit in Alabama on a highway (other than an interstate) that has four or more traffic lanes?","options":["70 mph","65 mph","60 mph","55 mph"],"answer":1,"explanation":"Alabama caps the speed on non-interstate highways having four or more lanes at 65 mph, while interstates are capped at 70 mph. Source: Ala. Code 32-5A-171.","handbook":"","hbref":""},{"q":"Under Alabama's lane-use rule, a commercial vehicle proceeding at less than the normal speed of traffic must be driven where?","options":["In the center lane at all times","In the right-hand lane, or as close as practicable to the right edge of the roadway","In any lane, since trucks are exempt from lane rules","In the left lane to keep the right lanes clear for merging"],"answer":1,"explanation":"Alabama requires any vehicle traveling slower than the normal speed of traffic to keep right (right-hand lane or as near the right edge as practicable), except when overtaking, passing, or preparing for a left turn. Source: Ala. Code 32-5A-80 (Driving on Right Side of Roadway).","handbook":"","hbref":""},{"q":"If a stopped CMV in Alabama is on a hill or curve that blocks the view of approaching drivers, what must the driver do with the rearmost warning device?","options":["Move it farther back so traffic is warned at least 500 feet away","Leave it exactly 200 feet back regardless of the obstruction","Remove it and rely on the vehicle's four-way flashers only","Place all three devices directly behind the rear bumper"],"answer":0,"explanation":"When a hill, curve, or other obstruction keeps drivers from seeing the vehicle within 500 feet, Alabama directs moving the rearmost triangle back down the road so the warning is provided beyond the obstruction. Source: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices.","handbook":"","hbref":""},{"q":"What is the fine range for a FIRST conviction of unlawfully passing a stopped school bus in Alabama?","options":["Not less than $150 nor more than $300","Not less than $50 nor more than $100","Not less than $500 nor more than $1,000","A flat $250 with no range"],"answer":0,"explanation":"A first conviction for illegally passing a stopped school bus in Alabama carries a fine of not less than $150 nor more than $300, with stiffer fines, community service, and license suspension for repeat offenses. Source: Ala. Code 32-5A-154.","handbook":"","hbref":""},{"q":"Which vehicles are required to make a full stop at every railroad-highway grade crossing in Alabama?","options":["All commercial vehicles over 10,000 pounds without exception","Buses carrying passengers and vehicles placarded for hazardous materials","Only empty tank trucks","Only vehicles towing a trailer of any kind"],"answer":1,"explanation":"Alabama requires buses carrying passengers and placarded HazMat vehicles (including loaded or empty HazMat cargo tanks and vehicles hauling any amount of chlorine) to stop at grade crossings; ordinary CMVs are not required to stop unless conditions demand it. Source: Alabama (ALEA) CDL Manual, Sections 2.15 and 9.6.","handbook":"","hbref":""},{"q":"What is the maximum legal load WIDTH in Alabama before an oversize permit from ALDOT is required?","options":["8 feet 0 inches","10 feet 0 inches","8 feet 6 inches","9 feet 6 inches"],"answer":2,"explanation":"Alabama's standard legal maximum load width is 8 feet 6 inches (102 inches); anything wider requires an oversize permit from the Alabama Department of Transportation (ALDOT). Source: ALDOT Oversize/Overweight Permit regulations.","handbook":"","hbref":""},{"q":"What is the maximum legal load HEIGHT in Alabama before an oversize permit is required?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"answer":1,"explanation":"Alabama sets the legal maximum vehicle/load height at 13 feet 6 inches; loads exceeding this require an ALDOT oversize permit, and heights over 15 feet 6 inches require a front height-pole escort. Source: ALDOT Oversize/Overweight Permit regulations.","handbook":"","hbref":""},{"q":"On a long, steep downgrade in Alabama's mountain terrain, what is the proper purpose of a runaway-vehicle escape ramp?","options":["To stop a vehicle whose brakes have failed by using a bed of loose, soft material","To provide a paved rest area for trucks to cool their brakes voluntarily","To serve as a mandatory inspection lane for all CMVs descending the grade","To allow faster vehicles to pass slow trucks on the climb"],"answer":0,"explanation":"Escape ramps are built on steep downgrades to stop runaway vehicles safely using a long bed of loose, soft material; drivers should know ramp locations on their route. Alabama's I-59 grades near Lookout/Sand Mountain feature such ramps. Source: Alabama (ALEA) CDL Manual, Section 2.16 Mountain Driving / Escape Ramps.","handbook":"","hbref":""},{"q":"Within how many minutes must an Alabama CMV driver who stops on a roadway or shoulder put out the required emergency warning devices?","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"answer":0,"explanation":"If a CMV must stop on a road or shoulder in Alabama, the driver must put out the emergency warning devices within ten minutes. Source: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices for Stopped Vehicles.","handbook":"","hbref":""},{"q":"When approaching a stopped emergency vehicle on a TWO-LANE Alabama road where moving over is impossible and the posted limit is 45 mph, what must a driver do?","options":["Maintain the posted limit but turn on the four-way flashers","Come to a complete stop in the travel lane","Move as far away within the lane as possible and slow to 15 mph below the posted limit (30 mph)","Slow to exactly 20 mph regardless of the posted limit"],"answer":2,"explanation":"On a two-lane Alabama road, a driver must move as far from the emergency vehicle as possible within the lane and slow to 15 mph below the posted limit when that limit is 25 mph or greater (here 45 - 15 = 30 mph). Source: Ala. Code 32-5A-58.2.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) and administers CDL testing in Alabama?","options":["The Alabama Department of Transportation (ALDOT)","The Alabama Law Enforcement Agency (ALEA), Driver License Division","The Alabama Department of Revenue, Motor Vehicle Division","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":1,"explanation":"CDLs in Alabama are issued and tested by the Alabama Law Enforcement Agency (ALEA), Driver License Division. The Alabama CDL Manual is published by ALEA, and knowledge/skills testing is conducted at ALEA Commercial Driver License offices. Source: Alabama CDL Manual (ALEA), Introduction; ALEA Driver License Division.","handbook":"","hbref":""},{"q":"How does an applicant schedule a CDL knowledge or skills test in Alabama?","options":["By walking in to any county tag/license office without an appointment","By applying online to FMCSA, which assigns a test center","By mailing a written request to ALDOT and waiting for a scheduled date","By making an appointment at an ALEA Commercial Driver License office through the online scheduling system at alea.gov"],"answer":3,"explanation":"The Alabama CDL Manual directs applicants to make an appointment for knowledge or skills testing at an ALEA Commercial Driver License office; under 'Driver License' / 'Online Services' on alea.gov, applicants use 'Schedule DL Appointment.' Source: Alabama CDL Manual (ALEA), Commercial Driver License Offices page.","handbook":"","hbref":""},{"q":"In Alabama, what must an applicant obtain and hold before they are allowed to take the CDL skills test for the first time?","options":["A Hazardous Materials endorsement","A federal DOT medical waiver","An International Registration Plan (IRP) account","A Commercial Learner's Permit (CLP)"],"answer":3,"explanation":"A first-time or upgrading CDL applicant must first be issued a Commercial Learner's Permit (CLP) by passing the required knowledge test(s). The CLP must then be held before the skills test may be taken. Source: Alabama CDL Manual (ALEA), Section 1; ALEA CDL FAQ.","handbook":"","hbref":""},{"q":"Under Alabama (and federal) rules, how long must a CLP be held before the holder may take the CDL skills test?","options":["At least 7 days","At least 30 days","At least 14 days","At least 60 days"],"answer":2,"explanation":"Alabama follows the federal requirement that a CLP be held for a minimum of 14 days before the holder may take the CDL skills test. Source: ALEA CDL FAQ; 49 CFR 383.25 as applied in Alabama.","handbook":"","hbref":""},{"q":"How long is an Alabama Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["Valid for 180 days and may be renewed once","Valid for 1 year and may be renewed twice","Valid for 30 days and is not renewable","Valid for 360 days and is not renewable"],"answer":3,"explanation":"ALEA states the CLP is valid for 360 days and is not renewable; if it expires, the applicant must re-test for a new CLP. Source: ALEA CDL FAQ.","handbook":"","hbref":""},{"q":"Before testing for a CDL for the first time in Alabama, which training must an applicant complete?","options":["A defensive-driving course approved by the Alabama courts","A 40-hour OSHA workplace-safety course","Entry-Level Driver Training (ELDT) through an FMCSA-registered provider","An ALEA-administered classroom course held only at the Montgomery office"],"answer":2,"explanation":"Entry-Level Driver Training (ELDT) is required for anyone obtaining a CDL for the first time (and for certain upgrades/endorsements). Training must be completed through a provider listed on the FMCSA Training Provider Registry before testing. Source: ALEA CDL Self-Certification/FAQ materials; FMCSA ELDT rule effective Feb. 7, 2022.","handbook":"","hbref":""},{"q":"Which knowledge test must EVERY Alabama CDL applicant pass, regardless of vehicle class or endorsements?","options":["The air brakes test","The combination vehicles test","The hazardous materials test","The general knowledge test"],"answer":3,"explanation":"The Alabama CDL Manual lists the general knowledge test as the one taken by all applicants; other knowledge tests (air brakes, combination, passenger, hazmat, tank, doubles/triples, school bus) depend on the class and endorsements sought. Source: Alabama CDL Manual (ALEA), Section 1.1.1 Knowledge Tests.","handbook":"","hbref":""},{"q":"According to the Alabama CDL Manual, the CDL skills test consists of which three segments?","options":["Written exam, eye exam, and road test","Coupling/uncoupling, backing, and air-brake check","Pre-trip, defensive driving, and night driving","Vehicle inspection, basic vehicle control, and on-road driving"],"answer":3,"explanation":"The manual states the CDL skills test has three segments: vehicle inspection, basic vehicle control, and on-road driving. Source: Alabama CDL Manual (ALEA), Section 1.1.2 Skills Tests.","handbook":"","hbref":""},{"q":"In what order must the three CDL skills-test segments be taken in Alabama?","options":["In any order the applicant chooses on test day","On-road first, then basic control, then vehicle inspection","In the order listed (vehicle inspection, then basic vehicle control, then on-road), passing each before moving to the next","Basic vehicle control first, then on-road, then vehicle inspection"],"answer":2,"explanation":"The Alabama CDL Manual states: 'You must take the segments in the order listed and must pass each one before moving to the next' — vehicle inspection, basic vehicle control, then on-road driving. Source: Alabama CDL Manual (ALEA), Section 1.1.2.","handbook":"","hbref":""},{"q":"What kind of vehicle must an applicant use to take the Alabama CDL skills test?","options":["A vehicle representative of the class/type for which the applicant wishes to be licensed","Any passenger car, since only driving habits are evaluated","A vehicle provided free of charge by the ALEA test site","Any commercial vehicle, regardless of class, as long as it has air brakes"],"answer":0,"explanation":"The manual requires the skills test be taken in the type of vehicle for which the applicant wishes to be licensed; the class of vehicle used can restrict the CDL issued. A vehicle with components marked or labeled cannot be used. Source: Alabama CDL Manual (ALEA), Section 1.1.2.","handbook":"","hbref":""},{"q":"During the Alabama CDL vehicle-inspection skills test, what is the applicant required to do at each item?","options":["Silently inspect each item while the examiner times the process","Point to or touch and name the item, and explain to the examiner what is being inspected and why","Write a description of each item on an inspection form","Only verbally list the items without touching or pointing to them"],"answer":1,"explanation":"The manual states that during the Vehicle Inspection test you must point to/touch and name the item you are inspecting and explain to the examiner what you are inspecting and why. Source: Alabama CDL Manual (ALEA), Section 1.1.2, Vehicle Inspection.","handbook":"","hbref":""},{"q":"What does the basic vehicle control portion of the Alabama CDL skills test evaluate?","options":["Knowledge of hazardous-materials placarding rules","Skill in moving the vehicle forward, backward, and turning it within a defined area","Ability to read and interpret highway signs","Ability to complete a daily driver's log"],"answer":1,"explanation":"The basic vehicle control test measures the applicant's skill in controlling the vehicle — moving it forward, backward, and turning within a defined, marked area, with the examiner explaining how each exercise is to be done. Source: Alabama CDL Manual (ALEA), Section 1.1.2, Basic Vehicle Control.","handbook":"","hbref":""},{"q":"Which document does an Alabama CDL applicant typically need to provide as proof of their Social Security number when applying?","options":["Proof of the applicant's Social Security number (e.g., Social Security card)","A notarized affidavit from a current employer only","A copy of the applicant's most recent federal tax return only","A motor-carrier DOT number assignment letter"],"answer":0,"explanation":"Alabama CDL applicants must present proof of their Social Security number along with required proof of identity/residency and a valid Alabama (Class D) driver license. Source: ALEA Driver License Division document requirements; ALEA CDL application materials.","handbook":"","hbref":""},{"q":"Federal regulations adopted in Alabama require CDL holders of Class A, B, or C vehicles to self-certify by choosing among how many categories of commercial operation?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Alabama's CDL Self-Certification Affidavit requires the driver to certify one of four categories of operation. Source: ALEA CDL Self-Certification Affidavit (cites 49 CFR 383, 384, 390, 391); Alabama CDL Manual Section 1.2.","handbook":"","hbref":""},{"q":"On the Alabama CDL Self-Certification Affidavit, which one of the four categories REQUIRES the driver to carry and submit a DOT medical examiner's certificate?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate (with an Alabama medical waiver K restriction)"],"answer":1,"explanation":"The Alabama affidavit lists four categories: Non-excepted Interstate (subject to 49 CFR part 391 — DOT medical certificate required), Excepted Interstate, Non-excepted Intrastate, and Excepted Intrastate. Only Non-excepted Interstate requires carrying/submitting a DOT medical card; the other three submit only the affidavit. Source: ALEA CDL Self-Certification Affidavit.","handbook":"","hbref":""},{"q":"According to the Alabama CDL Manual, if a driver operates in BOTH interstate and intrastate commerce, which self-certification status must they choose?","options":["Intrastate commerce","Excepted intrastate commerce","Interstate commerce","Whichever they perform most often"],"answer":2,"explanation":"The manual states that if you operate in both intrastate and interstate commerce, you must choose interstate commerce when self-certifying. Source: Alabama CDL Manual (ALEA), Section 1.2.1.","handbook":"","hbref":""},{"q":"As of the change effective June 23, 2025, how is an Alabama CDL holder's DOT medical examiner's certificate normally transmitted to ALEA?","options":["The driver must mail the original paper card to the county probate office","The certified medical examiner submits it electronically to FMCSA, which transmits it to the driver's state of record","The driver uploads a scanned paper card on the ALDOT permit portal","ALDOT inspectors collect the card at weigh stations and forward it to ALEA"],"answer":1,"explanation":"Effective June 23, 2025, ALEA accepts DOT medical certifications electronically only: the FMCSA-certified medical examiner submits the result electronically to FMCSA, which forwards it to the driver's state of record. Paper cards and self-uploads are no longer accepted; drivers verify their record at alabamadl.alea.gov. Source: ALEA news release 'Big Changes for Alabama CDL Holders'; ALEA CDL FAQ.","handbook":"","hbref":""},{"q":"If a Non-excepted Interstate Alabama CDL holder fails to keep a current 'certified' medical status on file, what is the consequence?","options":["They become 'not-certified' and may lose their CDL","Their CDL is automatically downgraded to a CLP for 90 days","They receive a one-time written warning with no license effect","Nothing, because the medical card is optional for CDL holders"],"answer":0,"explanation":"The Alabama CDL Manual warns that a driver required to have a 'certified' medical status who fails to provide and keep it up to date becomes 'not-certified' and may lose their CDL (the CDL can be downgraded/cancelled). Source: Alabama CDL Manual (ALEA), Section 1.2 Medical Documentation Requirements.","handbook":"","hbref":""},{"q":"In Alabama, when is a CDL holder's self-certification (and medical card, if applicable) generally required to be on file relative to renewing the commercial license?","options":["Submitted no later than 10 days prior to renewing the commercial driver license","Submitted only after the renewed license is mailed","Submitted within 30 days after the license expires","Submitted only once and never updated again"],"answer":0,"explanation":"The ALEA CDL Self-Certification Affidavit instructs drivers to submit the affidavit (and the medical card, if applicable) no later than 10 days prior to renewing the commercial driver license; failure to return the form can result in cancellation of the CDL. Source: ALEA CDL Self-Certification Affidavit.","handbook":"","hbref":""},{"q":"What is the standard renewal/validity cycle for an Alabama CDL, and when does it expire?","options":["It is renewed every 2 years and expires at year-end","It is renewed every 10 years and expires on January 1","It is renewed on an 8-year cycle and expires on the driver's birthday","It never expires once a CDL is first issued"],"answer":2,"explanation":"Alabama issues/renews driver licenses, including CDLs, on an 8-year cycle, expiring on the driver's birthday; a CDL may be renewed as early as 180 days before expiration and there is no grace period. (A Hazmat endorsement's TSA validation lasts only 5 years.) Source: ALEA Driver License Division; Alabama CDL renewal guidance.","handbook":"","hbref":""}],"ru":{"0":{"q":"На автомагистралях Алабамы с полосами движения шириной 12 футов и более, какова максимальная общая внешняя ширина транспортного средства, включая груз (за исключением зеркал и устройств безопасности)?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Раздел 32-9-20(1) Кодекса Алабамы устанавливает максимальную ширину 102 inches (8 feet 6 inches), включая груз, на автомагистралях с полосами шириной 12 футов и более, не считая зеркал и устройств безопасности. Источник: Alabama Code Section 32-9-20."},"1":{"q":"Какова максимальная допустимая по закону высота транспортного средства, полуприцепа или прицепа, включая груз, на автомагистралях Алабамы?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Раздел 32-9-20(2) Кодекса Алабамы запрещает любому транспортному средству, полуприцепу или прицепу превышать 13 1/2 feet (13 feet 6 inches) в высоту, включая груз. Источник: Alabama Code Section 32-9-20."},"2":{"q":"В Алабаме какова максимальная полная нагрузка на дорогу, передаваемая колёсами любой одиночной оси?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"Раздел 32-9-20(4) Кодекса Алабамы ограничивает нагрузку на любую одиночную ось до 20,000 pounds, что соответствует федеральному стандарту согласно 23 U.S.C. 127. Источник: Alabama Code Section 32-9-20."},"3":{"q":"Какова максимально допустимая нагрузка на сдвоенную группу осей на системе межштатных автомагистралей (Interstate Highway System) в Алабаме?","options":["32,000 pounds","34,000 pounds","36,000 pounds","38,000 pounds"],"explanation":"Раздел 32-9-20(4) Кодекса Алабамы ограничивает нагрузку на сдвоенную ось на системе межштатных автомагистралей до 34,000 pounds, включая все допуски при контроле, что соответствует федеральному пределу. Источник: Alabama Code Section 32-9-20."},"4":{"q":"Какова максимальная общая полная масса транспортного средства или сочетания транспортных средств на системе межштатных автомагистралей (Interstate Highway System) в Алабаме, включая все допуски при контроле?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Раздел 32-9-20(4) Кодекса Алабамы ограничивает общую полную массу величиной 80,000 pounds, включая все допуски при контроле, на системе межштатных автомагистралей, что соответствует 23 U.S.C. 127. Источник: Alabama Code Section 32-9-20."},"5":{"q":"Какова максимальная длина одиночного (цельного) транспортного средства на автомагистралях Алабамы?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Раздел 32-9-20(3) Кодекса Алабамы устанавливает, что ни одно одиночное транспортное средство не должно превышать 40 feet в длину. Источник: Alabama Code Section 32-9-20."},"6":{"q":"В составе автопоезда «седельный тягач — полуприцеп» в Алабаме какова максимальная длина полуприцепа, включая груз?","options":["48 feet","53 feet","57 feet","65 feet"],"explanation":"Раздел 32-9-20(3) Кодекса Алабамы предусматривает, что полуприцеп, включая груз, используемый в составе «седельный тягач — полуприцеп», не должен превышать 57 feet. Источник: Alabama Code Section 32-9-20."},"7":{"q":"На автомагистралях с полосами движения шириной МЕНЕЕ 12 футов в Алабаме какова максимальная общая внешняя ширина транспортного средства, включая груз?","options":["90 inches","96 inches","102 inches","108 inches"],"explanation":"Раздел 32-9-20(1) Кодекса Алабамы уменьшает максимальную ширину до 96 inches, включая груз, на автомагистралях, полосы движения которых имеют ширину менее 12 футов. Источник: Alabama Code Section 32-9-20."},"8":{"q":"В составе автопоезда «седельный тягач — полуприцеп — прицеп» (сдвоенные прицепы) в Алабаме какова максимальная длина каждого полуприцепа или прицепа, включая груз?","options":["27 feet","28 1/2 feet","30 feet","33 feet"],"explanation":"Раздел 32-9-20(3) Кодекса Алабамы ограничивает длину каждого полуприцепа или прицепа в составе «седельный тягач — полуприцеп — прицеп» (сдвоенный) величиной 28 1/2 feet, включая груз. Источник: Alabama Code Section 32-9-20."},"9":{"q":"Какова максимальная длина транспортного средства, обычно называемого автодомом (motor home), на автомагистралях Алабамы?","options":["40 feet","45 feet","53 feet","57 feet"],"explanation":"Раздел 32-9-20(3) Кодекса Алабамы предусматривает, что транспортные средства, обычно называемые автодомами (motor homes), не должны превышать 45 feet в длину. Источник: Alabama Code Section 32-9-20."},"10":{"q":"При перевозке лесопродукции или водопропускных труб по автомагистрали Алабамы какова максимальная допустимая по закону ширина груза без разрешения?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"Раздел 32-9-20(1) Кодекса Алабамы прямо устанавливает, что ни одно транспортное средство, перевозящее лесопродукцию или водопропускные трубы по любой автомагистрали, не должно иметь груз шириной более 102 inches. Источник: Alabama Code Section 32-9-20."},"11":{"q":"Два последовательных комплекта сдвоенных осей в Алабаме могут каждый нести полную нагрузку 34,000 pounds при условии, что расстояние между первой и последней осями этих последовательных комплектов составляет не менее скольки футов?","options":["30 feet","34 feet","36 feet","41 feet"],"explanation":"Раздел 32-9-20(4) Кодекса Алабамы допускает, чтобы два последовательных комплекта сдвоенных осей каждый нёс 34,000 pounds, если общее расстояние между первой и последней осями составляет 36 feet или более, при условии, что общая полная масса не превышает 80,000 pounds. Источник: Alabama Code Section 32-9-20."},"12":{"q":"Какую формулу Алабама применяет для определения максимально допустимой полной массы для группы из двух или более последовательных осей?","options":["Федеральную мостовую формулу W = 500(LN/(N-1) + 12N + 36)","Формулу отношения мощности к массе","Единое правило 80,000 pounds независимо от расстояния между осями","Формулу пропорциональности тормозного пути"],"explanation":"Раздел 32-9-20(4)(c) Кодекса Алабамы принимает федеральную мостовую формулу W = 500(LN/(N-1) + 12N + 36), где W — полная масса, L — расстояние между крайними осями группы, а N — число осей. Источник: Alabama Code Section 32-9-20."},"13":{"q":"Для контроля пределов нагрузки на ось и полной массы Алабама допускает весовой (контрольный) допуск, рассчитываемый путём умножения предписанной массы на какой коэффициент?","options":["0.05 (5 percent)","0.10 (10 percent)","0.15 (15 percent)","0.20 (20 percent)"],"explanation":"Раздел 32-9-20(4)(d) Кодекса Алабамы допускает весовой/контрольный допуск, равный предписанной массе, умноженной на одну десятую (.10), то есть 10 percent, прежде чем будет признано нарушение. Источник: Alabama Code Section 32-9-20."},"14":{"q":"Согласно закону Алабамы, двух- и трёхосные транспортные средства, используемые исключительно для перевозки сельскохозяйственной продукции на ферму и с фермы, НЕ обязаны соответствовать какому требованию?","options":["Пределам ширины и высоты","Требованиям по одиночной оси и полной массе","Требованиям по освещению и маркировке","Пределам длины для сочетаний транспортных средств"],"explanation":"Раздел 32-9-20(4)(j) Кодекса Алабамы освобождает двух- и трёхосные транспортные средства, используемые исключительно для перевозки сельскохозяйственной продукции на ферму и с фермы, от требований по одиночной оси пункта (4)a и требований по полной массе пункта (4)c. Источник: Alabama Code Section 32-9-20."},"15":{"q":"Транспортному средству, использующему работающую вспомогательную силовую установку (APU) или технологию снижения холостого хода в Алабаме, разрешается какая дополнительная масса сверх пределов полной массы, нагрузки на ось, сдвоенную ось или мостовой формулы?","options":["250 pounds","400 pounds","550 pounds","1,000 pounds"],"explanation":"Раздел 32-9-20(b)(1) Кодекса Алабамы допускает до дополнительных 400 pounds (или фактическую сертифицированную массу APU, в зависимости от того, что меньше) для транспортных средств, использующих вспомогательную силовую установку или технологию снижения холостого хода, что отражает федеральный Energy Policy Act of 2005. Источник: Alabama Code Section 32-9-20."},"16":{"q":"Годовое разрешение Алабамы на негабаритную/сверхтяжёлую перевозку НЕ может разрешать эксплуатацию транспортного средства, общая полная масса которого превышает какую величину?","options":["100,000 pounds","120,000 pounds","150,000 pounds","200,000 pounds"],"explanation":"Раздел 32-9-29(b)(1) Кодекса Алабамы предусматривает, что годовое разрешение не может разрешать транспортное средство, общая полная масса которого превышает 150,000 pounds, а полная масса свыше 100,000 pounds требует предварительной прокладки маршрута департаментом. Источник: Alabama Code Section 32-9-29."},"17":{"q":"По годовому разрешению Алабамы нагрузка на одиночную ось транспортного средства, имеющего разрешение, не может превышать какую величину?","options":["20,000 pounds","22,000 pounds","25,000 pounds","27,000 pounds"],"explanation":"Раздел 32-9-29(b)(1) Кодекса Алабамы ограничивает нагрузку на одиночную ось по годовому разрешению на негабаритную/сверхтяжёлую перевозку величиной 22,000 pounds, включая все допуски при контроле. Источник: Alabama Code Section 32-9-29."},"18":{"q":"Годовое разрешение Алабамы на негабаритную/сверхтяжёлую перевозку не может разрешать транспортное средство, высота которого превышает какой предел?","options":["13 feet 6 inches","14 feet","15 feet 6 inches","16 feet"],"explanation":"Раздел 32-9-29(b)(1) Кодекса Алабамы предусматривает, что годовое разрешение не может разрешать эксплуатацию транспортного средства, высота которого превышает 14 feet. Источник: Alabama Code Section 32-9-29."},"19":{"q":"Согласно закону Алабамы, какой статус имеют фермерская и сельскохозяйственная продукция и оборудование в отношении разрешений на негабаритные/сверхтяжёлые перевозки для движения по системе автомагистралей штата?","options":["Им требуется специальное годовое фермерское разрешение","Они освобождены от требования получать разрешения","Им требуется только разовое разрешение на поездку","Они должны получить разрешение, но не платят пошлину"],"explanation":"Раздел 32-9-29(f) Кодекса Алабамы устанавливает, что фермерская и сельскохозяйственная продукция и оборудование освобождены от требования получать разрешения для движения по системе автомагистралей штата Алабама. Источник: Alabama Code Section 32-9-29."},"20":{"q":"В Алабаме CDL класса A требуется для управления любым сочетанием транспортных средств с полной массой автопоезда (GCWR) не менее какой величины, когда GVWR буксируемой единицы превышает 10,000 pounds?","options":["16,001 pounds или более","26,001 pounds или более","10,001 pounds или более","36,001 pounds или более"],"explanation":"Алабама определяет CDL класса A как любое сочетание транспортных средств с GCWR 11,794 kilograms или более (26,001 pounds или более), при условии, что GVWR буксируемого(-ых) транспортного средства(-в) превышает 4,536 kg (10,000 lb). Источник: ALEA Driver License Division, страница классов/индоссаментов CDL и Alabama CDL Manual."},"21":{"q":"Согласно правилам Алабамы, какой класс CDL охватывает одиночное транспортное средство с GVWR 26,001 pounds или более, либо такое транспортное средство, буксирующее единицу с GVWR не более 10,000 pounds?","options":["Класс A","Класс C","Класс B","Класс D"],"explanation":"Алабама определяет класс B как любое одиночное транспортное средство с GVWR 11,794 kg или более (26,001 lb или более), либо любое такое транспортное средство, буксирующее транспортное средство с GVWR не более 4,536 kg (10,000 lb). Источник: страница классов/индоссаментов CDL ALEA и Alabama CDL Manual."},"22":{"q":"Транспортному средству, которое не соответствует весовым порогам класса A или класса B, но рассчитано на перевозку 16 или более пассажиров (включая водителя) либо перевозит опасные материалы, требующие табличек (placards), требуется какой класс CDL Алабамы?","options":["Класс C","Класс B","Класс A","Класс M"],"explanation":"Класс C Алабамы — это любое транспортное средство (или сочетание), не соответствующее определению класса A или B, но рассчитанное на перевозку 16 или более пассажиров, включая водителя, либо используемое для перевозки опасных материалов, требующих размещения табличек согласно 49 CFR part 172 subpart F. Источник: страница классов/индоссаментов CDL ALEA."},"23":{"q":"На перевозку скольки пассажиров (включая водителя) должно быть рассчитано транспортное средство, прежде чем в Алабаме потребуются индоссамент на пассажирский или школьный автобус и соответствующий CDL?","options":["12 или более","24 или более","16 или более","20 или более"],"explanation":"Алабама (следуя федеральному стандарту) устанавливает порог в 16 или более пассажиров, включая водителя, для определения класса C и для целей индоссамента на пассажирский/школьный автобус. Источник: страница классов/индоссаментов CDL ALEA; Alabama CDL Manual."},"24":{"q":"Какой код индоссамента на CDL Алабамы разрешает водителю управлять цистерной (tank vehicle)?","options":["T","N","H","X"],"explanation":"Алабама использует федеральные коды индоссаментов: N — это индоссамент на цистерну (Tank Vehicle / Tanker). Источник: страница классов/индоссаментов CDL ALEA; Alabama CDL Manual."},"25":{"q":"Что разрешает индоссамент «T» на CDL Алабамы?","options":["Перевозку опасных материалов","Управление цистерной","Управление сдвоенными и строенными прицепами","Управление эвакуатором"],"explanation":"В Алабаме индоссамент T разрешает управление сдвоенными/строенными прицепами и получается путём сдачи только теоретического теста (без экзамена по навыкам). Источник: страница классов/индоссаментов CDL ALEA; Alabama CDL Manual."},"26":{"q":"Какой единый код индоссамента на CDL Алабамы обозначает сочетание индоссаментов на цистерну (Tank Vehicle) И опасные материалы (Hazardous Materials)?","options":["H","N","X","P"],"explanation":"Алабама использует код X для совмещённого индоссамента на цистерну/опасные материалы (Tank Vehicle/Hazardous Materials); H отдельно — это HazMat, а N отдельно — это цистерна (Tanker). Источник: страница классов/индоссаментов CDL ALEA."},"27":{"q":"Прежде чем Алабама сможет выдать индоссамент HazMat (H) на CDL, заявитель должен получить что от федерального Управления транспортной безопасности (TSA)?","options":["Медицинское свидетельство (Medical Examiner's Certificate)","Заключение об отсутствии угрозы безопасности (Determination of No Security Threat)","Сертификат обучения FMCSA по почте","Освобождение от теоретического теста"],"explanation":"Ни один штат не может выдать или продлить индоссамент HazMat, если только TSA не вернёт заключение об отсутствии угрозы безопасности (Determination of No Security Threat) после снятия отпечатков пальцев и оценки угрозы безопасности. Алабама требует эту проверку TSA плюс теоретический тест HazMat. Источник: TSA/49 CFR 1572; требования ALEA к индоссаменту HazMat."},"28":{"q":"Каков минимальный возраст для получения CDL Алабамы для ВНУТРИШТАТНОГО (только в пределах Алабамы) коммерческого вождения?","options":["21","19","18","16"],"explanation":"Алабама разрешает CDL с 18 лет для внутриштатной эксплуатации; межштатная эксплуатация требует возраста 21 год. Источник: ALEA CDL FAQ; Alabama CDL Manual."},"29":{"q":"Каков минимальный возраст, необходимый для управления коммерческим транспортным средством через границы штатов (межштатно) по CDL Алабамы?","options":["18","21","19","25"],"explanation":"Межштатное коммерческое вождение (а также перевозка опасных материалов или грузов, требующих табличек, через границы штатов) требует минимального возраста 21 год в Алабаме, что соответствует федеральным правилам. Источник: ALEA CDL FAQ; 49 CFR 391.11."},"30":{"q":"После выдачи коммерческого ученического разрешения (CLP) как долго заявитель в Алабаме должен владеть CLP, прежде чем ему будет разрешено сдавать экзамен по навыкам (дорожный) на CDL?","options":["30 days","14 days","10 days","60 days"],"explanation":"Федеральный закон, принятый Алабамой, требует, чтобы CLP находилось во владении не менее 14 days, прежде чем можно будет сдавать экзамен по навыкам на CDL. Источник: ALEA CDL FAQ; 49 CFR 383.25."},"31":{"q":"Как долго действительно коммерческое ученическое разрешение (CLP) Алабамы, и можно ли его продлить?","options":["180 days, и его можно продлить один раз","360 days, и его нельзя продлить","1 year, и его можно продлевать ежегодно","90 days, и его нельзя продлить"],"explanation":"CLP Алабамы действительно в течение 360 days и не подлежит продлению; если срок его действия истекает, заявитель должен пересдать все письменные тесты и оплатить новое CLP. Источник: ALEA CDL FAQ."},"32":{"q":"Какой тип базового водительского удостоверения уже должен иметь заявитель в Алабаме, прежде чем подавать заявление на коммерческое ученическое разрешение или CDL?","options":["Действительное водительское удостоверение Алабамы класса D","Действительное мотоциклетное удостоверение Алабамы класса M","Только ученическое разрешение","Предыдущее удостоверение не требуется"],"explanation":"Алабама требует, чтобы заявители имели действительное водительское удостоверение Алабамы класса D (обычное), прежде чем подавать заявление на CLP или CDL. Источник: ALEA CDL FAQ; страница Document Requirements."},"33":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения в Алабаме?","options":["Департамент транспорта Алабамы (ALDOT)","Окружная пробатная контора (county probate office)","Подразделение по водительским удостоверениям Правоохранительного агентства Алабамы (ALEA Driver License Division)","Федеральное управление безопасности автоперевозчиков (FMCSA)"],"explanation":"CDL в Алабаме выдаются Правоохранительным агентством Алабамы (ALEA) через его Подразделение по водительским удостоверениям (Driver License Division), а не отдельным DMV или ALDOT. Источник: ALEA Driver License Division."},"34":{"q":"Обучение водителей начального уровня (ELDT), требуемое перед получением CDL Алабамы впервые, должно проводиться поставщиком, внесённым в какой список?","options":["Только в список одобренных школ ALEA","Реестр поставщиков обучения FMCSA (FMCSA Training Provider Registry, TPR)","Любую частную транспортную компанию","Реестр Системы общественных колледжей Алабамы"],"explanation":"С 7 февраля 2022 года заявители, впервые получающие CDL (а также при определённых повышениях класса/индоссаментах), должны пройти ELDT у поставщика, внесённого в FMCSA Training Provider Registry, который должен загрузить данные о прохождении до того, как Алабама разрешит тестирование. Источник: ALEA CDL FAQ; 49 CFR part 380."},"35":{"q":"Какое действие с CDL НЕ требует само по себе обучения водителей начального уровня (ELDT) перед тестированием в Алабаме?","options":["Получение CDL впервые","Повышение класса с B до A","Продление CDL с тем же классом и индоссаментами","Получение первого индоссамента HazMat (H)"],"explanation":"ELDT применяется при получении CDL впервые, повышении класса и получении впервые индоссаментов S, P или H. Простое продление, которое не повышает класс и не добавляет охватываемый индоссамент, не влечёт ELDT. Источник: 49 CFR part 380; ALEA CDL FAQ."},"36":{"q":"Заявитель на CDL Алабамы, который занимается межштатной торговлей и обязан соответствовать федеральным медицинским стандартам, самосертифицируется по какой категории?","options":["Excepted Interstate (межштатная с освобождением)","Non-Excepted Interstate (межштатная без освобождения)","Excepted Intrastate (внутриштатная с освобождением)","Non-Excepted Intrastate (внутриштатная без освобождения)"],"explanation":"Категория Non-Excepted Interstate применяется к водителям, занятым в межштатной торговле, которые должны иметь действительное медицинское свидетельство DOT (DOT Medical Examiner's Certificate). Алабама требует самосертификации по одной из четырёх категорий согласно 49 CFR 383. Источник: требования ALEA к самосертификации; 49 CFR 383.71."},"37":{"q":"Из скольки категорий медицинской самосертификации должен выбирать обладатель CDL Алабамы, и какая из них требует наличия действующей медицинской карты DOT?","options":["Две категории; только межштатная требует медицинской карты","Четыре категории; категория Non-Excepted Interstate требует действующей медицинской карты DOT","Три категории; ни одна не требует медицинской карты","Четыре категории; категория Excepted Intrastate требует действующей медицинской карты DOT"],"explanation":"Алабама использует четыре федеральные категории (Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, Excepted Intrastate). Водители, сертифицирующиеся как Non-Excepted Interstate, должны предоставить и поддерживать медицинское свидетельство DOT (DOT Medical Examiner's Certificate) от сертифицированного FMCSA эксперта. Источник: самосертификация ALEA; 49 CFR 383.71."},"38":{"q":"При подаче заявления на CDL или CLP Алабамы какой набор документов должен предоставить заявитель?","options":["Только карту социального страхования (Social Security card)","Подтверждение личности, подтверждение номера социального страхования, подтверждение проживания в Алабаме и (если не гражданин США) подтверждение законного пребывания","Только паспорт и два счёта за коммунальные услуги","Подтверждение личности и аттестат об окончании средней школы"],"explanation":"ALEA требует первичное подтверждение личности, документальное подтверждение SSN, подтверждение проживания в Алабаме и подтверждение законного пребывания для неграждан; один и тот же документ не может засчитываться за два требования. Источник: страница ALEA Document Requirements and Fees."},"39":{"q":"Поскольку школьный автобус, перевозящий 16 или более человек, также является пассажирским транспортным средством, что требует Алабама в дополнение к индоссаменту на школьный автобус (S)?","options":["Отдельный CDL класса A","Индоссамент на пассажирский транспорт (P)","Индоссамент на цистерну (N)","Индоссамент на сдвоенные/строенные прицепы (T)"],"explanation":"Алабама требует индоссамент на пассажирский транспорт (P) вместе с индоссаментом на школьный автобус (S); заявители сдают теоретические тесты по общим знаниям, пассажирскому транспорту и школьному автобусу плюс экзамен по навыкам на репрезентативном автобусе. Источник: классы/индоссаменты CDL ALEA; Alabama CDL Manual."},"40":{"q":"В Алабаме каков наименьший уровень концентрации алкоголя в крови (BAC), при котором управление коммерческим транспортным средством становится незаконным?","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"Алабама следует федеральному стандарту для CMV: управлять CMV незаконно, если ваш BAC составляет 0.04% или более. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"41":{"q":"Согласно правилу подразумеваемого согласия Алабамы, что предполагается в отношении лица, которое управляет коммерческим транспортным средством на дорогах Алабамы?","options":["Оно дало согласие на проверку на алкоголь","Оно должно иметь при себе отдельную карту согласия","Оно отказывается от права на слушание","Оно даёт согласие, только если явно находится в состоянии опьянения"],"explanation":"Alabama CDL Manual устанавливает, что если вы управляете CMV, считается, что вы дали своё согласие на проверку на алкоголь. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; Ala. Code Title 32."},"42":{"q":"В Алабаме на сколько обладатель CDL лишится CDL за ПЕРВОЕ серьёзное правонарушение, такое как вождение CMV в нетрезвом виде (DUI) или отказ от проверки на алкоголь (когда не перевозятся опасные материалы с табличками)?","options":["60 days","120 days","Не менее 1 year","Не менее 3 years"],"explanation":"Первое серьёзное правонарушение (DUI, BAC 0.04+ в CMV, отказ от проверки, оставление места происшествия и т. д.) приводит к лишению CDL не менее чем на один год. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"43":{"q":"В Алабаме водитель совершает первое серьёзное правонарушение при управлении CMV, на котором размещены таблички (placards) для опасных материалов. Каков срок дисквалификации?","options":["Не менее 1 year","Не менее 2 years","Не менее 3 years","Пожизненно"],"explanation":"Если первое серьёзное правонарушение совершается при управлении CMV, на котором размещены таблички для опасных материалов, дисквалификация составляет не менее трёх лет вместо одного. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"44":{"q":"В Алабаме какова дисквалификация за ВТОРОЕ серьёзное правонарушение (например, второе вождение CMV в нетрезвом виде)?","options":["1 year","3 years","10 years","Пожизненно"],"explanation":"Второе серьёзное правонарушение приводит к пожизненному лишению CDL. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"45":{"q":"В Алабаме отказ от прохождения проверки на алкоголь при управлении CMV рассматривается как какой вид нарушения?","options":["Серьёзное нарушение правил дорожного движения (правило 60 дней)","Серьёзное правонарушение (лишение не менее чем на 1 год)","Незначительное нарушение только со штрафом","Нарушение предписания о выводе из эксплуатации (out-of-service order)"],"explanation":"Отказ от прохождения проверки на содержание алкоголя в крови отнесён в Алабаме к серьёзным правонарушениям и влечёт дисквалификацию не менее чем на один год за первое нарушение. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"46":{"q":"Что из перечисленного указано в Alabama CDL Manual как СЕРЬЁЗНОЕ нарушение правил дорожного движения?","options":["Превышение скорости на 5 mph","Чрезмерное превышение скорости (на 15 mph или более сверх установленного предела)","Просроченная регистрационная наклейка","Перегоревший задний фонарь"],"explanation":"К серьёзным нарушениям правил дорожного движения относятся чрезмерное превышение скорости, определяемое как 15 mph или более сверх установленного предела, а также безрассудное вождение, неправильное перестроение и слишком близкое следование за другим транспортным средством. Источник: Alabama CDL Manual (ALEA), Section 1.3.3."},"47":{"q":"В Алабаме обладатель CDL осуждён за ДВА серьёзных нарушения правил дорожного движения на CMV в течение трёхлетнего периода. Какова дисквалификация?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Два серьёзных нарушения правил дорожного движения на CMV в течение трёхлетнего периода приводят к лишению CDL не менее чем на 60 days. Источник: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51."},"48":{"q":"В Алабаме обладатель CDL осуждён за ТРИ серьёзных нарушения правил дорожного движения на CMV в течение трёхлетнего периода. Какова дисквалификация?","options":["Не менее 60 days","Не менее 90 days","Не менее 120 days","Не менее 1 year"],"explanation":"Три или более серьёзных нарушения правил дорожного движения на CMV в течение трёхлетнего периода приводят к лишению CDL не менее чем на 120 days. Источник: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51."},"49":{"q":"В Алабаме какова дисквалификация за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order)?","options":["Не менее 30 days","Не менее 90 days","Не менее 180 days","Не менее 1 year"],"explanation":"Первое нарушение предписания о выводе из эксплуатации приводит к лишению CDL не менее чем на 90 days. Источник: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51."},"50":{"q":"В Алабаме водитель совершает ДВА нарушения предписания о выводе из эксплуатации (out-of-service order) в течение десятилетнего периода. Какова дисквалификация?","options":["Не менее 120 days","Не менее 1 year","Не менее 3 years","Не менее 5 years"],"explanation":"Два нарушения предписания о выводе из эксплуатации в течение десятилетнего периода приводят к лишению CDL не менее чем на один год. Источник: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51."},"51":{"q":"В Алабаме водитель совершает ТРИ или более нарушения предписания о выводе из эксплуатации (out-of-service order) в течение десятилетнего периода. Какова дисквалификация?","options":["Не менее 1 year","Не менее 2 years","Не менее 3 years","Пожизненно"],"explanation":"Три или более нарушения предписания о выводе из эксплуатации в течение десятилетнего периода приводят к лишению CDL не менее чем на три года. Источник: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51."},"52":{"q":"В Алабаме какова дисквалификация за ПЕРВОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) на CMV?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Первое нарушение на железнодорожном переезде приводит к лишению CDL не менее чем на 60 days. Источник: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51."},"53":{"q":"В Алабаме обладатель CDL получает ВТОРОЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение трёхлетнего периода. Какова дисквалификация?","options":["Не менее 60 days","Не менее 120 days","Не менее 6 months","Не менее 1 year"],"explanation":"Второе нарушение на железнодорожном переезде в течение трёхлетнего периода приводит к лишению CDL не менее чем на 120 days. Источник: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51."},"54":{"q":"В Алабаме обладатель CDL получает ТРЕТЬЕ нарушение на железнодорожном переезде (railroad-highway grade crossing) в течение трёхлетнего периода. Какова дисквалификация?","options":["Не менее 120 days","Не менее 180 days","Не менее 1 year","Не менее 3 years"],"explanation":"Третье нарушение на железнодорожном переезде в течение трёхлетнего периода приводит к лишению CDL не менее чем на один год. Источник: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51."},"55":{"q":"В Алабаме что происходит, если у водителя CMV обнаружено любое определяемое количество алкоголя, которое всё же ниже 0.04%?","options":["Ничего, это ниже допустимого предела","Вывод из эксплуатации на 24 hours","Немедленная дисквалификация на 1 year","Пожизненный запрет"],"explanation":"Водитель CMV с любым определяемым количеством алкоголя ниже 0.04% выводится из эксплуатации на 24 hours. Источник: Alabama CDL Manual (ALEA), Section 1.3.2."},"56":{"q":"В Алабаме после скольки осуждений за использование ручного мобильного телефона при управлении CMV у водителя дисквалифицируется CDL?","options":["Одно осуждение","Два или более осуждений","Четыре или более осуждений","Шесть или более осуждений"],"explanation":"CDL дисквалифицируется после двух или более осуждений по закону штата об использовании ручного мобильного телефона при управлении CMV: 60 days за второе нарушение в течение 3 лет и 120 days за три или более в течение 3 лет. Источник: Alabama CDL Manual (ALEA), Section 2.9.4."},"57":{"q":"Согласно правилам Alabama CDL Manual, отправка текстовых сообщений при управлении CMV запрещена. Осуждения водителя могут влечь гражданско-правовой штраф в размере до какой суммы?","options":["До $500","До $1,000","До $2,750","До $11,000"],"explanation":"Каждое нарушение, связанное с отправкой текстовых сообщений или использованием ручного телефона водителем CMV, влечёт гражданско-правовой штраф в размере до $2,750 (работодатели могут быть оштрафованы на сумму до $11,000). Источник: Alabama CDL Manual (ALEA), Sections 2.9.4 и 2.9.5; 49 CFR 392."},"58":{"q":"В Алабаме использование CMV для совершения тяжкого преступления (felony), связанного с контролируемыми веществами, влечёт какое наказание?","options":["Дисквалификацию на 60 days","Дисквалификацию на 1 year","Дисквалификацию на 3 years","Пожизненное лишение CDL"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с контролируемыми веществами, приводит к пожизненному лишению CDL без восстановления. Источник: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"59":{"q":"Что из перечисленного является СЕРЬЁЗНЫМ нарушением правил дорожного движения согласно Alabama CDL Manual, а не серьёзным правонарушением (major offense)?","options":["Управление CMV с BAC 0.04%","Отказ от химической проверки на алкоголь","Слишком близкое следование за другим транспортным средством","Оставление места происшествия"],"explanation":"Слишком близкое следование за другим транспортным средством отнесено к серьёзным нарушениям правил дорожного движения (засчитывается в правило 60/120 дней), тогда как DUI, отказ от проверки и оставление места происшествия являются серьёзными правонарушениями, влекущими дисквалификацию не менее чем на один год. Источник: Alabama CDL Manual (ALEA), Sections 1.3.2 и 1.3.3."},"60":{"q":"Когда транспортное средство с табличками опасных грузов должно остановиться на железнодорожном переезде в Алабаме, на каком расстоянии от ближайшего рельса должен остановиться водитель?","options":["Не менее 10 футов и не более 25 футов","Не менее 15 футов и не более 50 футов","Не менее 25 футов и не более 75 футов","Не менее 5 футов и не более 15 футов"],"explanation":"Алабама требует, чтобы транспортное средство с табличками HazMat останавливалось за 15–50 футов до ближайшего рельса, а затем продолжало движение только тогда, когда поезда нет и можно проехать пути без остановки. Источник: Alabama (ALEA) CDL Manual, Section 9.6 Railroad Crossings; Ala. Code 32-5A-150."},"61":{"q":"Согласно закону Алабамы Move Over Act, когда водитель на многополосной дороге не может безопасно освободить полосу, ближайшую к остановившемуся аварийному автомобилю или машине правоохранительных органов с включёнными проблесковыми маячками, что должен сделать водитель?","options":["Снизить скорость как минимум на 10 mph ниже установленного ограничения скорости","Снизить скорость как минимум на 20 mph ниже установленного ограничения скорости","Полностью остановиться, пока аварийный автомобиль не уедет","Снизить скорость как минимум на 15 mph ниже установленного ограничения скорости"],"explanation":"Согласно закону Алабамы Move Over Act, водитель, который не может безопасно перестроиться, должен снизить скорость как минимум на 15 mph ниже установленного ограничения скорости. Источник: Ala. Code 32-5A-58.2 (Moving Over or Reducing Speed When Approaching Emergency Vehicles)."},"62":{"q":"Каково максимальное ограничение скорости на межштатной автомагистрали (interstate) в Алабаме (если иное не указано на знаках или не разрешено)?","options":["65 mph","75 mph","80 mph","70 mph"],"explanation":"Закон Алабамы устанавливает максимальную скорость на межштатных автомагистралях 70 mph; на других дорогах с четырьмя и более полосами максимум составляет 65 mph. Источник: Ala. Code 32-5A-171 (Maximum Limits)."},"63":{"q":"В Алабаме, если коммерческое транспортное средство вынуждено остановиться на дороге с односторонним движением или дороге с разделительной полосой, где должны быть размещены три аварийных предупреждающих устройства?","options":["В 10 футах, 50 футах и 150 футах в сторону приближающегося транспорта","В 25 футах, 100 футах и 250 футах в сторону приближающегося транспорта","В 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта","В 5 футах, 75 футах и 100 футах в сторону приближающегося транспорта"],"explanation":"На дороге с односторонним движением или с разделительной полосой Алабама предписывает размещать предупреждающие устройства в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта. Источник: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices for Stopped Vehicles."},"64":{"q":"Согласно закону Алабамы о школьных автобусах, когда водитель транспортного средства, встречающий или обгоняющий остановившийся школьный автобус с работающими световыми сигналами, должен полностью остановиться?","options":["Только при приближении сзади автобуса, никогда спереди","Только когда автобус находится на той же стороне дороги, что и водитель","Только если на проезжей части явно присутствуют дети","При приближении с любого направления на обычной двухполосной или неразделённой дороге"],"explanation":"Алабама требует, чтобы водитель, встречающий или обгоняющий школьный автобус с ЛЮБОГО направления, останавливался, когда автобус остановился для посадки или высадки детей с включённым световым сигналом, за исключением дороги с разделительной полосой, как она определена законом. Источник: Ala. Code 32-5A-154."},"65":{"q":"Какая ситуация описывает ЕДИНСТВЕННОЕ в Алабаме исключение из правила об остановке перед стоящим школьным автобусом, который высаживает или сажает детей?","options":["Движение в любом городе с установленным ограничением скорости 30 mph или менее","Любой момент, когда водитель находится дальше 100 футов от автобуса","Встреча с автобусом со встречной проезжей части дороги с разделительной полосой, разделённой на две или более противоположных полос","Любая четырёхполосная дорога, разделённая она или нет"],"explanation":"Алабама освобождает водителя от остановки только при встрече со школьным автобусом, остановившимся на встречной проезжей части дороги с РАЗДЕЛИТЕЛЬНОЙ полосой, имеющей четыре или более полос, которая допускает движение как минимум двух полос транспорта в противоположных направлениях. На неразделённой многополосной дороге все водители всё равно должны остановиться. Источник: Ala. Code 32-5A-154."},"66":{"q":"Автобус, перевозящий пассажиров в Алабаме, должен остановиться на каком расстоянии от ближайшего рельса на железнодорожном переезде?","options":["Между 10 и 40 футами","Между 20 и 60 футами","Между 5 и 25 футами","Между 15 и 50 футами"],"explanation":"Алабама требует, чтобы автобус, перевозящий пассажиров, останавливался на расстоянии от 15 до 50 футов до ближайшего рельса, прислушивался и смотрел в обе стороны, а затем пересекал пути только тогда, когда это можно сделать без остановки на путях. Источник: Alabama (ALEA) CDL Manual, Section 4.3.5 Railroad-Highway Crossing Stops."},"67":{"q":"На двухполосной дороге Алабамы с движением в обоих направлениях, где размещаются предупреждающие устройства, когда CMV остановлено?","options":["В пределах 10 футов от транспортного средства, а также 200 футов спереди и 200 футов сзади","В пределах 25 футов от транспортного средства, а также 150 футов спереди и сзади","Все три размещаются только в 100 футах позади транспортного средства","В пределах 10 футов от транспортного средства, а также 100 футов спереди и 100 футов сзади"],"explanation":"На двухполосной дороге с движением в обе стороны Алабама предписывает размещать одно устройство в пределах 10 футов от транспортного средства, одно — в 100 футах позади и одно — в 100 футах впереди, на обочине или в полосе. Источник: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices."},"68":{"q":"Каков штраф за нарушение закона Алабамы Move Over Act?","options":["$100","$500","$200","$50"],"explanation":"Нарушение закона Алабамы Move Over является правонарушением (misdemeanor), наказуемым штрафом в двести долларов ($200). Источник: Ala. Code 32-5A-58.2."},"69":{"q":"Помимо машин правоохранительных органов и аварийных автомобилей, какие из этих остановившихся транспортных средств с включёнными предупреждающими/проблесковыми маячками также влекут за собой требования закона Алабамы Move Over?","options":["Мусоровоз или транспортное средство для сбора отходов либо вторсырья","Любой частный легковой автомобиль с включённой аварийной сигнализацией","Школьный автобус, сажающий детей","Развозной фургон, припаркованный в два ряда на городской улице"],"explanation":"Алабама расширила закон Move Over Act, чтобы охватить эвакуаторы, транспортные средства коммунальных служб, транспортные средства технического обслуживания/строительства/изыскательских работ, А ТАКЖЕ мусоровозы и транспортные средства для сбора отходов либо вторсырья с включёнными проблесковыми маячками. Источник: Ala. Code 32-5A-58.2."},"70":{"q":"Каково максимальное ограничение скорости в Алабаме на дороге (кроме межштатной автомагистрали), имеющей четыре или более полос движения?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"Алабама ограничивает скорость на немежштатных дорогах с четырьмя и более полосами до 65 mph, тогда как межштатные автомагистрали ограничены 70 mph. Источник: Ala. Code 32-5A-171."},"71":{"q":"Согласно правилу Алабамы об использовании полос, коммерческое транспортное средство, движущееся медленнее нормальной скорости потока, должно двигаться где?","options":["Всегда в центральной полосе","В правой полосе или как можно ближе к правому краю проезжей части","В любой полосе, поскольку грузовики освобождены от правил о полосах","В левой полосе, чтобы оставить правые полосы свободными для въезжающих"],"explanation":"Алабама требует, чтобы любое транспортное средство, движущееся медленнее нормальной скорости потока, держалось правее (в правой полосе или как можно ближе к правому краю), за исключением случаев обгона, объезда или подготовки к левому повороту. Источник: Ala. Code 32-5A-80 (Driving on Right Side of Roadway)."},"72":{"q":"Если остановившееся CMV в Алабаме находится на подъёме или повороте, который перекрывает обзор приближающимся водителям, что водитель должен сделать с самым задним предупреждающим устройством?","options":["Отнести его дальше назад, чтобы транспорт был предупреждён минимум за 500 футов","Оставить его ровно в 200 футах позади независимо от препятствия","Убрать его и полагаться только на аварийную сигнализацию транспортного средства","Разместить все три устройства прямо за задним бампером"],"explanation":"Когда подъём, поворот или иное препятствие не позволяет водителям увидеть транспортное средство в пределах 500 футов, Алабама предписывает отнести самый задний треугольник дальше по дороге, чтобы предупреждение обеспечивалось за пределами препятствия. Источник: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices."},"73":{"q":"Каков диапазон штрафа за ПЕРВОЕ осуждение за незаконный объезд остановившегося школьного автобуса в Алабаме?","options":["Не менее $150 и не более $300","Не менее $50 и не более $100","Не менее $500 и не более $1,000","Фиксированные $250 без диапазона"],"explanation":"Первое осуждение за незаконный объезд остановившегося школьного автобуса в Алабаме влечёт штраф не менее $150 и не более $300, с более суровыми штрафами, общественными работами и приостановлением действия лицензии за повторные нарушения. Источник: Ala. Code 32-5A-154."},"74":{"q":"Какие транспортные средства обязаны полностью останавливаться на каждом железнодорожном переезде в Алабаме?","options":["Все коммерческие транспортные средства свыше 10,000 фунтов без исключений","Автобусы, перевозящие пассажиров, и транспортные средства с табличками опасных грузов","Только пустые автоцистерны","Только транспортные средства, буксирующие прицеп любого вида"],"explanation":"Алабама требует, чтобы автобусы, перевозящие пассажиров, и транспортные средства с табличками HazMat (включая загруженные или пустые цистерны с HazMat и транспортные средства, перевозящие любое количество хлора) останавливались на переездах; обычные CMV не обязаны останавливаться, если этого не требуют условия. Источник: Alabama (ALEA) CDL Manual, Sections 2.15 and 9.6."},"75":{"q":"Какова максимальная разрешённая ШИРИНА груза в Алабаме, прежде чем требуется разрешение на негабаритный груз от ALDOT?","options":["8 футов 0 дюймов","10 футов 0 дюймов","8 футов 6 дюймов","9 футов 6 дюймов"],"explanation":"Стандартная разрешённая законом максимальная ширина груза в Алабаме составляет 8 футов 6 дюймов (102 inches); всё, что шире, требует разрешения на негабаритный груз от Alabama Department of Transportation (ALDOT). Источник: ALDOT Oversize/Overweight Permit regulations."},"76":{"q":"Какова максимальная разрешённая ВЫСОТА груза в Алабаме, прежде чем требуется разрешение на негабаритный груз?","options":["13 футов 0 дюймов","13 футов 6 дюймов","14 футов 0 дюймов","12 футов 6 дюймов"],"explanation":"Алабама устанавливает разрешённую законом максимальную высоту транспортного средства/груза в 13 футов 6 дюймов; грузы, превышающие это значение, требуют разрешения ALDOT на негабаритный груз, а при высоте более 15 футов 6 дюймов требуется передовое сопровождение с измерительной штангой (height-pole escort). Источник: ALDOT Oversize/Overweight Permit regulations."},"77":{"q":"На длинном крутом спуске в горной местности Алабамы какова надлежащая цель аварийной тормозной полосы для неуправляемых транспортных средств (escape ramp)?","options":["Остановить транспортное средство с отказавшими тормозами с помощью слоя рыхлого мягкого материала","Обеспечить мощёную зону отдыха, чтобы грузовики добровольно охлаждали тормоза","Служить обязательной полосой досмотра для всех CMV, спускающихся по уклону","Позволить более быстрым транспортным средствам обгонять медленные грузовики на подъёме"],"explanation":"Аварийные тормозные полосы строятся на крутых спусках, чтобы безопасно останавливать неуправляемые транспортные средства с помощью длинного слоя рыхлого мягкого материала; водители должны знать расположение полос на своём маршруте. На уклонах I-59 близ Lookout/Sand Mountain в Алабаме есть такие полосы. Источник: Alabama (ALEA) CDL Manual, Section 2.16 Mountain Driving / Escape Ramps."},"78":{"q":"В течение скольких минут водитель CMV в Алабаме, остановившийся на проезжей части или обочине, должен выставить требуемые аварийные предупреждающие устройства?","options":["10 минут","5 минут","15 минут","30 минут"],"explanation":"Если CMV вынуждено остановиться на дороге или обочине в Алабаме, водитель должен выставить аварийные предупреждающие устройства в течение десяти минут. Источник: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices for Stopped Vehicles."},"79":{"q":"При приближении к остановившемуся аварийному автомобилю на ДВУХПОЛОСНОЙ дороге Алабамы, где перестроиться невозможно, а установленное ограничение составляет 45 mph, что должен сделать водитель?","options":["Сохранять установленную скорость, но включить аварийную сигнализацию","Полностью остановиться в полосе движения","Отъехать как можно дальше в пределах полосы и снизить скорость до 15 mph ниже установленного ограничения (30 mph)","Снизить скорость ровно до 20 mph независимо от установленного ограничения"],"explanation":"На двухполосной дороге Алабамы водитель должен отъехать как можно дальше от аварийного автомобиля в пределах полосы и снизить скорость до 15 mph ниже установленного ограничения, когда это ограничение составляет 25 mph или более (здесь 45 - 15 = 30 mph). Источник: Ala. Code 32-5A-58.2."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) и проводит тестирование на CDL в Алабаме?","options":["Alabama Department of Transportation (ALDOT)","Alabama Law Enforcement Agency (ALEA), Driver License Division","Alabama Department of Revenue, Motor Vehicle Division","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"CDL в Алабаме выдаются и тестируются Alabama Law Enforcement Agency (ALEA), Driver License Division. Alabama CDL Manual публикуется ALEA, а тестирование знаний/навыков проводится в офисах ALEA Commercial Driver License. Источник: Alabama CDL Manual (ALEA), Introduction; ALEA Driver License Division."},"81":{"q":"Как заявитель записывается на тест знаний или навыков для CDL в Алабаме?","options":["Прийти без записи в любой окружной офис tag/license","Подать онлайн-заявку в FMCSA, которая назначает центр тестирования","Отправить письменный запрос по почте в ALDOT и ждать назначенной даты","Записаться на приём в офис ALEA Commercial Driver License через систему онлайн-записи на alea.gov"],"explanation":"Alabama CDL Manual предписывает заявителям записываться на тестирование знаний или навыков в офис ALEA Commercial Driver License; в разделе 'Driver License' / 'Online Services' на alea.gov заявители используют 'Schedule DL Appointment.' Источник: Alabama CDL Manual (ALEA), Commercial Driver License Offices page."},"82":{"q":"В Алабаме, что заявитель должен получить и иметь на руках, прежде чем ему будет разрешено впервые сдавать тест навыков для CDL?","options":["Endorsement на опасные грузы (Hazardous Materials)","Федеральное медицинское освобождение DOT (medical waiver)","Учётную запись International Registration Plan (IRP)","Коммерческое учебное разрешение (CLP)"],"explanation":"Заявитель, впервые получающий или повышающий CDL, должен сначала получить коммерческое учебное разрешение (CLP), сдав требуемый тест(ы) знаний. Затем CLP должно быть на руках, прежде чем можно будет сдавать тест навыков. Источник: Alabama CDL Manual (ALEA), Section 1; ALEA CDL FAQ."},"83":{"q":"Согласно правилам Алабамы (и федеральным), сколько времени CLP должно находиться на руках, прежде чем его держатель сможет сдавать тест навыков для CDL?","options":["Не менее 7 дней","Не менее 30 дней","Не менее 14 дней","Не менее 60 дней"],"explanation":"Алабама следует федеральному требованию о том, что CLP должно находиться на руках минимум 14 дней, прежде чем его держатель сможет сдавать тест навыков для CDL. Источник: ALEA CDL FAQ; 49 CFR 383.25 в применении в Алабаме."},"84":{"q":"Сколько времени действует коммерческое учебное разрешение Алабамы (CLP) и можно ли его продлить?","options":["Действует 180 дней и может быть продлено один раз","Действует 1 год и может быть продлено дважды","Действует 30 дней и не подлежит продлению","Действует 360 дней и не подлежит продлению"],"explanation":"ALEA указывает, что CLP действует 360 дней и не подлежит продлению; если срок его действия истекает, заявитель должен повторно сдать тесты для получения нового CLP. Источник: ALEA CDL FAQ."},"85":{"q":"Прежде чем впервые сдавать тестирование на CDL в Алабаме, какое обучение должен пройти заявитель?","options":["Курс безопасного вождения, одобренный судами Алабамы","40-часовой курс OSHA по безопасности на рабочем месте","Entry-Level Driver Training (ELDT) через провайдера, зарегистрированного в FMCSA","Аудиторный курс под управлением ALEA, проводимый только в офисе в Montgomery"],"explanation":"Entry-Level Driver Training (ELDT) требуется для всех, кто впервые получает CDL (а также для определённых повышений/endorsements). Обучение должно быть завершено через провайдера, указанного в FMCSA Training Provider Registry, до тестирования. Источник: ALEA CDL Self-Certification/FAQ materials; FMCSA ELDT rule, вступившее в силу Feb. 7, 2022."},"86":{"q":"Какой тест знаний должен сдать КАЖДЫЙ заявитель на CDL в Алабаме, независимо от класса транспортного средства или endorsements?","options":["Тест по пневматическим тормозам (air brakes)","Тест по составным транспортным средствам (combination vehicles)","Тест по опасным грузам (hazardous materials)","Тест общих знаний (general knowledge)"],"explanation":"Alabama CDL Manual указывает тест общих знаний как тот, который сдают все заявители; другие тесты знаний (air brakes, combination, passenger, hazmat, tank, doubles/triples, school bus) зависят от запрашиваемого класса и endorsements. Источник: Alabama CDL Manual (ALEA), Section 1.1.1 Knowledge Tests."},"87":{"q":"Согласно Alabama CDL Manual, тест навыков для CDL состоит из каких трёх частей?","options":["Письменный экзамен, проверка зрения и дорожный тест","Сцепка/расцепка, движение задним ходом и проверка пневматических тормозов","Pre-trip, безопасное вождение и вождение ночью","Осмотр транспортного средства, базовый контроль над транспортным средством и вождение на дороге"],"explanation":"Руководство указывает, что тест навыков для CDL состоит из трёх частей: осмотр транспортного средства, базовый контроль над транспортным средством и вождение на дороге. Источник: Alabama CDL Manual (ALEA), Section 1.1.2 Skills Tests."},"88":{"q":"В каком порядке должны сдаваться три части теста навыков для CDL в Алабаме?","options":["В любом порядке, который заявитель выберет в день теста","Сначала вождение на дороге, затем базовый контроль, затем осмотр транспортного средства","В перечисленном порядке (осмотр транспортного средства, затем базовый контроль над транспортным средством, затем вождение на дороге), сдавая каждую часть перед переходом к следующей","Сначала базовый контроль над транспортным средством, затем вождение на дороге, затем осмотр транспортного средства"],"explanation":"Alabama CDL Manual указывает: 'Вы должны проходить части в перечисленном порядке и должны сдать каждую перед переходом к следующей' — осмотр транспортного средства, базовый контроль над транспортным средством, затем вождение на дороге. Источник: Alabama CDL Manual (ALEA), Section 1.1.2."},"89":{"q":"Какое транспортное средство должен использовать заявитель для сдачи теста навыков для CDL в Алабаме?","options":["Транспортное средство, представляющее класс/тип, для которого заявитель желает получить лицензию","Любой легковой автомобиль, поскольку оцениваются только навыки вождения","Транспортное средство, предоставляемое бесплатно центром тестирования ALEA","Любое коммерческое транспортное средство, независимо от класса, при условии что у него есть пневматические тормоза"],"explanation":"Руководство требует, чтобы тест навыков сдавался на типе транспортного средства, для которого заявитель желает получить лицензию; класс используемого транспортного средства может ограничить выдаваемое CDL. Транспортное средство с компонентами, имеющими маркировку или ярлыки, использовать нельзя. Источник: Alabama CDL Manual (ALEA), Section 1.1.2."},"90":{"q":"Во время теста навыков по осмотру транспортного средства для CDL в Алабаме, что обязан делать заявитель у каждого элемента?","options":["Молча осматривать каждый элемент, пока экзаменатор засекает время процесса","Указать на элемент или коснуться его и назвать, а также объяснить экзаменатору, что осматривается и почему","Написать описание каждого элемента в форме осмотра","Только устно перечислить элементы, не касаясь их и не указывая на них"],"explanation":"Руководство указывает, что во время теста по осмотру транспортного средства вы должны указать на осматриваемый элемент или коснуться его и назвать, а также объяснить экзаменатору, что вы осматриваете и почему. Источник: Alabama CDL Manual (ALEA), Section 1.1.2, Vehicle Inspection."},"91":{"q":"Что оценивает часть теста навыков для CDL в Алабаме по базовому контролю над транспортным средством?","options":["Знание правил размещения табличек опасных грузов","Умение двигать транспортное средство вперёд, назад и поворачивать его в пределах обозначенной зоны","Способность читать и интерпретировать дорожные знаки","Способность вести ежедневный журнал водителя"],"explanation":"Тест базового контроля над транспортным средством измеряет умение заявителя управлять транспортным средством — двигать его вперёд, назад и поворачивать в пределах определённой, размеченной зоны, при этом экзаменатор объясняет, как выполнять каждое упражнение. Источник: Alabama CDL Manual (ALEA), Section 1.1.2, Basic Vehicle Control."},"92":{"q":"Какой документ обычно должен предоставить заявитель на CDL в Алабаме в качестве подтверждения своего номера Social Security при подаче заявления?","options":["Подтверждение номера Social Security заявителя (например, карта Social Security)","Только нотариально заверенный аффидевит от текущего работодателя","Только копию последней федеральной налоговой декларации заявителя","Письмо о присвоении DOT-номера автоперевозчику"],"explanation":"Заявители на CDL в Алабаме должны предъявить подтверждение своего номера Social Security вместе с требуемым подтверждением личности/места жительства и действующим водительским удостоверением Алабамы (Class D). Источник: ALEA Driver License Division document requirements; ALEA CDL application materials."},"93":{"q":"Федеральные нормы, принятые в Алабаме, требуют, чтобы держатели CDL для транспортных средств Class A, B или C прошли самосертификацию, выбрав из скольких категорий коммерческих перевозок?","options":["Четырёх","Двух","Трёх","Пяти"],"explanation":"Аффидевит о самосертификации CDL в Алабаме требует, чтобы водитель удостоверил одну из четырёх категорий перевозок. Источник: ALEA CDL Self-Certification Affidavit (ссылается на 49 CFR 383, 384, 390, 391); Alabama CDL Manual Section 1.2."},"94":{"q":"В аффидевите о самосертификации CDL в Алабаме какая одна из четырёх категорий ТРЕБУЕТ, чтобы водитель имел при себе и предоставлял сертификат медицинского эксперта DOT?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate (с алабамским медицинским освобождением — ограничение K)"],"explanation":"Аффидевит Алабамы перечисляет четыре категории: Non-excepted Interstate (подпадает под 49 CFR part 391 — требуется медицинский сертификат DOT), Excepted Interstate, Non-excepted Intrastate и Excepted Intrastate. Только Non-excepted Interstate требует иметь при себе/предоставлять медицинскую карту DOT; остальные три предоставляют только аффидевит. Источник: ALEA CDL Self-Certification Affidavit."},"95":{"q":"Согласно Alabama CDL Manual, если водитель осуществляет перевозки КАК в межштатной, ТАК и во внутриштатной торговле, какой статус самосертификации он должен выбрать?","options":["Внутриштатная торговля (Intrastate commerce)","Освобождённая внутриштатная торговля (Excepted intrastate commerce)","Межштатная торговля (Interstate commerce)","Ту, что он выполняет чаще всего"],"explanation":"Руководство указывает, что если вы осуществляете перевозки как во внутриштатной, так и в межштатной торговле, при самосертификации вы должны выбрать межштатную торговлю (interstate commerce). Источник: Alabama CDL Manual (ALEA), Section 1.2.1."},"96":{"q":"По состоянию на изменение, вступившее в силу June 23, 2025, как обычно передаётся в ALEA сертификат медицинского эксперта DOT держателя CDL в Алабаме?","options":["Водитель должен отправить оригинал бумажной карты по почте в окружной probate office","Сертифицированный медицинский эксперт подаёт его электронно в FMCSA, которая передаёт его в штат регистрации водителя","Водитель загружает отсканированную бумажную карту на портал разрешений ALDOT","Инспекторы ALDOT собирают карту на весовых станциях и пересылают её в ALEA"],"explanation":"С June 23, 2025 ALEA принимает медицинские сертификации DOT только в электронном виде: сертифицированный FMCSA медицинский эксперт подаёт результат электронно в FMCSA, которая пересылает его в штат регистрации водителя. Бумажные карты и самостоятельная загрузка больше не принимаются; водители проверяют свою запись на alabamadl.alea.gov. Источник: ALEA news release 'Big Changes for Alabama CDL Holders'; ALEA CDL FAQ."},"97":{"q":"Если держатель CDL в Алабаме категории Non-excepted Interstate не поддерживает актуальный 'certified' медицинский статус в записях, каковы последствия?","options":["Он становится 'not-certified' и может потерять своё CDL","Его CDL автоматически понижается до CLP на 90 дней","Он получает одноразовое письменное предупреждение без влияния на лицензию","Ничего, потому что медицинская карта необязательна для держателей CDL"],"explanation":"Alabama CDL Manual предупреждает, что водитель, обязанный иметь 'certified' медицинский статус, который не предоставляет и не поддерживает его в актуальном состоянии, становится 'not-certified' и может потерять своё CDL (CDL может быть понижено/аннулировано). Источник: Alabama CDL Manual (ALEA), Section 1.2 Medical Documentation Requirements."},"98":{"q":"В Алабаме, когда самосертификация держателя CDL (и медицинская карта, если применимо) обычно должна быть в записях относительно продления коммерческой лицензии?","options":["Подана не позднее чем за 10 дней до продления коммерческого водительского удостоверения","Подана только после того, как продлённая лицензия отправлена по почте","Подана в течение 30 дней после истечения срока действия лицензии","Подана только один раз и больше никогда не обновляется"],"explanation":"Аффидевит ALEA CDL Self-Certification предписывает водителям подавать аффидевит (и медицинскую карту, если применимо) не позднее чем за 10 дней до продления коммерческого водительского удостоверения; невозврат формы может привести к аннулированию CDL. Источник: ALEA CDL Self-Certification Affidavit."},"99":{"q":"Каков стандартный цикл продления/действия CDL в Алабаме, и когда истекает его срок?","options":["Оно продлевается каждые 2 года и истекает в конце года","Оно продлевается каждые 10 лет и истекает January 1","Оно продлевается по 8-летнему циклу и истекает в день рождения водителя","Оно никогда не истекает после первой выдачи CDL"],"explanation":"Алабама выдаёт/продлевает водительские удостоверения, включая CDL, по 8-летнему циклу с истечением срока в день рождения водителя; CDL может быть продлено уже за 180 дней до истечения срока, и льготного периода нет. (Валидация TSA для endorsement Hazmat действует только 5 лет.) Источник: ALEA Driver License Division; Alabama CDL renewal guidance."}},"tr":{"0":{"q":"Alabama'da şerit genişliği 12 fit veya daha fazla olan otoyollarda, bir aracın yükü dahil (aynalar ve güvenlik cihazları hariç) izin verilen azami toplam dış genişliği nedir?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Alabama Code 32-9-20(1), şerit genişliği 12 fit veya daha fazla olan otoyollarda, aynalar ve güvenlik cihazları hariç olmak üzere yük dahil azami genişliği 102 inches (8 fit 6 inç) olarak belirler. Kaynak: Alabama Code Section 32-9-20."},"1":{"q":"Alabama otoyollarında bir araç, yarı römork veya römork için yük dahil yasal azami yükseklik nedir?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Alabama Code 32-9-20(2), herhangi bir araç, yarı römork veya römorkun yük dahil yüksekliğinin 13 1/2 fit (13 feet 6 inches) değerini aşmasını yasaklar. Kaynak: Alabama Code Section 32-9-20."},"2":{"q":"Alabama'da, herhangi bir tek (single) dingilin tekerlekleri tarafından otoyola uygulanan azami brüt ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"Alabama Code 32-9-20(4), herhangi bir tek dingili 20,000 pounds ile sınırlar; bu, 23 U.S.C. 127 kapsamındaki federal standartla tutarlıdır. Kaynak: Alabama Code Section 32-9-20."},"3":{"q":"Alabama'da Eyaletlerarası Otoyol Sistemi'nde (Interstate Highway System) bir tandem dingil grubu için izin verilen azami ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","38,000 pounds"],"explanation":"Alabama Code 32-9-20(4), Interstate Highway System'de tandem dingil ağırlığını, tüm uygulama toleransları dahil olmak üzere 34,000 pounds ile sınırlar; bu federal sınırla eşleşir. Kaynak: Alabama Code Section 32-9-20."},"4":{"q":"Alabama'da Eyaletlerarası Otoyol Sistemi'nde (Interstate Highway System) bir araç veya araç kombinasyonu için tüm uygulama toleransları dahil azami toplam brüt ağırlık nedir?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Alabama Code 32-9-20(4), Interstate System'de toplam brüt ağırlığı, tüm uygulama toleransları dahil olmak üzere 80,000 pounds ile sınırlar; bu 23 U.S.C. 127 ile tutarlıdır. Kaynak: Alabama Code Section 32-9-20."},"5":{"q":"Alabama otoyollarında tek (düz) bir aracın azami uzunluğu nedir?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Alabama Code 32-9-20(3), hiçbir tek aracın uzunluğunun 40 feet değerini aşamayacağını belirtir. Kaynak: Alabama Code Section 32-9-20."},"6":{"q":"Alabama'da bir çekici-yarı römork kombinasyonunda, yük dahil yarı römorkun azami uzunluğu nedir?","options":["48 feet","53 feet","57 feet","65 feet"],"explanation":"Alabama Code 32-9-20(3), çekici-yarı römork kombinasyonunda kullanılan yarı römorkun, yük dahil 57 feet değerini aşamayacağını öngörür. Kaynak: Alabama Code Section 32-9-20."},"7":{"q":"Alabama'da şerit genişliği 12 fitten AZ olan otoyollarda, bir aracın yük dahil azami toplam dış genişliği nedir?","options":["90 inches","96 inches","102 inches","108 inches"],"explanation":"Alabama Code 32-9-20(1), şeritleri 12 fitten az genişlikte olan otoyollarda azami genişliği yük dahil 96 inches değerine düşürür. Kaynak: Alabama Code Section 32-9-20."},"8":{"q":"Alabama'da bir çekici-yarı römork-römork (ikiz römork) kombinasyonunda, her bir yarı römork veya römorkun yük dahil azami uzunluğu nedir?","options":["27 feet","28 1/2 feet","30 feet","33 feet"],"explanation":"Alabama Code 32-9-20(3), bir çekici-yarı römork-römork (ikiz) kombinasyonundaki her bir yarı römork veya römorku yük dahil 28 1/2 feet ile sınırlar. Kaynak: Alabama Code Section 32-9-20."},"9":{"q":"Alabama otoyollarında genellikle karavan (motor home) olarak adlandırılan bir motorlu aracın azami uzunluğu nedir?","options":["40 feet","45 feet","53 feet","57 feet"],"explanation":"Alabama Code 32-9-20(3), genellikle karavan (motor home) olarak adlandırılan motorlu araçların uzunluğunun 45 feet değerini aşamayacağını öngörür. Kaynak: Alabama Code Section 32-9-20."},"10":{"q":"Alabama'da bir otoyolda orman ürünleri veya menfez borusu taşırken, izin (permit) olmaksızın izin verilen azami yasal yük genişliği nedir?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"Alabama Code 32-9-20(1), herhangi bir otoyolda orman ürünleri veya menfez borusu taşıyan hiçbir aracın yükünün 102 inches genişliği aşamayacağını özellikle belirtir. Kaynak: Alabama Code Section 32-9-20."},"11":{"q":"Alabama'da iki ardışık tandem dingil seti, ilk ve son dingiller arasındaki mesafenin en az kaç fit olması koşuluyla her biri 34,000 pounds brüt yük taşıyabilir?","options":["30 feet","34 feet","36 feet","41 feet"],"explanation":"Alabama Code 32-9-20(4), ilk ve son dingiller arasındaki toplam mesafe 36 feet veya daha fazla ise ve toplam brüt ağırlık 80,000 pounds değerini aşmıyorsa, iki ardışık tandem dingil setinin her birinin 34,000 pounds taşımasına izin verir. Kaynak: Alabama Code Section 32-9-20."},"12":{"q":"Alabama, iki veya daha fazla ardışık dingilden oluşan bir grup üzerindeki izin verilen azami brüt ağırlığı belirlemek için hangi formülü uygular?","options":["Federal köprü formülü W = 500(LN/(N-1) + 12N + 36)","Beygir gücü-ağırlık oranı formülü","Dingil aralığından bağımsız sabit 80,000 librelik kural","Durma mesafesi orantı formülü"],"explanation":"Alabama Code 32-9-20(4)(c), federal köprü formülü W = 500(LN/(N-1) + 12N + 36) formülünü benimser; burada W brüt ağırlık, L grubun en uç dingilleri arasındaki mesafe ve N dingil sayısıdır. Kaynak: Alabama Code Section 32-9-20."},"13":{"q":"Dingil ve brüt ağırlık sınırlarının uygulanması için Alabama, öngörülen ağırlığın hangi faktörle çarpılmasıyla hesaplanan bir kantar (uygulama) toleransına izin verir?","options":["0.05 (yüzde 5)","0.10 (yüzde 10)","0.15 (yüzde 15)","0.20 (yüzde 20)"],"explanation":"Alabama Code 32-9-20(4)(d), bir ihlal sayılmadan önce öngörülen ağırlığın onda biri (.10), yani yüzde 10 ile çarpılmasına eşit bir kantar/uygulama toleransına izin verir. Kaynak: Alabama Code Section 32-9-20."},"14":{"q":"Alabama yasasına göre, yalnızca bir çiftliğe ve çiftlikten tarımsal ürün taşımak için kullanılan iki ve üç dingilli araçlar hangi gereksinime UYMAK zorunda değildir?","options":["Genişlik ve yükseklik sınırları","Tek dingil ve brüt ağırlık gereksinimleri","Aydınlatma ve işaretleme gereksinimleri","Kombinasyonlar için uzunluk sınırları"],"explanation":"Alabama Code 32-9-20(4)(j), yalnızca bir çiftliğe ve çiftlikten tarımsal ürün taşımak için kullanılan iki ve üç dingilli araçları, (4)a paragrafının tek dingil gereksinimlerinden ve (4)c paragrafının brüt ağırlık gereksinimlerinden muaf tutar. Kaynak: Alabama Code Section 32-9-20."},"15":{"q":"Alabama'da çalışan bir yardımcı güç ünitesi (APU) veya rölanti azaltma teknolojisi kullanan bir araca, brüt, dingil, tandem veya köprü formülü sınırlarının üzerinde ne kadar ek ağırlığa izin verilir?","options":["250 pounds","400 pounds","550 pounds","1,000 pounds"],"explanation":"Alabama Code 32-9-20(b)(1), yardımcı güç veya rölanti azaltma teknolojisi kullanan araçlar için 2005 federal Enerji Politikası Yasası'nı (Energy Policy Act of 2005) yansıtarak, 400 pounds değerine kadar (veya hangisi daha az ise gerçek sertifikalı APU ağırlığı kadar) ek ağırlığa izin verir. Kaynak: Alabama Code Section 32-9-20."},"16":{"q":"Bir Alabama yıllık gabari dışı/aşırı yük izni (permit), toplam brüt ağırlığı hangi değeri aşan bir aracın çalışmasına izin VEREMEZ?","options":["100,000 pounds","120,000 pounds","150,000 pounds","200,000 pounds"],"explanation":"Alabama Code 32-9-29(b)(1), yıllık bir iznin toplam brüt ağırlığı 150,000 pounds değerini aşan bir araca izin veremeyeceğini ve 100,000 pounds üzerindeki brüt ağırlıkların departman tarafından önceden güzergah belirlenmesini gerektirdiğini öngörür. Kaynak: Alabama Code Section 32-9-29."},"17":{"q":"Bir Alabama yıllık izni (permit) kapsamında, izinli bir aracın tek dingil ağırlığı hangi miktarı aşamaz?","options":["20,000 pounds","22,000 pounds","25,000 pounds","27,000 pounds"],"explanation":"Alabama Code 32-9-29(b)(1), bir yıllık gabari dışı/aşırı yük izni kapsamındaki tek dingil ağırlığını, tüm uygulama toleransları dahil olmak üzere 22,000 pounds ile sınırlar. Kaynak: Alabama Code Section 32-9-29."},"18":{"q":"Bir Alabama yıllık gabari dışı/aşırı yük izni (permit), yüksekliği hangi sınırı aşan bir araca izin veremez?","options":["13 feet 6 inches","14 feet","15 feet 6 inches","16 feet"],"explanation":"Alabama Code 32-9-29(b)(1), bir yıllık iznin yüksekliği 14 feet değerini aşan bir aracın çalışmasına izin veremeyeceğini öngörür. Kaynak: Alabama Code Section 32-9-29."},"19":{"q":"Alabama yasasına göre, çiftlik ve tarımsal ürünler ile ekipmanların, eyalet otoyol sisteminde hareket için gabari dışı/aşırı yük izinleri (permit) açısından durumu nedir?","options":["Özel bir yıllık çiftlik izni gerektirirler","İzin alma gereksiniminden muaftırlar","Yalnızca tek seferlik bir izin gerektirirler","İzin almak zorundadırlar ancak ücret ödemezler"],"explanation":"Alabama Code 32-9-29(f), çiftlik ve tarımsal ürünler ile ekipmanların, Alabama eyalet otoyol sisteminde hareket için izin alma gereksiniminden muaf olduğunu belirtir. Kaynak: Alabama Code Section 32-9-29."},"20":{"q":"Alabama'da, çekilen ünitenin GVWR'si 10,000 pounds değerini aştığında, en az hangi brüt kombinasyon ağırlık değerine (GCWR) sahip herhangi bir araç kombinasyonunu kullanmak için Class A CDL gereklidir?","options":["16,001 pounds veya daha fazla","26,001 pounds veya daha fazla","10,001 pounds veya daha fazla","36,001 pounds veya daha fazla"],"explanation":"Alabama, Class A CDL'yi, çekilen aracın/araçların GVWR'si 4,536 kg (10,000 lb) değerini aşmak koşuluyla, GCWR'si 11,794 kilogram veya daha fazla (26,001 pounds veya daha fazla) olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: ALEA Driver License Division, CDL sınıfları/onayları sayfası ve Alabama CDL Manual."},"21":{"q":"Alabama kurallarına göre, GVWR'si 26,001 pounds veya daha fazla olan tek bir aracı ya da GVWR'si 10,000 pounds değerini aşmayan bir üniteyi çeken böyle bir aracı hangi CDL sınıfı kapsar?","options":["Class A","Class C","Class B","Class D"],"explanation":"Alabama, Class B'yi, GVWR'si 11,794 kg veya daha fazla (26,001 lb veya daha fazla) olan herhangi bir tek araç ya da GVWR'si 4,536 kg (10,000 lb) değerini aşmayan bir aracı çeken böyle bir araç olarak tanımlar. Kaynak: ALEA CDL sınıfları/onayları sayfası ve Alabama CDL Manual."},"22":{"q":"Class A veya Class B ağırlık eşiklerini karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren tehlikeli madde taşıyan bir araç, hangi Alabama CDL sınıfını gerektirir?","options":["Class C","Class B","Class A","Class M"],"explanation":"Alabama Class C, Class A veya B tanımını karşılamayan ancak sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da 49 CFR part 172 subpart F kapsamında plakart gerektiren tehlikeli madde taşımak için kullanılan herhangi bir araçtır (veya kombinasyondur). Kaynak: ALEA CDL sınıfları/onayları sayfası."},"23":{"q":"Alabama'da yolcu veya okul otobüsü onayı ile uygun CDL'nin gerekli olması için bir aracın kaç yolcu (sürücü dahil) taşımak üzere tasarlanmış olması gerekir?","options":["12 veya daha fazla","24 veya daha fazla","16 veya daha fazla","20 veya daha fazla"],"explanation":"Alabama (federal standardı izleyerek), Class C tanımı ve yolcu/okul otobüsü onayı amaçları için eşiği sürücü dahil 16 veya daha fazla yolcu olarak belirler. Kaynak: ALEA CDL sınıfları/onayları sayfası; Alabama CDL Manual."},"24":{"q":"Bir Alabama CDL'sinde, sürücüye bir tank aracı kullanma yetkisi veren onay kodu hangisidir?","options":["T","N","H","X"],"explanation":"Alabama federal onay kodlarını kullanır: N, Tank Aracı (Tanker) onayıdır. Kaynak: ALEA CDL sınıfları/onayları sayfası; Alabama CDL Manual."},"25":{"q":"Bir Alabama CDL'sindeki 'T' onayı neye yetki verir?","options":["Tehlikeli madde taşımaya","Bir tank aracı kullanmaya","Çift ve üçlü römork çalıştırmaya","Bir çekici (tow truck) kullanmaya"],"explanation":"Alabama'da T onayı, çift/üçlü römork çalıştırmaya yetki verir ve yalnızca bir bilgi testi geçilerek alınır (beceri testi yoktur). Kaynak: ALEA CDL sınıfları/onayları sayfası; Alabama CDL Manual."},"26":{"q":"Bir Alabama CDL'sinde, Tank Aracı VE Tehlikeli Madde kombinasyonunu temsil eden tek onay kodu hangisidir?","options":["H","N","X","P"],"explanation":"Alabama, birleşik Tank Aracı/Tehlikeli Madde onayı için X kodunu kullanır; tek başına H HazMat ve tek başına N Tanker'dir. Kaynak: ALEA CDL sınıfları/onayları sayfası."},"27":{"q":"Alabama'nın bir CDL üzerinde HazMat (H) onayı verebilmesi için, başvuru sahibinin federal Ulaştırma Güvenliği İdaresi'nden (TSA) ne alması gerekir?","options":["Bir Medical Examiner's Certificate (Tıbbi Muayene Belgesi)","Bir Determination of No Security Threat (Güvenlik Tehdidi Yok Kararı)","Posta yoluyla bir FMCSA eğitim sertifikası","Bilgi testinden muafiyet"],"explanation":"Parmak izi alma ve bir güvenlik tehdidi değerlendirmesinin ardından TSA bir Determination of No Security Threat (Güvenlik Tehdidi Yok Kararı) vermedikçe hiçbir eyalet bir HazMat onayı veremez veya yenileyemez. Alabama bu TSA arka plan kontrolünü ve HazMat bilgi testini gerektirir. Kaynak: TSA/49 CFR 1572; ALEA HazMat onay gereksinimleri."},"28":{"q":"EYALET İÇİ (yalnızca Alabama içinde) ticari sürücülük için bir Alabama CDL almanın asgari yaşı nedir?","options":["21","19","18","16"],"explanation":"Alabama, eyalet içi çalışma için 18 yaşında bir CDL'ye izin verir; eyaletlerarası çalışma 21 yaşını gerektirir. Kaynak: ALEA CDL SSS; Alabama CDL Manual."},"29":{"q":"Bir Alabama CDL'si ile eyalet sınırlarının ötesinde (eyaletlerarası) ticari motorlu araç kullanmak için gereken asgari yaş nedir?","options":["18","21","19","25"],"explanation":"Eyaletlerarası ticari sürücülük (ve eyalet sınırlarının ötesinde tehlikeli madde veya plakart gerektiren yük taşıma), federal kurallarla tutarlı olarak Alabama'da asgari 21 yaş gerektirir. Kaynak: ALEA CDL SSS; 49 CFR 391.11."},"30":{"q":"Bir Ticari Öğrenci Belgesi (CLP) verildikten sonra, bir Alabama başvuru sahibinin CDL beceri (yol) testine girmesine izin verilmeden önce CLP'yi ne kadar süre elinde tutması gerekir?","options":["30 gün","14 gün","10 gün","60 gün"],"explanation":"Alabama tarafından benimsenen federal yasa, CDL beceri testine girilmeden önce CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: ALEA CDL SSS; 49 CFR 383.25."},"31":{"q":"Bir Alabama Ticari Öğrenci Belgesi (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["180 gün ve bir kez yenilenebilir","360 gün ve yenilenemez","1 yıl ve yıllık olarak yenilenebilir","90 gün ve yenilenemez"],"explanation":"Bir Alabama CLP'si 360 gün geçerlidir ve yenilenemez; süresi dolarsa, başvuru sahibi tüm yazılı testleri yeniden almalı ve yeni bir CLP için ödeme yapmalıdır. Kaynak: ALEA CDL SSS."},"32":{"q":"Bir Alabama başvuru sahibinin bir Ticari Öğrenci Belgesi veya CDL için başvurmadan önce halihazırda hangi tür temel sürücü belgesine sahip olması gerekir?","options":["Geçerli bir Alabama Class D sürücü belgesi","Geçerli bir Alabama Class M motosiklet belgesi","Yalnızca bir öğrenci belgesi (learner's permit)","Önceden herhangi bir belge gerekmez"],"explanation":"Alabama, başvuru sahiplerinin bir CLP veya CDL için başvurmadan önce geçerli bir Alabama Class D (normal) sürücü belgesine sahip olmasını gerektirir. Kaynak: ALEA CDL SSS; Belge Gereksinimleri sayfası."},"33":{"q":"Alabama'da ticari sürücü belgelerini hangi kurum verir?","options":["Alabama Ulaştırma Departmanı (ALDOT)","İlçe veraset dairesi (county probate office)","Alabama Kolluk Kuvveti (ALEA) Driver License Division","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)"],"explanation":"Alabama'da CDL'ler, ayrı bir DMV veya ALDOT tarafından değil, Alabama Kolluk Kuvveti (ALEA) tarafından Driver License Division aracılığıyla verilir. Kaynak: ALEA Driver License Division."},"34":{"q":"İlk kez bir Alabama CDL'sinden önce gereken Başlangıç Seviyesi Sürücü Eğitimi (ELDT), nerede listelenen bir sağlayıcı tarafından verilmelidir?","options":["Yalnızca ALEA onaylı okul listesi","FMCSA Eğitim Sağlayıcı Sicili (Training Provider Registry, TPR)","Herhangi bir özel kamyon taşımacılığı şirketi","Alabama Topluluk Koleji Sistemi sicili"],"explanation":"7 Şubat 2022'den (Feb 7, 2022) bu yana, ilk kez CDL başvuru sahipleri (ve belirli yükseltmeler/onaylar) ELDT'yi FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan tamamlamalıdır; bu sağlayıcı, Alabama testlere izin vermeden önce tamamlanmayı yüklemelidir. Kaynak: ALEA CDL SSS; 49 CFR part 380."},"35":{"q":"Alabama'da hangi CDL işlemi, tek başına, test öncesinde Başlangıç Seviyesi Sürücü Eğitimi (ELDT) GEREKTİRMEZ?","options":["İlk kez bir CDL almak","Class B'den Class A'ya yükseltmek","Bir CDL'yi aynı sınıf ve onaylarla yenilemek","İlk HazMat (H) onayını almak"],"explanation":"ELDT; ilk kez CDL'ler, sınıf yükseltmeleri ve ilk kez S, P veya H onayları için geçerlidir. Sınıfı yükseltmeyen veya kapsama dahil bir onay eklemeyen basit bir yenileme ELDT'yi tetiklemez. Kaynak: 49 CFR part 380; ALEA CDL SSS."},"36":{"q":"Eyaletlerarası ticarette araç kullanan ve federal tıbbi standartları karşılaması gereken bir Alabama CDL başvuru sahibi hangi kategori altında kendi beyanında bulunur?","options":["Excepted Interstate (İstisnalı Eyaletlerarası)","Non-Excepted Interstate (İstisnasız Eyaletlerarası)","Excepted Intrastate (İstisnalı Eyalet İçi)","Non-Excepted Intrastate (İstisnasız Eyalet İçi)"],"explanation":"Non-Excepted Interstate kategorisi, geçerli bir DOT Medical Examiner's Certificate'i (Tıbbi Muayene Belgesi) bulundurmak zorunda olan, eyaletlerarası ticarette araç kullanan sürücüler için geçerlidir. Alabama, 49 CFR 383 uyarınca dört kategoriden birine kendi beyanı yapılmasını gerektirir. Kaynak: ALEA kendi beyanı gereksinimleri; 49 CFR 383.71."},"37":{"q":"Bir Alabama CDL sahibinin kaç tıbbi kendi beyanı kategorisi arasından seçim yapması gerekir ve hangisi güncel bir DOT tıbbi kartının bulundurulmasını gerektirir?","options":["İki kategori; yalnızca eyaletlerarası olan bir tıbbi kart gerektirir","Dört kategori; Non-Excepted Interstate kategorisi güncel bir DOT tıbbi kartı gerektirir","Üç kategori; hiçbiri tıbbi kart gerektirmez","Dört kategori; Excepted Intrastate kategorisi güncel bir DOT tıbbi kartı gerektirir"],"explanation":"Alabama dört federal kategoriyi kullanır (Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, Excepted Intrastate). Non-Excepted Interstate beyanında bulunan sürücüler, FMCSA sertifikalı bir muayene görevlisinden alınan bir DOT Medical Examiner's Certificate'i sağlamalı ve bulundurmalıdır. Kaynak: ALEA kendi beyanı; 49 CFR 383.71."},"38":{"q":"Bir Alabama CDL veya CLP için başvururken, başvuru sahibi hangi belge setini sunmalıdır?","options":["Yalnızca bir Sosyal Güvenlik kartı","Kimlik kanıtı, Sosyal Güvenlik numarası kanıtı, Alabama ikametgah kanıtı ve (ABD vatandaşı değilse) yasal varlık kanıtı","Yalnızca bir pasaport ve iki fatura","Kimlik kanıtı ve bir lise diploması"],"explanation":"ALEA; birincil kimlik kanıtı, belgelenmiş SSN kanıtı, Alabama ikametgah kanıtı ve vatandaş olmayanlar için yasal varlık kanıtı gerektirir; aynı belge iki gereksinim için sayılamaz. Kaynak: ALEA Belge Gereksinimleri ve Ücretler sayfası."},"39":{"q":"16 veya daha fazla yolcu taşıyan bir okul otobüsü aynı zamanda bir yolcu aracı olduğundan, Alabama Okul Otobüsü (S) onayına ek olarak ne gerektirir?","options":["Ayrı bir Class A CDL","Yolcu (P) onayı","Tanker (N) onayı","Çift/Üçlü Römork (T) onayı"],"explanation":"Alabama, Okul Otobüsü (S) onayı ile birlikte Yolcu (P) onayını gerektirir; başvuru sahipleri Genel Bilgi, Yolcu ve Okul Otobüsü bilgi testlerini ve temsili bir otobüste bir beceri testini geçer. Kaynak: ALEA CDL sınıfları/onayları; Alabama CDL Manual."},"40":{"q":"Alabama'da, bir ticari motorlu aracın kullanılmasını yasadışı kılan en düşük kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"Alabama federal CMV standardını izler: BAC'niz 0.04% veya daha fazla ise bir CMV kullanmak yasadışıdır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"41":{"q":"Alabama'nın zımni rıza (implied consent) kuralı uyarınca, Alabama yollarında ticari motorlu araç kullanan bir kişi hakkında ne varsayılır?","options":["Alkol testine rıza göstermiş sayılırlar","Ayrı bir rıza kartı taşımalıdırlar","Duruşma hakkından feragat ederler","Yalnızca görünür şekilde ehliyetsizlerse rıza gösterirler"],"explanation":"Alabama CDL Manual, bir CMV kullanıyorsanız alkol testine rıza göstermiş sayılacağınızı belirtir. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; Ala. Code Title 32."},"42":{"q":"Alabama'da, bir CDL sahibi İLK ciddi suç için (CMV DUI veya alkol testini reddetme gibi, plakart gerektiren tehlikeli madde taşımıyorken) CDL'sini ne kadar süre kaybeder?","options":["60 gün","120 gün","En az 1 yıl","En az 3 yıl"],"explanation":"İlk ciddi suç (DUI, bir CMV'de 0.04+ BAC, testi reddetme, olay yerini terk etme vb.) CDL'nin en az bir yıl kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"43":{"q":"Alabama'da, bir sürücü tehlikeli maddeler için plakartlı bir CMV kullanırken ilk ciddi suçu işler. Ehliyet iptali (disqualification) ne kadardır?","options":["En az 1 yıl","En az 2 yıl","En az 3 yıl","Ömür boyu"],"explanation":"Tehlikeli maddeler için plakartlı bir CMV kullanılırken ilk ciddi suç işlenirse, ehliyet iptali bir yıl yerine en az üç yıldır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"44":{"q":"Alabama'da, İKİNCİ bir ciddi suç (ikinci bir CMV DUI gibi) için ehliyet iptali (disqualification) nedir?","options":["1 yıl","3 yıl","10 yıl","Ömür boyu"],"explanation":"İkinci bir ciddi suç, CDL'nin ömür boyu kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"45":{"q":"Alabama'da, bir CMV kullanırken alkol testine girmeyi reddetmek ne tür bir ihlal olarak değerlendirilir?","options":["Ciddi bir trafik ihlali (60 günlük kural)","Bir ağır suç (en az 1 yıllık kayıp)","Yalnızca para cezası olan küçük bir kabahat","Bir hizmet dışı bırakma emri (out-of-service order) ihlali"],"explanation":"Kandaki alkol testine girmeyi reddetmek, Alabama'da ağır suç olarak listelenir ve ilk suç için en az bir yıllık ehliyet iptali taşır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"46":{"q":"Aşağıdakilerden hangisi Alabama CDL Manual'da CİDDİ bir trafik ihlali olarak listelenmiştir?","options":["Limitin 5 mph üzerinde araç kullanmak","Aşırı hız yapmak (belirtilen limitin 15 mph veya daha fazla üzerinde)","Süresi dolmuş bir tescil etiketi","Yanmış bir arka stop lambası"],"explanation":"Ciddi trafik ihlalleri; belirtilen limitin 15 mph veya daha fazla üzerinde olarak tanımlanan aşırı hız yapmanın yanı sıra dikkatsiz araç kullanma, uygunsuz şerit değiştirme ve çok yakın takip etmeyi içerir. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.3."},"47":{"q":"Alabama'da, bir CDL sahibi üç yıllık bir süre içinde bir CMV'de İKİ ciddi trafik ihlalinden mahkum olur. Ehliyet iptali (disqualification) nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"Üç yıllık bir süre içinde bir CMV'de iki ciddi trafik ihlali, CDL'nin en az 60 gün kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51."},"48":{"q":"Alabama'da, bir CDL sahibi üç yıllık bir süre içinde bir CMV'de ÜÇ ciddi trafik ihlalinden mahkum olur. Ehliyet iptali (disqualification) nedir?","options":["En az 60 gün","En az 90 gün","En az 120 gün","En az 1 yıl"],"explanation":"Üç yıllık bir süre içinde bir CMV'de üç veya daha fazla ciddi trafik ihlali, CDL'nin en az 120 gün kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51."},"49":{"q":"Alabama'da, bir hizmet dışı bırakma emrinin (out-of-service order) İLK ihlali için ehliyet iptali (disqualification) nedir?","options":["En az 30 gün","En az 90 gün","En az 180 gün","En az 1 yıl"],"explanation":"Bir hizmet dışı bırakma emrinin ilk ihlali, CDL'nin en az 90 gün kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51."},"50":{"q":"Alabama'da, bir sürücü on yıllık bir süre içinde İKİ hizmet dışı bırakma emri (out-of-service order) ihlali işler. Ehliyet iptali (disqualification) nedir?","options":["En az 120 gün","En az 1 yıl","En az 3 yıl","En az 5 yıl"],"explanation":"On yıllık bir süre içinde iki hizmet dışı bırakma emri ihlali, CDL'nin en az bir yıl kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51."},"51":{"q":"Alabama'da, bir sürücü on yıllık bir süre içinde ÜÇ veya daha fazla hizmet dışı bırakma emri (out-of-service order) ihlali işler. Ehliyet iptali (disqualification) nedir?","options":["En az 1 yıl","En az 2 yıl","En az 3 yıl","Ömür boyu"],"explanation":"On yıllık bir süre içinde üç veya daha fazla hizmet dışı bırakma emri ihlali, CDL'nin en az üç yıl kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51."},"52":{"q":"Alabama'da, bir CMV'de İLK demiryolu-karayolu hemzemin geçit ihlali için ehliyet iptali (disqualification) nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, CDL'nin en az 60 gün kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51."},"53":{"q":"Alabama'da, bir CDL sahibi üç yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali alır. Ehliyet iptali (disqualification) nedir?","options":["En az 60 gün","En az 120 gün","En az 6 ay","En az 1 yıl"],"explanation":"Üç yıllık bir süre içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, CDL'nin en az 120 gün kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51."},"54":{"q":"Alabama'da, bir CDL sahibi üç yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali alır. Ehliyet iptali (disqualification) nedir?","options":["En az 120 gün","En az 180 gün","En az 1 yıl","En az 3 yıl"],"explanation":"Üç yıllık bir süre içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali, CDL'nin en az bir yıl kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51."},"55":{"q":"Alabama'da, bir CMV sürücüsünde hala 0.04% altında olan tespit edilebilir herhangi bir miktarda alkol bulunursa ne olur?","options":["Hiçbir şey, yasal limitin altındadır","24 saat hizmet dışı (out-of-service)","Anında 1 yıllık ehliyet iptali","Ömür boyu yasak"],"explanation":"0.04% altında tespit edilebilir herhangi bir miktarda alkolü olan bir CMV sürücüsü 24 saatliğine hizmet dışı bırakılır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2."},"56":{"q":"Alabama'da, bir CMV kullanırken elde tutulan bir cep telefonu kullanmaktan kaç mahkumiyetten sonra bir sürücünün CDL'si iptal edilir?","options":["Bir mahkumiyet","İki veya daha fazla mahkumiyet","Dört veya daha fazla mahkumiyet","Altı veya daha fazla mahkumiyet"],"explanation":"Bir CMV kullanırken elde tutulan cep telefonu kullanımına ilişkin bir eyalet yasasından iki veya daha fazla mahkumiyetten sonra bir CDL iptal edilir: 3 yıl içinde ikinci suç için 60 gün ve 3 yıl içinde üç veya daha fazla için 120 gün. Kaynak: Alabama CDL Manual (ALEA), Section 2.9.4."},"57":{"q":"Alabama CDL Manual'daki kurallar uyarınca, bir CMV kullanırken mesaj yazmak (texting) yasaktır. Sürücü mahkumiyetleri hangi tutara kadar bir idari para cezası taşıyabilir?","options":["$500'a kadar","$1,000'a kadar","$2,750'a kadar","$11,000'a kadar"],"explanation":"Bir CMV sürücüsü tarafından yapılan her mesaj yazma veya elde tutulan telefon ihlali, $2,750'a kadar bir idari para cezasına tabidir (işverenler $11,000'a kadar para cezasına çarptırılabilir). Kaynak: Alabama CDL Manual (ALEA), Sections 2.9.4 ve 2.9.5; 49 CFR 392."},"58":{"q":"Alabama'da, kontrollü maddeler içeren bir suçu işlemek için bir CMV kullanmak hangi cezayla sonuçlanır?","options":["60 günlük ehliyet iptali","1 yıllık ehliyet iptali","3 yıllık ehliyet iptali","CDL'nin ömür boyu kaybı"],"explanation":"Kontrollü maddeler içeren bir suçu işlemek için bir CMV kullanmak, yeniden verilme olmaksızın CDL'nin ömür boyu kaybedilmesiyle sonuçlanır. Kaynak: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51."},"59":{"q":"Aşağıdakilerden hangisi Alabama CDL Manual kapsamında bir ağır suç yerine CİDDİ bir trafik ihlalidir?","options":["0.04% BAC ile bir CMV kullanmak","Kimyasal bir alkol testini reddetmek","Bir aracı çok yakından takip etmek","Bir kaza yerini terk etmek"],"explanation":"Bir aracı çok yakından takip etmek, ciddi bir trafik ihlali olarak listelenir (60/120 günlük kurala doğru sayılır), buna karşılık DUI, test reddi ve olay yerini terk etmek en az bir yıllık ehliyet iptali taşıyan ağır suçlardır. Kaynak: Alabama CDL Manual (ALEA), Sections 1.3.2 ve 1.3.3."},"60":{"q":"Alabama'da plakartlı (tehlikeli madde işaretli) bir araç, demir yolu-karayolu hemzemin geçidinde durmak zorunda kaldığında, sürücü en yakın raydan ne kadar mesafede durmalıdır?","options":["10 fitten az ve 25 fitten fazla olmayacak şekilde","15 fitten az ve 50 fitten fazla olmayacak şekilde","25 fitten az ve 75 fitten fazla olmayacak şekilde","5 fitten az ve 15 fitten fazla olmayacak şekilde"],"explanation":"Alabama, plakartlı HazMat aracının en yakın raydan 15 ila 50 fit önce durmasını ve ancak hiçbir tren gelmediğinde ve durmadan rayları geçebileceğinde ilerlemesini gerektirir. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 9.6 Demir Yolu Geçitleri; Ala. Code 32-5A-150."},"61":{"q":"Alabama'nın Move Over Yasası (Şerit Değiştirme Yasası) kapsamında, çok şeritli bir karayolunda bir sürücü, yanıp sönen ışıklar gösteren duran bir acil durum veya kanun uygulama aracının en yakınındaki şeridi güvenli bir şekilde boşaltamadığında ne yapmalıdır?","options":["Belirlenen hız sınırının en az 10 mph altında bir hıza yavaşlamalı","Belirlenen hız sınırının en az 20 mph altında bir hıza yavaşlamalı","Acil durum aracı ayrılana kadar tamamen durmalı","Belirlenen hız sınırının en az 15 mph altında bir hıza yavaşlamalı"],"explanation":"Alabama'nın Move Over Yasası kapsamında, güvenli bir şekilde şerit değiştiremeyen bir sürücü, belirlenen hız sınırından en az 15 mph daha düşük bir hıza yavaşlamalıdır. Kaynak: Ala. Code 32-5A-58.2 (Acil Durum Araçlarına Yaklaşırken Şerit Değiştirme veya Hız Azaltma)."},"62":{"q":"Alabama'da bir eyaletler arası otoyolda (interstate) azami hız sınırı nedir (aksi belirtilmedikçe veya yetkilendirilmedikçe)?","options":["65 mph","75 mph","80 mph","70 mph"],"explanation":"Alabama yasaları, eyaletler arası otoyollarda azami hızı 70 mph olarak belirler; dört veya daha fazla şeritli diğer karayollarında ise azami hız 65 mph'dir. Kaynak: Ala. Code 32-5A-171 (Azami Sınırlar)."},"63":{"q":"Alabama'da, bir ticari araç tek yönlü veya bölünmüş bir karayolunda durmak zorunda kalırsa, üç adet acil durum uyarı cihazı nereye yerleştirilmelidir?","options":["Yaklaşan trafiğe doğru 10 fit, 50 fit ve 150 fit","Yaklaşan trafiğe doğru 25 fit, 100 fit ve 250 fit","Yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit","Yaklaşan trafiğe doğru 5 fit, 75 fit ve 100 fit"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda Alabama, uyarı cihazlarının yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit mesafeye yerleştirilmesini öngörür. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 2.8 Duran Araçlar için Uyarı Cihazları."},"64":{"q":"Alabama'nın okul otobüsü yasası kapsamında, görsel sinyalleri çalışır durumda olan duran bir okul otobüsüyle karşılaşan veya onu geçen bir aracın sürücüsü ne zaman tamamen durmak zorundadır?","options":["Yalnızca otobüse arkadan yaklaşırken, asla önden değil","Yalnızca otobüs sürücüyle yolun aynı tarafında olduğunda","Yalnızca çocuklar yolda gözle görülür şekilde mevcutsa","Sıradan iki şeritli veya bölünmemiş bir yolda her iki yönden yaklaşırken"],"explanation":"Alabama, görsel sinyali çalışır durumdayken çocukları indirmek veya bindirmek için durmuş bir okul otobüsüyle HER İKİ yönden karşılaşan veya onu geçen bir sürücünün durmasını gerektirir; ancak yasada tanımlandığı şekliyle bölünmüş bir karayolu bunun istisnasıdır. Kaynak: Ala. Code 32-5A-154."},"65":{"q":"Hangi durum, çocukları indiren veya bindiren duran bir okul otobüsü için durma kuralının Alabama'daki TEK istisnasını tanımlar?","options":["Belirlenen hız sınırı 30 mph veya daha az olan herhangi bir şehirde araç kullanmak","Sürücünün otobüsten 100 fitten daha uzakta olduğu herhangi bir durum","Zıt yönlere giden en az iki şeride ayrılmış bölünmüş bir karayolunun karşı yolundan otobüsle karşılaşmak","Bölünmüş olsun veya olmasın, herhangi bir dört şeritli yol"],"explanation":"Alabama, bir sürücüyü yalnızca dört veya daha fazla şeritli ve trafiğin en az iki şeritte zıt yönlerde akmasına izin veren BÖLÜNMÜŞ bir karayolunun karşı yolunda durmuş bir okul otobüsüyle karşılaştığında durma yükümlülüğünden muaf tutar. Bölünmemiş çok şeritli bir yolda tüm sürücüler yine de durmak zorundadır. Kaynak: Ala. Code 32-5A-154."},"66":{"q":"Alabama'da yolcu taşıyan bir otobüs, demir yolu-karayolu geçidinde en yakın raydan ne kadar mesafede durmalıdır?","options":["10 ila 40 fit arasında","20 ila 60 fit arasında","5 ila 25 fit arasında","15 ila 50 fit arasında"],"explanation":"Alabama, yolcu taşıyan bir otobüsün en yakın raydan 15 ila 50 fit önce durmasını, her iki yönü dinleyip bakmasını ve ancak rayların üzerinde durmadan geçilebileceği zaman geçmesini gerektirir. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 4.3.5 Demir Yolu-Karayolu Geçidi Duruşları."},"67":{"q":"Her iki yönde de trafiğin aktığı iki şeritli bir Alabama yolunda, bir CMV (ticari motorlu araç) durduğunda uyarı cihazları nereye yerleştirilir?","options":["Aracın 10 fit içinde, ayrıca öne 200 fit ve arkaya 200 fit","Aracın 25 fit içinde, ayrıca öne ve arkaya 150 fit","Üçü de yalnızca aracın 100 fit arkasına yerleştirilir","Aracın 10 fit içinde, ayrıca öne 100 fit ve arkaya 100 fit"],"explanation":"Her iki yönde trafiğin aktığı iki şeritli bir yolda Alabama, bir cihazın aracın 10 fit içine, bir cihazın 100 fit arkasına ve bir cihazın 100 fit önüne, banket üzerine veya şeride yerleştirilmesini öngörür. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 2.8 Uyarı Cihazları."},"68":{"q":"Alabama'nın Move Over Yasası'nın ihlali için para cezası nedir?","options":["$100","$500","$200","$50"],"explanation":"Alabama'nın Move Over yasasının ihlali, iki yüz dolar ($200) para cezası ile cezalandırılabilen bir kabahattir. Kaynak: Ala. Code 32-5A-58.2."},"69":{"q":"Kanun uygulama ve acil durum araçlarının yanı sıra, uyarı/yanıp sönen ışıklar gösteren aşağıdaki duran araçlardan hangisi de Alabama'nın Move Over gerekliliklerini tetikler?","options":["Bir çöp, atık, süprüntü veya geri dönüşüm toplama aracı","Dörtlü flaşörleri açık herhangi bir özel binek otomobil","Çocukları alan bir okul otobüsü","Bir şehir sokağında çift sıra park etmiş bir dağıtım minibüsü"],"explanation":"Alabama, Move Over Yasası'nı çekicileri, altyapı/hizmet araçlarını, bakım/inşaat/ölçüm araçlarını VE yanıp sönen ışıklar gösteren çöp, atık, süprüntü veya geri dönüşüm toplama araçlarını kapsayacak şekilde genişletmiştir. Kaynak: Ala. Code 32-5A-58.2."},"70":{"q":"Alabama'da dört veya daha fazla trafik şeridi olan bir karayolunda (eyaletler arası otoyol dışında) azami hız sınırı nedir?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"Alabama, dört veya daha fazla şeritli eyaletler arası olmayan karayollarında hızı 65 mph ile sınırlar; eyaletler arası otoyollar ise 70 mph ile sınırlıdır. Kaynak: Ala. Code 32-5A-171."},"71":{"q":"Alabama'nın şerit kullanım kuralı kapsamında, normal trafik hızından daha yavaş ilerleyen bir ticari araç nerede sürülmelidir?","options":["Her zaman orta şeritte","Sağ şeritte veya yol kenarının sağ kenarına mümkün olduğunca yakın","Herhangi bir şeritte, çünkü kamyonlar şerit kurallarından muaftır","Sağ şeritleri birleşmeler için boş tutmak amacıyla sol şeritte"],"explanation":"Alabama, normal trafik hızından daha yavaş giden herhangi bir aracın, geçiş, sollama veya sola dönüş hazırlığı durumları hariç, sağda kalmasını (sağ şerit veya sağ kenara mümkün olduğunca yakın) gerektirir. Kaynak: Ala. Code 32-5A-80 (Yolun Sağ Tarafında Araç Kullanma)."},"72":{"q":"Alabama'da duran bir CMV, yaklaşan sürücülerin görüşünü engelleyen bir tepe veya viraj üzerinde ise, sürücü en arkadaki uyarı cihazıyla ne yapmalıdır?","options":["Trafiğin en az 500 fit uzaktan uyarılması için onu daha geriye taşımalı","Engele bakılmaksızın onu tam olarak 200 fit geride bırakmalı","Onu kaldırıp yalnızca aracın dörtlü flaşörlerine güvenmeli","Üç cihazı da doğrudan arka tamponun arkasına yerleştirmeli"],"explanation":"Bir tepe, viraj veya başka bir engel, sürücülerin aracı 500 fit içinde görmesini engellediğinde Alabama, en arkadaki üçgenin yol boyunca daha geriye taşınmasını öngörür; böylece uyarı engelin ötesinde sağlanır. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 2.8 Uyarı Cihazları."},"73":{"q":"Alabama'da duran bir okul otobüsünü yasa dışı şekilde geçmenin İLK mahkumiyeti için para cezası aralığı nedir?","options":["$150'den az ve $300'den fazla olmamak üzere","$50'den az ve $100'den fazla olmamak üzere","$500'den az ve $1,000'den fazla olmamak üzere","Aralık olmaksızın sabit $250"],"explanation":"Alabama'da duran bir okul otobüsünü yasa dışı şekilde geçmenin ilk mahkumiyeti, $150'den az ve $300'den fazla olmayan bir para cezası taşır; tekrarlanan suçlar için daha ağır para cezaları, kamu hizmeti ve ehliyet askıya alma uygulanır. Kaynak: Ala. Code 32-5A-154."},"74":{"q":"Alabama'da her demir yolu-karayolu hemzemin geçidinde tam olarak durmak zorunda olan araçlar hangileridir?","options":["İstisnasız 10,000 pound üzerindeki tüm ticari araçlar","Yolcu taşıyan otobüsler ve tehlikeli maddeler için plakartlı araçlar","Yalnızca boş tanker kamyonları","Yalnızca herhangi bir türde römork çeken araçlar"],"explanation":"Alabama, yolcu taşıyan otobüslerin ve plakartlı HazMat araçlarının (dolu veya boş HazMat kargo tankları ile herhangi bir miktarda klor taşıyan araçlar dahil) hemzemin geçitlerde durmasını gerektirir; sıradan CMV'lerin koşullar gerektirmedikçe durması gerekmez. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 2.15 ve 9.6."},"75":{"q":"Alabama'da ALDOT'tan bir aşırı boyut izni gerekmeden önceki azami yasal yük GENİŞLİĞİ nedir?","options":["8 fit 0 inç","10 fit 0 inç","8 fit 6 inç","9 fit 6 inç"],"explanation":"Alabama'nın standart azami yasal yük genişliği 8 fit 6 inçtir (102 inç); bundan daha geniş herhangi bir şey, Alabama Ulaştırma Bakanlığı'ndan (ALDOT) bir aşırı boyut izni gerektirir. Kaynak: ALDOT Aşırı Boyut/Aşırı Ağırlık İzin düzenlemeleri."},"76":{"q":"Alabama'da bir aşırı boyut izni gerekmeden önceki azami yasal yük YÜKSEKLİĞİ nedir?","options":["13 fit 0 inç","13 fit 6 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"Alabama, azami yasal araç/yük yüksekliğini 13 fit 6 inç olarak belirler; bunu aşan yükler bir ALDOT aşırı boyut izni gerektirir ve 15 fit 6 inçten yüksek yükler önde bir yükseklik direği eskortu gerektirir. Kaynak: ALDOT Aşırı Boyut/Aşırı Ağırlık İzin düzenlemeleri."},"77":{"q":"Alabama'nın dağlık arazisindeki uzun ve dik bir iniş eğiminde, kaçak araç kurtarma rampasının asıl amacı nedir?","options":["Frenleri arızalanmış bir aracı, gevşek ve yumuşak malzemeden oluşan bir yatak kullanarak durdurmak","Kamyonların frenlerini gönüllü olarak soğutmaları için asfaltlanmış bir dinlenme alanı sağlamak","Eğimi inen tüm CMV'ler için zorunlu bir muayene şeridi olarak hizmet etmek","Daha hızlı araçların tırmanışta yavaş kamyonları geçmesine izin vermek"],"explanation":"Kaçış rampaları, dik iniş eğimlerinde kaçak araçları, uzun ve gevşek, yumuşak malzemeden oluşan bir yatak kullanarak güvenli bir şekilde durdurmak için inşa edilir; sürücüler güzergahlarındaki rampa konumlarını bilmelidir. Alabama'nın Lookout/Sand Mountain yakınındaki I-59 eğimleri bu tür rampalara sahiptir. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 2.16 Dağ Sürüşü / Kaçış Rampaları."},"78":{"q":"Bir yol veya banket üzerinde duran bir Alabama CMV sürücüsü, gerekli acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["10 dakika","5 dakika","15 dakika","30 dakika"],"explanation":"Alabama'da bir CMV bir yol veya banket üzerinde durmak zorunda kalırsa, sürücü acil durum uyarı cihazlarını on dakika içinde yerleştirmelidir. Kaynak: Alabama (ALEA) CDL Kılavuzu, Bölüm 2.8 Duran Araçlar için Uyarı Cihazları."},"79":{"q":"Şerit değiştirmenin imkansız olduğu ve belirlenen sınırın 45 mph olduğu İKİ ŞERİTLİ bir Alabama yolunda duran bir acil durum aracına yaklaşırken bir sürücü ne yapmalıdır?","options":["Belirlenen sınırı korumalı ancak dörtlü flaşörleri açmalı","Seyir şeridinde tamamen durmalı","Şerit içinde mümkün olduğunca uzağa çekilmeli ve belirlenen sınırın 15 mph altına (30 mph) yavaşlamalı","Belirlenen sınıra bakılmaksızın tam olarak 20 mph'ye yavaşlamalı"],"explanation":"İki şeritli bir Alabama yolunda, bir sürücü acil durum aracından şerit içinde mümkün olduğunca uzağa çekilmeli ve belirlenen sınır 25 mph veya daha fazla olduğunda (burada 45 - 15 = 30 mph) belirlenen sınırın 15 mph altına yavaşlamalıdır. Kaynak: Ala. Code 32-5A-58.2."},"80":{"q":"Alabama'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir ve CDL sınavlarını yönetir?","options":["Alabama Ulaştırma Bakanlığı (ALDOT)","Alabama Kanun Uygulama Kurumu (ALEA), Sürücü Belgesi Dairesi","Alabama Gelir İdaresi, Motorlu Taşıtlar Dairesi","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)"],"explanation":"Alabama'da CDL'ler, Alabama Kanun Uygulama Kurumu (ALEA), Sürücü Belgesi Dairesi tarafından verilir ve sınanır. Alabama CDL Kılavuzu ALEA tarafından yayımlanır ve bilgi/beceri sınavları ALEA Ticari Sürücü Belgesi ofislerinde yapılır. Kaynak: Alabama CDL Kılavuzu (ALEA), Giriş; ALEA Sürücü Belgesi Dairesi."},"81":{"q":"Bir başvuru sahibi Alabama'da bir CDL bilgi veya beceri sınavını nasıl planlar?","options":["Randevu almadan herhangi bir ilçe plaka/ruhsat ofisine giderek","Bir test merkezi atayan FMCSA'ya çevrimiçi başvurarak","ALDOT'a yazılı bir talep göndererek ve planlanan bir tarih bekleyerek","alea.gov'daki çevrimiçi planlama sistemi aracılığıyla bir ALEA Ticari Sürücü Belgesi ofisinde randevu alarak"],"explanation":"Alabama CDL Kılavuzu, başvuru sahiplerini bilgi veya beceri sınavı için bir ALEA Ticari Sürücü Belgesi ofisinde randevu almaya yönlendirir; alea.gov üzerinde 'Driver License' / 'Online Services' altında başvuru sahipleri 'Schedule DL Appointment' seçeneğini kullanır. Kaynak: Alabama CDL Kılavuzu (ALEA), Ticari Sürücü Belgesi Ofisleri sayfası."},"82":{"q":"Alabama'da, bir başvuru sahibinin CDL beceri sınavına ilk kez girmesine izin verilmeden önce neyi edinmesi ve elinde bulundurması gerekir?","options":["Bir Tehlikeli Maddeler onayı","Bir federal DOT tıbbi muafiyeti","Bir Uluslararası Tescil Planı (IRP) hesabı","Bir Ticari Öğrenici Belgesi (CLP)"],"explanation":"İlk kez başvuran veya yükseltme yapan bir CDL başvuru sahibine, önce gerekli bilgi sınav(lar)ını geçerek bir Ticari Öğrenici Belgesi (CLP) verilmelidir. Beceri sınavına girilmeden önce CLP'nin elde bulundurulması gerekir. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1; ALEA CDL SSS."},"83":{"q":"Alabama (ve federal) kurallar kapsamında, belge sahibinin CDL beceri sınavına girebilmesi için bir CLP ne kadar süre elinde bulundurulmalıdır?","options":["En az 7 gün","En az 30 gün","En az 14 gün","En az 60 gün"],"explanation":"Alabama, belge sahibinin CDL beceri sınavına girebilmesi için bir CLP'nin en az 14 gün elde bulundurulması gerektiğine ilişkin federal şartı izler. Kaynak: ALEA CDL SSS; Alabama'da uygulandığı şekliyle 49 CFR 383.25."},"84":{"q":"Bir Alabama Ticari Öğrenici Belgesi (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["180 gün geçerlidir ve bir kez yenilenebilir","1 yıl geçerlidir ve iki kez yenilenebilir","30 gün geçerlidir ve yenilenemez","360 gün geçerlidir ve yenilenemez"],"explanation":"ALEA, CLP'nin 360 gün geçerli olduğunu ve yenilenemeyeceğini belirtir; süresi dolarsa, başvuru sahibi yeni bir CLP için yeniden sınava girmelidir. Kaynak: ALEA CDL SSS."},"85":{"q":"Alabama'da ilk kez bir CDL sınavına girmeden önce, bir başvuru sahibinin hangi eğitimi tamamlaması gerekir?","options":["Alabama mahkemeleri tarafından onaylanmış bir savunmacı sürüş kursu","40 saatlik bir OSHA işyeri güvenliği kursu","FMCSA'ya kayıtlı bir sağlayıcı aracılığıyla Giriş Seviyesi Sürücü Eğitimi (ELDT)","Yalnızca Montgomery ofisinde yapılan ALEA tarafından yönetilen bir sınıf kursu"],"explanation":"Giriş Seviyesi Sürücü Eğitimi (ELDT), ilk kez CDL alan herkes için (ve belirli yükseltmeler/onaylar için) gereklidir. Eğitim, sınava girilmeden önce FMCSA Eğitim Sağlayıcı Sicilinde listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır. Kaynak: ALEA CDL Öz-Sertifikasyon/SSS materyalleri; 7 Şubat 2022'de yürürlüğe giren FMCSA ELDT kuralı."},"86":{"q":"Araç sınıfı veya onaylarından bağımsız olarak HER Alabama CDL başvuru sahibinin geçmesi gereken bilgi sınavı hangisidir?","options":["Hava fren sınavı","Kombinasyon araçları sınavı","Tehlikeli maddeler sınavı","Genel bilgi sınavı"],"explanation":"Alabama CDL Kılavuzu, genel bilgi sınavını tüm başvuru sahiplerinin girdiği sınav olarak listeler; diğer bilgi sınavları (hava frenleri, kombinasyon, yolcu, tehlikeli madde, tank, ikili/üçlü, okul otobüsü) istenen sınıfa ve onaylara bağlıdır. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.1.1 Bilgi Sınavları."},"87":{"q":"Alabama CDL Kılavuzu'na göre, CDL beceri sınavı hangi üç bölümden oluşur?","options":["Yazılı sınav, göz muayenesi ve yol sınavı","Bağlama/çözme, geri gitme ve hava freni kontrolü","Sefer öncesi, savunmacı sürüş ve gece sürüşü","Araç muayenesi, temel araç kontrolü ve yolda sürüş"],"explanation":"Kılavuz, CDL beceri sınavının üç bölümden oluştuğunu belirtir: araç muayenesi, temel araç kontrolü ve yolda sürüş. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.1.2 Beceri Sınavları."},"88":{"q":"Alabama'da üç CDL beceri sınavı bölümü hangi sırayla yapılmalıdır?","options":["Başvuru sahibinin sınav günü seçtiği herhangi bir sırayla","Önce yolda sürüş, sonra temel kontrol, sonra araç muayenesi","Listelenen sırayla (önce araç muayenesi, sonra temel araç kontrolü, sonra yolda sürüş), bir sonrakine geçmeden önce her birini geçerek","Önce temel araç kontrolü, sonra yolda sürüş, sonra araç muayenesi"],"explanation":"Alabama CDL Kılavuzu şöyle der: 'Bölümleri listelenen sırayla almalı ve bir sonrakine geçmeden önce her birini geçmelisiniz' — araç muayenesi, temel araç kontrolü, sonra yolda sürüş. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.1.2."},"89":{"q":"Bir başvuru sahibi Alabama CDL beceri sınavına girmek için ne tür bir araç kullanmalıdır?","options":["Başvuru sahibinin ehliyet almak istediği sınıfı/türü temsil eden bir araç","Yalnızca sürüş alışkanlıkları değerlendirildiği için herhangi bir binek otomobil","ALEA test merkezi tarafından ücretsiz olarak sağlanan bir araç","Hava frenleri olduğu sürece, sınıfından bağımsız olarak herhangi bir ticari araç"],"explanation":"Kılavuz, beceri sınavının başvuru sahibinin ehliyet almak istediği türde bir araçla yapılmasını gerektirir; kullanılan aracın sınıfı, verilen CDL'yi kısıtlayabilir. Bileşenleri işaretli veya etiketli bir araç kullanılamaz. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.1.2."},"90":{"q":"Alabama CDL araç muayenesi beceri sınavı sırasında, başvuru sahibinin her bir kalemde yapması gereken nedir?","options":["Sınav görevlisi süreyi tutarken her kalemi sessizce muayene etmek","Kalemi işaret etmek veya dokunup adlandırmak ve sınav görevlisine neyi neden muayene ettiğini açıklamak","Bir muayene formuna her kalemin açıklamasını yazmak","Kalemlere dokunmadan veya işaret etmeden yalnızca sözlü olarak listelemek"],"explanation":"Kılavuz, Araç Muayenesi sınavı sırasında muayene ettiğiniz kalemi işaret etmeniz/dokunmanız ve adlandırmanız ve sınav görevlisine neyi neden muayene ettiğinizi açıklamanız gerektiğini belirtir. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.1.2, Araç Muayenesi."},"91":{"q":"Alabama CDL beceri sınavının temel araç kontrolü bölümü neyi değerlendirir?","options":["Tehlikeli madde plakart kurallarının bilgisini","Aracı ileri, geri hareket ettirme ve belirlenmiş bir alan içinde döndürme becerisini","Karayolu işaretlerini okuma ve yorumlama yeteneğini","Günlük bir sürücü kaydını tamamlama yeteneğini"],"explanation":"Temel araç kontrolü sınavı, başvuru sahibinin aracı kontrol etme becerisini ölçer — onu belirlenmiş, işaretlenmiş bir alan içinde ileri, geri hareket ettirmek ve döndürmek; sınav görevlisi her egzersizin nasıl yapılacağını açıklar. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.1.2, Temel Araç Kontrolü."},"92":{"q":"Bir Alabama CDL başvuru sahibi, başvururken Sosyal Güvenlik numarasının kanıtı olarak genellikle hangi belgeyi sunmalıdır?","options":["Başvuru sahibinin Sosyal Güvenlik numarasının kanıtı (ör. Sosyal Güvenlik kartı)","Yalnızca mevcut bir işverenden noter onaylı bir beyanname","Yalnızca başvuru sahibinin en son federal vergi beyannamesinin bir kopyası","Bir motorlu taşıyıcı DOT numarası atama mektubu"],"explanation":"Alabama CDL başvuru sahipleri, gerekli kimlik/ikamet kanıtı ve geçerli bir Alabama (Sınıf D) sürücü belgesi ile birlikte Sosyal Güvenlik numaralarının kanıtını sunmalıdır. Kaynak: ALEA Sürücü Belgesi Dairesi belge gereklilikleri; ALEA CDL başvuru materyalleri."},"93":{"q":"Alabama'da benimsenen federal düzenlemeler, Sınıf A, B veya C araçların CDL sahiplerinin kaç ticari operasyon kategorisi arasından seçim yaparak öz-sertifikasyon yapmasını gerektirir?","options":["Dört","İki","Üç","Beş"],"explanation":"Alabama'nın CDL Öz-Sertifikasyon Beyannamesi, sürücünün dört operasyon kategorisinden birini onaylamasını gerektirir. Kaynak: ALEA CDL Öz-Sertifikasyon Beyannamesi (49 CFR 383, 384, 390, 391'e atıfta bulunur); Alabama CDL Kılavuzu Bölüm 1.2."},"94":{"q":"Alabama CDL Öz-Sertifikasyon Beyannamesi'nde, dört kategoriden hangisi sürücünün bir DOT tıbbi muayene görevlisi sertifikası taşımasını ve sunmasını GEREKTİRİR?","options":["İstisnalı Eyaletler Arası (Excepted Interstate)","İstisnasız Eyaletler Arası (Non-excepted Interstate)","İstisnalı Eyalet İçi (Excepted Intrastate)","İstisnasız Eyalet İçi (Non-excepted Intrastate) (Alabama tıbbi muafiyet K kısıtlaması ile)"],"explanation":"Alabama beyannamesi dört kategori listeler: İstisnasız Eyaletler Arası (49 CFR bölüm 391'e tabi — DOT tıbbi sertifikası gerekir), İstisnalı Eyaletler Arası, İstisnasız Eyalet İçi ve İstisnalı Eyalet İçi. Yalnızca İstisnasız Eyaletler Arası bir DOT tıbbi kartı taşımayı/sunmayı gerektirir; diğer üçü yalnızca beyannameyi sunar. Kaynak: ALEA CDL Öz-Sertifikasyon Beyannamesi."},"95":{"q":"Alabama CDL Kılavuzu'na göre, bir sürücü HEM eyaletler arası HEM de eyalet içi ticarette faaliyet gösteriyorsa, hangi öz-sertifikasyon statüsünü seçmelidir?","options":["Eyalet içi ticaret (Intrastate commerce)","İstisnalı eyalet içi ticaret (Excepted intrastate commerce)","Eyaletler arası ticaret (Interstate commerce)","En sık hangisini yapıyorlarsa o"],"explanation":"Kılavuz, hem eyalet içi hem de eyaletler arası ticarette faaliyet gösteriyorsanız, öz-sertifikasyon yaparken eyaletler arası ticareti seçmeniz gerektiğini belirtir. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.2.1."},"96":{"q":"23 Haziran 2025'te yürürlüğe giren değişiklikle birlikte, bir Alabama CDL sahibinin DOT tıbbi muayene görevlisi sertifikası normalde ALEA'ya nasıl iletilir?","options":["Sürücü orijinal kağıt kartı ilçe vesayet ofisine postalamalıdır","Sertifikalı tıbbi muayene görevlisi onu elektronik olarak FMCSA'ya gönderir, FMCSA da sürücünün kayıtlı olduğu eyalete iletir","Sürücü, taranmış bir kağıt kartı ALDOT izin portalına yükler","ALDOT denetçileri kartı tartı istasyonlarında toplar ve ALEA'ya iletir"],"explanation":"23 Haziran 2025'ten itibaren ALEA, DOT tıbbi sertifikasyonlarını yalnızca elektronik olarak kabul eder: FMCSA sertifikalı tıbbi muayene görevlisi sonucu elektronik olarak FMCSA'ya gönderir, FMCSA da onu sürücünün kayıtlı olduğu eyalete iletir. Kağıt kartlar ve kişisel yüklemeler artık kabul edilmez; sürücüler kayıtlarını alabamadl.alea.gov adresinde doğrular. Kaynak: ALEA basın bülteni 'Big Changes for Alabama CDL Holders'; ALEA CDL SSS."},"97":{"q":"İstisnasız Eyaletler Arası bir Alabama CDL sahibi, dosyasında güncel bir 'sertifikalı' tıbbi statü tutmazsa, sonucu ne olur?","options":["'Sertifikasız' duruma geçerler ve CDL'lerini kaybedebilirler","CDL'leri 90 gün boyunca otomatik olarak bir CLP'ye düşürülür","Ehliyet üzerinde hiçbir etkisi olmaksızın tek seferlik yazılı bir uyarı alırlar","Hiçbir şey, çünkü tıbbi kart CDL sahipleri için isteğe bağlıdır"],"explanation":"Alabama CDL Kılavuzu, 'sertifikalı' tıbbi statüye sahip olması gereken bir sürücünün bunu sağlamaması ve güncel tutmaması durumunda 'sertifikasız' duruma geçeceği ve CDL'sini kaybedebileceği (CDL düşürülebilir/iptal edilebilir) konusunda uyarır. Kaynak: Alabama CDL Kılavuzu (ALEA), Bölüm 1.2 Tıbbi Belgelendirme Gereklilikleri."},"98":{"q":"Alabama'da, bir CDL sahibinin öz-sertifikasyonunun (ve varsa tıbbi kartının) ticari ehliyetin yenilenmesine göre genellikle ne zaman dosyada bulunması gerekir?","options":["Ticari sürücü belgesini yenilemeden en geç 10 gün önce sunulmalı","Yalnızca yenilenen ehliyet postalandıktan sonra sunulmalı","Ehliyetin süresi dolduktan sonraki 30 gün içinde sunulmalı","Yalnızca bir kez sunulmalı ve bir daha asla güncellenmemeli"],"explanation":"ALEA CDL Öz-Sertifikasyon Beyannamesi, sürücülere beyannameyi (ve varsa tıbbi kartı) ticari sürücü belgesini yenilemeden en geç 10 gün önce sunmalarını talimat verir; formu iade etmemek CDL'nin iptaliyle sonuçlanabilir. Kaynak: ALEA CDL Öz-Sertifikasyon Beyannamesi."},"99":{"q":"Bir Alabama CDL'sinin standart yenileme/geçerlilik döngüsü nedir ve ne zaman sona erer?","options":["Her 2 yılda bir yenilenir ve yıl sonunda sona erer","Her 10 yılda bir yenilenir ve 1 Ocak'ta sona erer","8 yıllık bir döngüde yenilenir ve sürücünün doğum gününde sona erer","Bir CDL ilk verildikten sonra asla sona ermez"],"explanation":"Alabama, CDL'ler dahil sürücü belgelerini 8 yıllık bir döngüde verir/yeniler ve bunlar sürücünün doğum gününde sona erer; bir CDL, süresinin dolmasından en erken 180 gün önce yenilenebilir ve hiçbir ek süre (grace period) yoktur. (Bir HazMat onayının TSA doğrulaması yalnızca 5 yıl sürer.) Kaynak: ALEA Sürücü Belgesi Dairesi; Alabama CDL yenileme rehberi."}},"es":{"0":{"q":"En las carreteras de Alabama con carriles de circulación de 12 pies o más de ancho, ¿cuál es el ancho total exterior máximo de un vehículo, incluida su carga (sin contar los espejos ni los dispositivos de seguridad)?","options":["96 pulgadas","100 pulgadas","102 pulgadas","108 pulgadas"],"explanation":"El Alabama Code 32-9-20(1) establece el ancho máximo en 102 pulgadas (8 pies 6 pulgadas), incluida la carga, en carreteras con carriles de 12 pies o más de ancho, sin contar los espejos ni los dispositivos de seguridad. Fuente: Alabama Code Section 32-9-20."},"1":{"q":"¿Cuál es la altura máxima legal, incluida la carga, para un vehículo, semirremolque o remolque en las carreteras de Alabama?","options":["13 pies","13 pies 6 pulgadas","14 pies","14 pies 6 pulgadas"],"explanation":"El Alabama Code 32-9-20(2) prohíbe que cualquier vehículo, semirremolque o remolque supere los 13 1/2 pies (13 pies 6 pulgadas) de altura, incluida la carga. Fuente: Alabama Code Section 32-9-20."},"2":{"q":"En Alabama, ¿cuál es el peso bruto máximo que las ruedas de un solo eje (eje único) pueden imponer sobre la carretera?","options":["18,000 libras","20,000 libras","22,000 libras","24,000 libras"],"explanation":"El Alabama Code 32-9-20(4) limita cualquier eje único a 20,000 libras, en concordancia con el estándar federal según 23 U.S.C. 127. Fuente: Alabama Code Section 32-9-20."},"3":{"q":"¿Cuál es el peso máximo permitido en un grupo de ejes en tándem en el Sistema de Carreteras Interestatales (Interstate Highway System) en Alabama?","options":["32,000 libras","34,000 libras","36,000 libras","38,000 libras"],"explanation":"El Alabama Code 32-9-20(4) limita el peso de un eje en tándem en el Sistema de Carreteras Interestatales a 34,000 libras, incluidas todas las tolerancias de control, lo que coincide con el límite federal. Fuente: Alabama Code Section 32-9-20."},"4":{"q":"¿Cuál es el peso bruto total máximo para un vehículo o combinación de vehículos en el Sistema de Carreteras Interestatales en Alabama, incluidas todas las tolerancias de control?","options":["73,280 libras","80,000 libras","84,000 libras","88,000 libras"],"explanation":"El Alabama Code 32-9-20(4) limita el peso bruto total a 80,000 libras, incluidas todas las tolerancias de control, en el Sistema Interestatal, en concordancia con 23 U.S.C. 127. Fuente: Alabama Code Section 32-9-20."},"5":{"q":"¿Cuál es la longitud máxima de un vehículo único (rígido) en las carreteras de Alabama?","options":["35 pies","40 pies","45 pies","53 pies"],"explanation":"El Alabama Code 32-9-20(3) establece que ningún vehículo único debe superar los 40 pies de longitud. Fuente: Alabama Code Section 32-9-20."},"6":{"q":"En una combinación de tractocamión y semirremolque en Alabama, ¿cuál es la longitud máxima del semirremolque, incluida la carga?","options":["48 pies","53 pies","57 pies","65 pies"],"explanation":"El Alabama Code 32-9-20(3) dispone que el semirremolque, incluida la carga, utilizado en una combinación de tractocamión y semirremolque no debe superar los 57 pies. Fuente: Alabama Code Section 32-9-20."},"7":{"q":"En las carreteras con carriles de circulación de MENOS de 12 pies de ancho en Alabama, ¿cuál es el ancho total exterior máximo de un vehículo, incluida la carga?","options":["90 pulgadas","96 pulgadas","102 pulgadas","108 pulgadas"],"explanation":"El Alabama Code 32-9-20(1) reduce el ancho máximo a 96 pulgadas, incluida la carga, en carreteras cuyos carriles de circulación tienen menos de 12 pies de ancho. Fuente: Alabama Code Section 32-9-20."},"8":{"q":"En una combinación de tractocamión-semirremolque-remolque (remolque doble) en Alabama, ¿cuál es la longitud máxima de cada semirremolque o remolque, incluida la carga?","options":["27 pies","28 1/2 pies","30 pies","33 pies"],"explanation":"El Alabama Code 32-9-20(3) limita cada semirremolque o remolque en una combinación de tractocamión-semirremolque-remolque (doble) a 28 1/2 pies, incluida la carga. Fuente: Alabama Code Section 32-9-20."},"9":{"q":"¿Cuál es la longitud máxima de un vehículo automotor comúnmente llamado casa rodante (motor home) en las carreteras de Alabama?","options":["40 pies","45 pies","53 pies","57 pies"],"explanation":"El Alabama Code 32-9-20(3) dispone que los vehículos automotores comúnmente llamados casas rodantes (motor homes) no deben superar los 45 pies de longitud. Fuente: Alabama Code Section 32-9-20."},"10":{"q":"Al transportar productos forestales o tubería de alcantarilla en una carretera de Alabama, ¿cuál es el ancho máximo legal de la carga sin permiso?","options":["96 pulgadas","102 pulgadas","108 pulgadas","120 pulgadas"],"explanation":"El Alabama Code 32-9-20(1) establece específicamente que ningún vehículo que transporte productos forestales o tubería de alcantarilla en cualquier carretera debe tener una carga que supere las 102 pulgadas de ancho. Fuente: Alabama Code Section 32-9-20."},"11":{"q":"En Alabama, dos conjuntos consecutivos de ejes en tándem pueden cargar cada uno un peso bruto de 34,000 libras siempre que la distancia entre el primer y el último eje de los conjuntos consecutivos sea de al menos cuántos pies?","options":["30 pies","34 pies","36 pies","41 pies"],"explanation":"El Alabama Code 32-9-20(4) permite que dos conjuntos consecutivos de ejes en tándem carguen cada uno 34,000 libras si la distancia total entre el primer y el último eje es de 36 pies o más, sin que el peso bruto total supere las 80,000 libras. Fuente: Alabama Code Section 32-9-20."},"12":{"q":"¿Qué fórmula aplica Alabama para determinar el peso bruto máximo permitido en un grupo de dos o más ejes consecutivos?","options":["La fórmula federal del puente (bridge formula) W = 500(LN/(N-1) + 12N + 36)","La fórmula de la relación potencia-peso","Una regla fija de 80,000 libras sin importar el espaciamiento","La fórmula de proporcionalidad de la distancia de frenado"],"explanation":"El Alabama Code 32-9-20(4)(c) adopta la fórmula federal del puente (bridge formula) W = 500(LN/(N-1) + 12N + 36), donde W es el peso bruto, L es la distancia entre los ejes extremos del grupo y N es el número de ejes. Fuente: Alabama Code Section 32-9-20."},"13":{"q":"Para el control de los límites de peso por eje y de peso bruto, Alabama permite una tolerancia de báscula (de control) calculada multiplicando el peso prescrito por qué factor?","options":["0.05 (5 por ciento)","0.10 (10 por ciento)","0.15 (15 por ciento)","0.20 (20 por ciento)"],"explanation":"El Alabama Code 32-9-20(4)(d) permite una tolerancia de báscula/control igual al peso prescrito multiplicado por un décimo (.10), es decir, el 10 por ciento, antes de que se considere que ha ocurrido una infracción. Fuente: Alabama Code Section 32-9-20."},"14":{"q":"Según la ley de Alabama, los vehículos de dos y tres ejes utilizados exclusivamente para transportar productos agrícolas hacia y desde una finca NO están obligados a cumplir con cuál requisito?","options":["Los límites de ancho y altura","Los requisitos de eje único y de peso bruto","Los requisitos de iluminación y marcado","Los límites de longitud para combinaciones"],"explanation":"El Alabama Code 32-9-20(4)(j) exime a los vehículos de dos y tres ejes utilizados exclusivamente para transportar productos agrícolas hacia y desde una finca de los requisitos de eje único del párrafo (4)a y de los requisitos de peso bruto del párrafo (4)c. Fuente: Alabama Code Section 32-9-20."},"15":{"q":"Un vehículo que utiliza una unidad de energía auxiliar (APU) en funcionamiento o tecnología de reducción de ralentí en Alabama tiene permitido cuánto peso adicional por encima de los límites de peso bruto, por eje, en tándem o de la fórmula del puente?","options":["250 libras","400 libras","550 libras","1,000 libras"],"explanation":"El Alabama Code 32-9-20(b)(1) permite hasta 400 libras adicionales (o el peso certificado real de la APU, lo que sea menor) para los vehículos que utilizan energía auxiliar o tecnología de reducción de ralentí, reflejando la federal Energy Policy Act of 2005. Fuente: Alabama Code Section 32-9-20."},"16":{"q":"Un permiso anual de Alabama para vehículos de dimensiones o peso excesivos NO puede autorizar la operación de un vehículo cuyo peso bruto total supere qué cifra?","options":["100,000 libras","120,000 libras","150,000 libras","200,000 libras"],"explanation":"El Alabama Code 32-9-29(b)(1) dispone que un permiso anual no puede autorizar un vehículo cuyo peso bruto total supere las 150,000 libras, y los pesos brutos superiores a 100,000 libras requieren la planificación previa de la ruta por parte del departamento. Fuente: Alabama Code Section 32-9-29."},"17":{"q":"Bajo un permiso anual de Alabama, el peso por eje único de un vehículo autorizado no puede superar qué cantidad?","options":["20,000 libras","22,000 libras","25,000 libras","27,000 libras"],"explanation":"El Alabama Code 32-9-29(b)(1) limita el peso por eje único bajo un permiso anual de dimensiones o peso excesivos a 22,000 libras, incluidas todas las tolerancias de control. Fuente: Alabama Code Section 32-9-29."},"18":{"q":"Un permiso anual de Alabama para vehículos de dimensiones o peso excesivos no puede autorizar un vehículo cuya altura supere qué límite?","options":["13 pies 6 pulgadas","14 pies","15 pies 6 pulgadas","16 pies"],"explanation":"El Alabama Code 32-9-29(b)(1) dispone que un permiso anual no puede autorizar la operación de un vehículo cuya altura supere los 14 pies. Fuente: Alabama Code Section 32-9-29."},"19":{"q":"Según la ley de Alabama, ¿qué estatus tienen los productos y equipos agrícolas y de finca con respecto a los permisos por dimensiones o peso excesivos para circular por el sistema de carreteras estatales?","options":["Requieren un permiso anual especial de finca","Están exentos del requisito de obtener permisos","Requieren únicamente un permiso de un solo viaje","Deben obtener un permiso pero no pagan ninguna tarifa"],"explanation":"El Alabama Code 32-9-29(f) establece que los productos y equipos agrícolas y de finca están exentos del requisito de obtener permisos para circular por el sistema de carreteras estatales de Alabama. Fuente: Alabama Code Section 32-9-29."},"20":{"q":"En Alabama, se requiere una CDL Clase A para operar cualquier combinación de vehículos con una capacidad de peso bruto combinado (GCWR) de al menos qué valor, cuando el GVWR de la unidad remolcada supera las 10,000 libras?","options":["16,001 libras o más","26,001 libras o más","10,001 libras o más","36,001 libras o más"],"explanation":"Alabama define una CDL Clase A como cualquier combinación de vehículos con un GCWR de 11,794 kilogramos o más (26,001 libras o más), siempre que el GVWR del vehículo o los vehículos remolcados supere los 4,536 kg (10,000 lb). Fuente: ALEA Driver License Division, página de clases/endosos de CDL y el Manual de CDL de Alabama."},"21":{"q":"Según las normas de Alabama, ¿qué clase de CDL abarca un vehículo único con un GVWR de 26,001 libras o más, o dicho vehículo remolcando una unidad que no supere las 10,000 libras de GVWR?","options":["Clase A","Clase C","Clase B","Clase D"],"explanation":"Alabama define la Clase B como cualquier vehículo único con un GVWR de 11,794 kg o más (26,001 lb o más), o cualquiera de dichos vehículos remolcando un vehículo que no supere los 4,536 kg (10,000 lb) de GVWR. Fuente: página de clases/endosos de CDL de ALEA y el Manual de CDL de Alabama."},"22":{"q":"Un vehículo que no cumple con los umbrales de peso de la Clase A o la Clase B pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor), o que transporta materiales peligrosos que requieren rótulos (placards), ¿qué clase de CDL de Alabama requiere?","options":["Clase C","Clase B","Clase A","Clase M"],"explanation":"La Clase C de Alabama es cualquier vehículo (o combinación) que no cumple con la definición de la Clase A o B pero está diseñado para transportar 16 o más pasajeros incluido el conductor, o que se utiliza para transportar materiales peligrosos que requieren rótulos (placards) según 49 CFR part 172 subpart F. Fuente: página de clases/endosos de CDL de ALEA."},"23":{"q":"¿Para cuántos pasajeros (incluido el conductor) debe estar diseñado un vehículo antes de que se active el endoso de pasajeros o de autobús escolar y la CDL correspondiente en Alabama?","options":["12 o más","24 o más","16 o más","20 o más"],"explanation":"Alabama (siguiendo el estándar federal) fija el umbral en 16 o más pasajeros incluido el conductor para la definición de la Clase C y para los fines de los endosos de pasajeros/autobús escolar. Fuente: página de clases/endosos de CDL de ALEA; Manual de CDL de Alabama."},"24":{"q":"En una CDL de Alabama, ¿qué código de endoso autoriza al conductor a operar un vehículo cisterna (tanque)?","options":["T","N","H","X"],"explanation":"Alabama utiliza los códigos de endoso federales: N es el endoso de Vehículo Cisterna (Tanque). Fuente: página de clases/endosos de CDL de ALEA; Manual de CDL de Alabama."},"25":{"q":"¿Qué autoriza el endoso 'T' en una CDL de Alabama?","options":["Transportar materiales peligrosos","Conducir un vehículo cisterna (tanque)","Operar remolques dobles y triples","Operar una grúa de remolque"],"explanation":"En Alabama, el endoso T autoriza la operación de remolques dobles/triples y se obtiene aprobando únicamente un examen de conocimientos (sin examen de habilidades). Fuente: página de clases/endosos de CDL de ALEA; Manual de CDL de Alabama."},"26":{"q":"En una CDL de Alabama, ¿qué código de endoso único representa la combinación de Vehículo Cisterna Y Materiales Peligrosos?","options":["H","N","X","P"],"explanation":"Alabama utiliza el código X para el endoso combinado de Vehículo Cisterna/Materiales Peligrosos; H por sí solo es HazMat y N por sí solo es Cisterna (Tanque). Fuente: página de clases/endosos de CDL de ALEA."},"27":{"q":"Antes de que Alabama pueda emitir un endoso de HazMat (H) en una CDL, el solicitante debe recibir qué cosa de la Administración de Seguridad en el Transporte (TSA) federal?","options":["Un Certificado de Examinador Médico","Una Determinación de Ausencia de Amenaza a la Seguridad (Determination of No Security Threat)","Un certificado de capacitación de la FMCSA por correo","Una exención del examen de conocimientos"],"explanation":"Ningún estado puede emitir ni renovar un endoso de HazMat a menos que la TSA emita una Determinación de Ausencia de Amenaza a la Seguridad (Determination of No Security Threat) tras la toma de huellas dactilares y una evaluación de amenazas a la seguridad. Alabama exige esta verificación de antecedentes de la TSA además del examen de conocimientos de HazMat. Fuente: TSA/49 CFR 1572; requisitos del endoso de HazMat de ALEA."},"28":{"q":"¿Cuál es la edad mínima para obtener una CDL de Alabama para la conducción comercial INTRAESTATAL (solo dentro de Alabama)?","options":["21","19","18","16"],"explanation":"Alabama permite una CDL a los 18 años para la operación intraestatal; la operación interestatal requiere tener 21 años. Fuente: preguntas frecuentes (FAQ) de CDL de ALEA; Manual de CDL de Alabama."},"29":{"q":"¿Cuál es la edad mínima requerida para conducir un vehículo comercial cruzando líneas estatales (interestatal) con una CDL de Alabama?","options":["18","21","19","25"],"explanation":"La conducción comercial interestatal (y el transporte de materiales peligrosos o cargas que requieren rótulos a través de líneas estatales) requiere una edad mínima de 21 años en Alabama, en concordancia con las normas federales. Fuente: preguntas frecuentes (FAQ) de CDL de ALEA; 49 CFR 391.11."},"30":{"q":"Después de que se le emite un Permiso de Aprendiz Comercial (CLP), ¿durante cuánto tiempo debe un solicitante de Alabama tener el CLP antes de que se le permita tomar el examen de habilidades (de manejo) de la CDL?","options":["30 días","14 días","10 días","60 días"],"explanation":"La ley federal adoptada por Alabama exige que el CLP se tenga durante al menos 14 días antes de que se pueda tomar el examen de habilidades de la CDL. Fuente: preguntas frecuentes (FAQ) de CDL de ALEA; 49 CFR 383.25."},"31":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Alabama, y se puede renovar?","options":["180 días, y se puede renovar una vez","360 días, y no se puede renovar","1 año, y se puede renovar anualmente","90 días, y no se puede renovar"],"explanation":"Un CLP de Alabama es válido por 360 días y no es renovable; si vence, el solicitante debe volver a tomar todos los exámenes escritos y pagar por un nuevo CLP. Fuente: preguntas frecuentes (FAQ) de CDL de ALEA."},"32":{"q":"¿Qué tipo de licencia de conducir base debe tener ya un solicitante de Alabama antes de solicitar un Permiso de Aprendiz Comercial o una CDL?","options":["Una licencia de conducir Clase D de Alabama válida","Una licencia de motocicleta Clase M de Alabama válida","Solo un permiso de aprendiz","No se requiere ninguna licencia previa"],"explanation":"Alabama exige que los solicitantes tengan una licencia de conducir Clase D (regular) de Alabama válida antes de solicitar un CLP o una CDL. Fuente: preguntas frecuentes (FAQ) de CDL de ALEA; página de Requisitos de Documentos."},"33":{"q":"¿Qué agencia emite las licencias de conducir comercial en Alabama?","options":["El Departamento de Transporte de Alabama (ALDOT)","La oficina del registro civil del condado (county probate office)","La Agencia de Aplicación de la Ley de Alabama (ALEA), Driver License Division","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"Las CDL en Alabama son emitidas por la Agencia de Aplicación de la Ley de Alabama (ALEA) a través de su Driver License Division, no por un DMV separado ni por ALDOT. Fuente: ALEA Driver License Division."},"34":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) requerida antes de una primera CDL de Alabama debe ser impartida por un proveedor que figure en dónde?","options":["Únicamente en la lista de escuelas aprobadas por ALEA","El Registro de Proveedores de Capacitación (TPR) de la FMCSA","Cualquier empresa privada de transporte por camión","El registro del Sistema de Colegios Comunitarios de Alabama"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de CDL por primera vez (y ciertas mejoras de categoría/endosos) deben completar la ELDT con un proveedor que figure en el Registro de Proveedores de Capacitación (Training Provider Registry) de la FMCSA, el cual debe cargar la finalización antes de que Alabama permita el examen. Fuente: preguntas frecuentes (FAQ) de CDL de ALEA; 49 CFR part 380."},"35":{"q":"¿Qué trámite de CDL NO requiere, por sí solo, la Capacitación para Conductores de Nivel Inicial (ELDT) antes del examen en Alabama?","options":["Obtener una CDL por primera vez","Mejorar de Clase B a Clase A","Renovar una CDL con la misma clase y endosos","Obtener un primer endoso de HazMat (H)"],"explanation":"La ELDT se aplica a las CDL por primera vez, a las mejoras de clase y a los primeros endosos S, P o H. Una simple renovación que no mejora la clase ni agrega un endoso cubierto no activa la ELDT. Fuente: 49 CFR part 380; preguntas frecuentes (FAQ) de CDL de ALEA."},"36":{"q":"Un solicitante de CDL de Alabama que conduce en el comercio interestatal y que está obligado a cumplir con los estándares médicos federales se autocertifica bajo qué categoría?","options":["Interestatal Exceptuado (Excepted Interstate)","Interestatal No Exceptuado (Non-Excepted Interstate)","Intraestatal Exceptuado (Excepted Intrastate)","Intraestatal No Exceptuado (Non-Excepted Intrastate)"],"explanation":"La categoría Interestatal No Exceptuado (Non-Excepted Interstate) se aplica a los conductores que operan en el comercio interestatal y que deben mantener un Certificado de Examinador Médico del DOT válido. Alabama exige la autocertificación en una de cuatro categorías según 49 CFR 383. Fuente: requisitos de autocertificación de ALEA; 49 CFR 383.71."},"37":{"q":"¿Entre cuántas categorías de autocertificación médica debe elegir un titular de CDL de Alabama, y cuál requiere mantener una tarjeta médica del DOT vigente?","options":["Dos categorías; solo la interestatal necesita una tarjeta médica","Cuatro categorías; la categoría Interestatal No Exceptuado (Non-Excepted Interstate) requiere una tarjeta médica del DOT vigente","Tres categorías; ninguna requiere una tarjeta médica","Cuatro categorías; la categoría Intraestatal Exceptuado (Excepted Intrastate) requiere una tarjeta médica del DOT vigente"],"explanation":"Alabama utiliza las cuatro categorías federales (Interestatal No Exceptuado, Interestatal Exceptuado, Intraestatal No Exceptuado, Intraestatal Exceptuado). Los conductores que se certifican como Interestatal No Exceptuado deben presentar y mantener un Certificado de Examinador Médico del DOT emitido por un examinador certificado por la FMCSA. Fuente: autocertificación de ALEA; 49 CFR 383.71."},"38":{"q":"Al solicitar una CDL o un CLP de Alabama, ¿qué conjunto de documentos debe presentar el solicitante?","options":["Solo una tarjeta de Seguro Social","Comprobante de identidad, comprobante del número de Seguro Social, comprobante de residencia en Alabama y (si no es ciudadano estadounidense) comprobante de presencia legal","Solo un pasaporte y dos facturas de servicios públicos","Comprobante de identidad y un diploma de escuela secundaria"],"explanation":"ALEA exige un comprobante principal de identidad, un comprobante documentado del SSN, comprobante de residencia en Alabama y comprobante de presencia legal para quienes no son ciudadanos; un mismo documento no puede contar para dos requisitos. Fuente: página de Requisitos de Documentos y Tarifas de ALEA."},"39":{"q":"Dado que un autobús escolar que transporta 16 o más ocupantes también es un vehículo de pasajeros, ¿qué exige Alabama además del endoso de Autobús Escolar (S)?","options":["Una CDL Clase A por separado","El endoso de Pasajeros (P)","El endoso de Cisterna (N)","El endoso de Dobles/Triples (T)"],"explanation":"Alabama exige el endoso de Pasajeros (P) junto con el endoso de Autobús Escolar (S); los solicitantes aprueban los exámenes de conocimientos de Conocimientos Generales, Pasajeros y Autobús Escolar, además de un examen de habilidades en un autobús representativo. Fuente: clases/endosos de CDL de ALEA; Manual de CDL de Alabama."},"40":{"q":"En Alabama, ¿cuál es la concentración de alcohol en la sangre (BAC) más baja que hace ilegal operar un vehículo comercial?","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"Alabama sigue el estándar federal para vehículos comerciales (CMV): es ilegal operar un CMV si su BAC es de 0.04% o más. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; 49 CFR 383.51."},"41":{"q":"Bajo la regla de consentimiento implícito de Alabama, ¿qué se presume respecto a una persona que conduce un vehículo comercial en las carreteras de Alabama?","options":["Ha otorgado su consentimiento a las pruebas de alcohol","Debe portar una tarjeta de consentimiento por separado","Renuncia al derecho a una audiencia","Consiente solo si está visiblemente afectada"],"explanation":"El Manual de CDL de Alabama establece que, si usted opera un CMV, se considerará que ha otorgado su consentimiento a las pruebas de alcohol. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; Ala. Code Title 32."},"42":{"q":"En Alabama, ¿por cuánto tiempo perderá un titular de CDL su CDL por una PRIMERA falta grave, como un DUI en un CMV o negarse a la prueba de alcohol (cuando no se transporta material peligroso con rótulos)?","options":["60 días","120 días","Al menos 1 año","Al menos 3 años"],"explanation":"Una primera falta grave (DUI, BAC de 0.04 o más en un CMV, negarse a la prueba, abandonar el lugar de los hechos, etc.) resulta en la pérdida de la CDL por al menos un año. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; 49 CFR 383.51."},"43":{"q":"En Alabama, un conductor comete una primera falta grave mientras opera un CMV que lleva rótulos (placards) de materiales peligrosos. ¿Cuánto dura la descalificación?","options":["Al menos 1 año","Al menos 2 años","Al menos 3 años","De por vida"],"explanation":"Si una primera falta grave ocurre mientras se opera un CMV con rótulos (placards) de materiales peligrosos, la descalificación es de al menos tres años en lugar de uno. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; 49 CFR 383.51."},"44":{"q":"En Alabama, ¿cuál es la descalificación por una SEGUNDA falta grave (como un segundo DUI en un CMV)?","options":["1 año","3 años","10 años","De por vida"],"explanation":"Una segunda falta grave resulta en la pérdida de la CDL de por vida. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; 49 CFR 383.51."},"45":{"q":"En Alabama, negarse a someterse a una prueba de alcohol mientras se opera un CMV se considera qué tipo de infracción?","options":["Una infracción de tránsito seria (regla de 60 días)","Una falta grave (pérdida de al menos 1 año)","Una infracción menor con solo una multa","Una violación de una orden de fuera de servicio (out-of-service)"],"explanation":"Negarse a someterse a una prueba de alcohol en la sangre está catalogado como una falta grave en Alabama, lo que conlleva una descalificación de al menos un año por una primera falta. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; 49 CFR 383.51."},"46":{"q":"¿Cuál de las siguientes figura como una infracción de tránsito SERIA en el Manual de CDL de Alabama?","options":["Conducir 5 mph por encima del límite","Exceso de velocidad grave (15 mph o más por encima del límite establecido)","Una calcomanía de registro vencida","Una luz trasera quemada"],"explanation":"Las infracciones de tránsito serias incluyen el exceso de velocidad grave, definido como 15 mph o más por encima del límite establecido, junto con la conducción imprudente, los cambios de carril indebidos y seguir a otro vehículo demasiado de cerca. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.3."},"47":{"q":"En Alabama, un titular de CDL es condenado por DOS infracciones de tránsito serias en un CMV dentro de un período de tres años. ¿Cuál es la descalificación?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"Dos infracciones de tránsito serias en un CMV dentro de un período de tres años resultan en la pérdida de la CDL por al menos 60 días. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.3; 49 CFR 383.51."},"48":{"q":"En Alabama, un titular de CDL es condenado por TRES infracciones de tránsito serias en un CMV dentro de un período de tres años. ¿Cuál es la descalificación?","options":["Al menos 60 días","Al menos 90 días","Al menos 120 días","Al menos 1 año"],"explanation":"Tres o más infracciones de tránsito serias en un CMV dentro de un período de tres años resultan en la pérdida de la CDL por al menos 120 días. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.3; 49 CFR 383.51."},"49":{"q":"En Alabama, ¿cuál es la descalificación por una PRIMERA violación de una orden de fuera de servicio (out-of-service)?","options":["Al menos 30 días","Al menos 90 días","Al menos 180 días","Al menos 1 año"],"explanation":"Una primera violación de una orden de fuera de servicio (out-of-service) resulta en la pérdida de la CDL por al menos 90 días. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.4; 49 CFR 383.51."},"50":{"q":"En Alabama, un conductor comete DOS violaciones de órdenes de fuera de servicio (out-of-service) dentro de un período de diez años. ¿Cuál es la descalificación?","options":["Al menos 120 días","Al menos 1 año","Al menos 3 años","Al menos 5 años"],"explanation":"Dos violaciones de órdenes de fuera de servicio (out-of-service) dentro de un período de diez años resultan en la pérdida de la CDL por al menos un año. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.4; 49 CFR 383.51."},"51":{"q":"En Alabama, un conductor comete TRES o más violaciones de órdenes de fuera de servicio (out-of-service) dentro de un período de diez años. ¿Cuál es la descalificación?","options":["Al menos 1 año","Al menos 2 años","Al menos 3 años","De por vida"],"explanation":"Tres o más violaciones de órdenes de fuera de servicio (out-of-service) dentro de un período de diez años resultan en la pérdida de la CDL por al menos tres años. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.4; 49 CFR 383.51."},"52":{"q":"En Alabama, ¿cuál es la descalificación por una PRIMERA violación en un cruce de ferrocarril a nivel (railroad-highway grade crossing) en un CMV?","options":["Al menos 30 días","Al menos 60 días","Al menos 120 días","Al menos 1 año"],"explanation":"Una primera violación en un cruce de ferrocarril a nivel (railroad-highway grade crossing) resulta en la pérdida de la CDL por al menos 60 días. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.5; 49 CFR 383.51."},"53":{"q":"En Alabama, un titular de CDL recibe una SEGUNDA violación en un cruce de ferrocarril a nivel (railroad-highway grade crossing) dentro de un período de tres años. ¿Cuál es la descalificación?","options":["Al menos 60 días","Al menos 120 días","Al menos 6 meses","Al menos 1 año"],"explanation":"Una segunda violación en un cruce de ferrocarril a nivel (railroad-highway grade crossing) dentro de un período de tres años resulta en la pérdida de la CDL por al menos 120 días. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.5; 49 CFR 383.51."},"54":{"q":"En Alabama, un titular de CDL recibe una TERCERA violación en un cruce de ferrocarril a nivel (railroad-highway grade crossing) dentro de un período de tres años. ¿Cuál es la descalificación?","options":["Al menos 120 días","Al menos 180 días","Al menos 1 año","Al menos 3 años"],"explanation":"Una tercera violación en un cruce de ferrocarril a nivel (railroad-highway grade crossing) dentro de un período de tres años resulta en la pérdida de la CDL por al menos un año. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.5; 49 CFR 383.51."},"55":{"q":"En Alabama, ¿qué sucede si se descubre que un conductor de CMV tiene cualquier cantidad detectable de alcohol que aún está por debajo de 0.04%?","options":["Nada, está por debajo del límite legal","Fuera de servicio (out-of-service) por 24 horas","Descalificación inmediata de 1 año","Una prohibición de por vida"],"explanation":"Un conductor de CMV con cualquier cantidad detectable de alcohol por debajo de 0.04% será puesto fuera de servicio (out-of-service) durante 24 horas. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2."},"56":{"q":"En Alabama, ¿después de cuántas condenas por usar un teléfono móvil de mano mientras se conduce un CMV se descalifica la CDL de un conductor?","options":["Una condena","Dos o más condenas","Cuatro o más condenas","Seis o más condenas"],"explanation":"Una CDL se descalifica después de dos o más condenas por una ley estatal sobre el uso de teléfonos móviles de mano mientras se opera un CMV: 60 días por la segunda falta dentro de 3 años y 120 días por tres o más dentro de 3 años. Fuente: Manual de CDL de Alabama (ALEA), Sección 2.9.4."},"57":{"q":"Según las reglas del Manual de CDL de Alabama, enviar mensajes de texto mientras se conduce un CMV está prohibido. Las condenas a conductores pueden conllevar una sanción civil de hasta qué monto?","options":["Hasta $500","Hasta $1,000","Hasta $2,750","Hasta $11,000"],"explanation":"Cada infracción por enviar mensajes de texto o por usar un teléfono de mano por parte de un conductor de CMV está sujeta a una sanción civil de hasta $2,750 (los empleadores pueden ser multados con hasta $11,000). Fuente: Manual de CDL de Alabama (ALEA), Secciones 2.9.4 y 2.9.5; 49 CFR 392."},"58":{"q":"En Alabama, usar un CMV para cometer un delito grave (felony) relacionado con sustancias controladas resulta en qué sanción?","options":["Una descalificación de 60 días","Una descalificación de 1 año","Una descalificación de 3 años","Pérdida de la CDL de por vida"],"explanation":"Usar un CMV para cometer un delito grave (felony) relacionado con sustancias controladas resulta en la pérdida de la CDL de por vida, sin posibilidad de reinstauración. Fuente: Manual de CDL de Alabama (ALEA), Sección 1.3.2; 49 CFR 383.51."},"59":{"q":"¿Cuál de estas es una infracción de tránsito SERIA según el Manual de CDL de Alabama, en lugar de una falta grave?","options":["Conducir un CMV con un BAC de 0.04%","Negarse a una prueba química de alcohol","Seguir a un vehículo demasiado de cerca","Abandonar el lugar de un accidente"],"explanation":"Seguir a un vehículo demasiado de cerca está catalogado como una infracción de tránsito seria (que cuenta para la regla de 60/120 días), mientras que el DUI, la negativa a la prueba y abandonar el lugar de los hechos son faltas graves que conllevan una descalificación de al menos un año. Fuente: Manual de CDL de Alabama (ALEA), Secciones 1.3.2 y 1.3.3."},"60":{"q":"Cuando un vehículo con materiales peligrosos rotulado debe detenerse en un cruce ferroviario a nivel en Alabama, ¿a qué distancia del riel más cercano debe detenerse el conductor?","options":["No menos de 10 pies y no más de 25 pies","No menos de 15 pies y no más de 50 pies","No menos de 25 pies y no más de 75 pies","No menos de 5 pies y no más de 15 pies"],"explanation":"Alabama exige que un vehículo con HazMat rotulado se detenga de 15 a 50 pies antes del riel más cercano y luego avance solo cuando no se aproxime ningún tren y pueda despejar las vías sin detenerse. Fuente: Manual CDL de Alabama (ALEA), Sección 9.6 Cruces Ferroviarios; Ala. Code 32-5A-150."},"61":{"q":"Según la Ley de Cambio de Carril (Move Over Act) de Alabama, cuando un conductor en una carretera de varios carriles no puede desocupar de forma segura el carril más cercano a un vehículo de emergencia o de las fuerzas del orden detenido con luces intermitentes encendidas, ¿qué debe hacer el conductor?","options":["Reducir a una velocidad de al menos 10 mph por debajo del límite de velocidad señalizado","Reducir a una velocidad de al menos 20 mph por debajo del límite de velocidad señalizado","Detenerse por completo hasta que el vehículo de emergencia se retire","Reducir a una velocidad de al menos 15 mph por debajo del límite de velocidad señalizado"],"explanation":"Según la Ley de Cambio de Carril (Move Over Act) de Alabama, un conductor que no puede cambiar de carril de forma segura debe reducir a una velocidad de al menos 15 mph menos que el límite de velocidad señalizado. Fuente: Ala. Code 32-5A-58.2 (Cambiar de Carril o Reducir la Velocidad al Aproximarse a Vehículos de Emergencia)."},"62":{"q":"¿Cuál es el límite máximo de velocidad en una autopista interestatal en Alabama (a menos que se señalice o autorice de otra manera)?","options":["65 mph","75 mph","80 mph","70 mph"],"explanation":"La ley de Alabama establece la velocidad máxima en las autopistas interestatales en 70 mph; en otras carreteras con cuatro o más carriles el máximo es de 65 mph. Fuente: Ala. Code 32-5A-171 (Límites Máximos)."},"63":{"q":"En Alabama, si un vehículo comercial debe detenerse en una carretera de un solo sentido o dividida, ¿dónde se deben colocar los tres dispositivos de advertencia de emergencia?","options":["A 10 pies, 50 pies y 150 pies hacia el tráfico que se aproxima","A 25 pies, 100 pies y 250 pies hacia el tráfico que se aproxima","A 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima","A 5 pies, 75 pies y 100 pies hacia el tráfico que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, Alabama indica que los dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima. Fuente: Manual CDL de Alabama (ALEA), Sección 2.8 Dispositivos de Advertencia para Vehículos Detenidos."},"64":{"q":"Según la ley de autobuses escolares de Alabama, ¿cuándo debe detenerse por completo el conductor de un vehículo que se encuentra con un autobús escolar detenido o lo rebasa cuando este tiene sus señales visuales en funcionamiento?","options":["Solo cuando se aproxima por detrás del autobús, nunca por el frente","Solo cuando el autobús está en el mismo lado de la vía que el conductor","Solo si hay niños visiblemente presentes en la vía","Al aproximarse desde cualquier dirección en una vía común de dos carriles o sin división"],"explanation":"Alabama exige que un conductor que se encuentra con un autobús escolar o lo rebasa desde CUALQUIER dirección se detenga cuando el autobús se ha detenido para recoger o dejar niños con su señal visual en funcionamiento, excepto en una carretera dividida según se define por estatuto. Fuente: Ala. Code 32-5A-154."},"65":{"q":"¿Qué situación describe la ÚNICA excepción de Alabama para detenerse ante un autobús escolar detenido que recoge o deja niños?","options":["Conducir en cualquier ciudad con un límite de velocidad señalizado de 30 mph o menos","Cada vez que el conductor esté a más de 100 pies del autobús","Encontrarse con el autobús desde la calzada opuesta de una carretera dividida separada en dos o más carriles de sentido contrario","Cualquier vía de cuatro carriles, esté dividida o no"],"explanation":"Alabama exime a un conductor de detenerse solo cuando se encuentra con un autobús escolar detenido en la calzada opuesta de una carretera DIVIDIDA con cuatro o más carriles que permite que al menos dos carriles de tráfico circulen en sentidos opuestos. En una vía de varios carriles sin división, todos los conductores aún deben detenerse. Fuente: Ala. Code 32-5A-154."},"66":{"q":"¿A qué distancia del riel más cercano debe detenerse un autobús que transporta pasajeros en Alabama en un cruce ferroviario a nivel?","options":["Entre 10 y 40 pies","Entre 20 y 60 pies","Entre 5 y 25 pies","Entre 15 y 50 pies"],"explanation":"Alabama exige que un autobús que transporta pasajeros se detenga entre 15 y 50 pies antes del riel más cercano, escuche y mire en ambas direcciones, y luego cruce solo cuando pueda hacerlo sin detenerse sobre las vías. Fuente: Manual CDL de Alabama (ALEA), Sección 4.3.5 Paradas en Cruces Ferroviarios a Nivel."},"67":{"q":"En una carretera de Alabama de dos carriles que lleva tráfico en ambas direcciones, ¿dónde se colocan los dispositivos de advertencia cuando un CMV está detenido?","options":["A menos de 10 pies del vehículo, y a 200 pies al frente y 200 pies atrás","A menos de 25 pies del vehículo, y a 150 pies al frente y atrás","Los tres colocados a 100 pies detrás del vehículo únicamente","A menos de 10 pies del vehículo, y a 100 pies al frente y 100 pies atrás"],"explanation":"En una carretera de dos carriles que lleva tráfico en ambos sentidos, Alabama indica colocar un dispositivo a menos de 10 pies del vehículo, uno a 100 pies detrás y uno a 100 pies adelante, sobre el acotamiento o en el carril. Fuente: Manual CDL de Alabama (ALEA), Sección 2.8 Dispositivos de Advertencia."},"68":{"q":"¿Cuál es la multa por una infracción de la Ley de Cambio de Carril (Move Over Act) de Alabama?","options":["$100","$500","$200","$50"],"explanation":"Una infracción de la ley de Cambio de Carril (Move Over) de Alabama es un delito menor sancionable con una multa de doscientos dólares ($200). Fuente: Ala. Code 32-5A-58.2."},"69":{"q":"Además de los vehículos de las fuerzas del orden y de emergencia, ¿cuál de estos vehículos detenidos que muestran luces de advertencia/intermitentes también activa los requisitos de Cambio de Carril (Move Over) de Alabama?","options":["Un vehículo de recolección de basura, desechos, residuos o reciclaje","Cualquier automóvil de pasajeros de propiedad privada con las luces de emergencia encendidas","Un autobús escolar recogiendo niños","Una camioneta de reparto estacionada en doble fila en una calle de la ciudad"],"explanation":"Alabama amplió la Ley de Cambio de Carril (Move Over Act) para cubrir grúas, vehículos de servicios públicos, vehículos de mantenimiento/construcción/topografía Y vehículos de recolección de basura, desechos, residuos o reciclaje que muestran luces intermitentes. Fuente: Ala. Code 32-5A-58.2."},"70":{"q":"¿Cuál es el límite máximo de velocidad en Alabama en una carretera (que no sea una interestatal) que tiene cuatro o más carriles de tráfico?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"Alabama limita la velocidad en carreteras no interestatales con cuatro o más carriles a 65 mph, mientras que las interestatales se limitan a 70 mph. Fuente: Ala. Code 32-5A-171."},"71":{"q":"Según la regla de uso de carriles de Alabama, ¿dónde debe conducirse un vehículo comercial que circula a menos de la velocidad normal del tráfico?","options":["En el carril central en todo momento","En el carril de la derecha, o lo más cerca posible del borde derecho de la calzada","En cualquier carril, ya que los camiones están exentos de las reglas de carril","En el carril izquierdo para mantener los carriles derechos despejados para incorporaciones"],"explanation":"Alabama exige que cualquier vehículo que viaje más lento que la velocidad normal del tráfico se mantenga a la derecha (carril de la derecha o lo más cerca posible del borde derecho), excepto al rebasar, adelantar o prepararse para girar a la izquierda. Fuente: Ala. Code 32-5A-80 (Conducir en el Lado Derecho de la Calzada)."},"72":{"q":"Si un CMV detenido en Alabama está en una colina o curva que bloquea la visibilidad de los conductores que se aproximan, ¿qué debe hacer el conductor con el dispositivo de advertencia más alejado hacia atrás?","options":["Moverlo más atrás para que se advierta al tráfico a una distancia de al menos 500 pies","Dejarlo exactamente a 200 pies atrás sin importar la obstrucción","Retirarlo y depender únicamente de las luces intermitentes de cuatro vías del vehículo","Colocar los tres dispositivos directamente detrás del parachoques trasero"],"explanation":"Cuando una colina, curva u otra obstrucción impide que los conductores vean el vehículo dentro de 500 pies, Alabama indica mover el triángulo más alejado hacia atrás por la vía para que la advertencia se proporcione más allá de la obstrucción. Fuente: Manual CDL de Alabama (ALEA), Sección 2.8 Dispositivos de Advertencia."},"73":{"q":"¿Cuál es el rango de multa para una PRIMERA condena por rebasar ilegalmente un autobús escolar detenido en Alabama?","options":["No menos de $150 ni más de $300","No menos de $50 ni más de $100","No menos de $500 ni más de $1,000","Una cantidad fija de $250 sin rango"],"explanation":"Una primera condena por rebasar ilegalmente un autobús escolar detenido en Alabama conlleva una multa de no menos de $150 ni más de $300, con multas más severas, servicio comunitario y suspensión de licencia para infracciones reincidentes. Fuente: Ala. Code 32-5A-154."},"74":{"q":"¿Qué vehículos están obligados a hacer una parada completa en todos los cruces ferroviarios a nivel en Alabama?","options":["Todos los vehículos comerciales de más de 10,000 libras sin excepción","Autobuses que transportan pasajeros y vehículos rotulados para materiales peligrosos","Solo camiones cisterna vacíos","Solo vehículos que remolcan un remolque de cualquier tipo"],"explanation":"Alabama exige que los autobuses que transportan pasajeros y los vehículos HazMat rotulados (incluidos los tanques de carga HazMat cargados o vacíos y los vehículos que transportan cualquier cantidad de cloro) se detengan en los cruces a nivel; los CMV comunes no están obligados a detenerse a menos que las condiciones lo exijan. Fuente: Manual CDL de Alabama (ALEA), Secciones 2.15 y 9.6."},"75":{"q":"¿Cuál es el ANCHO máximo legal de carga en Alabama antes de que se requiera un permiso de sobredimensión de ALDOT?","options":["8 pies 0 pulgadas","10 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 6 pulgadas"],"explanation":"El ancho máximo legal estándar de carga de Alabama es de 8 pies 6 pulgadas (102 pulgadas); cualquier cosa más ancha requiere un permiso de sobredimensión del Departamento de Transporte de Alabama (ALDOT). Fuente: Regulaciones de Permisos de Sobredimensión/Sobrepeso de ALDOT."},"76":{"q":"¿Cuál es la ALTURA máxima legal de carga en Alabama antes de que se requiera un permiso de sobredimensión?","options":["13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"Alabama establece la altura máxima legal del vehículo/carga en 13 pies 6 pulgadas; las cargas que excedan esto requieren un permiso de sobredimensión de ALDOT, y las alturas de más de 15 pies 6 pulgadas requieren una escolta con poste medidor de altura al frente. Fuente: Regulaciones de Permisos de Sobredimensión/Sobrepeso de ALDOT."},"77":{"q":"En una pendiente descendente larga y pronunciada en el terreno montañoso de Alabama, ¿cuál es el propósito correcto de una rampa de escape para vehículos sin frenos?","options":["Detener un vehículo cuyos frenos han fallado usando un lecho de material suelto y blando","Proporcionar un área de descanso pavimentada para que los camiones enfríen sus frenos voluntariamente","Servir como un carril de inspección obligatorio para todos los CMV que descienden la pendiente","Permitir que los vehículos más rápidos rebasen a los camiones lentos en la subida"],"explanation":"Las rampas de escape se construyen en pendientes descendentes pronunciadas para detener de forma segura los vehículos sin frenos usando un lecho largo de material suelto y blando; los conductores deben conocer las ubicaciones de las rampas en su ruta. Las pendientes de la I-59 de Alabama cerca de Lookout/Sand Mountain cuentan con tales rampas. Fuente: Manual CDL de Alabama (ALEA), Sección 2.16 Conducción en Montaña / Rampas de Escape."},"78":{"q":"¿Dentro de cuántos minutos debe un conductor de CMV de Alabama que se detiene en una calzada o acotamiento colocar los dispositivos de advertencia de emergencia requeridos?","options":["10 minutos","5 minutos","15 minutos","30 minutos"],"explanation":"Si un CMV debe detenerse en una calzada o acotamiento en Alabama, el conductor debe colocar los dispositivos de advertencia de emergencia dentro de diez minutos. Fuente: Manual CDL de Alabama (ALEA), Sección 2.8 Dispositivos de Advertencia para Vehículos Detenidos."},"79":{"q":"Al aproximarse a un vehículo de emergencia detenido en una carretera de DOS CARRILES de Alabama donde es imposible cambiar de carril y el límite señalizado es de 45 mph, ¿qué debe hacer un conductor?","options":["Mantener el límite señalizado pero encender las luces intermitentes de cuatro vías","Detenerse por completo en el carril de circulación","Alejarse lo más posible dentro del carril y reducir a 15 mph por debajo del límite señalizado (30 mph)","Reducir exactamente a 20 mph sin importar el límite señalizado"],"explanation":"En una carretera de dos carriles de Alabama, un conductor debe alejarse lo más posible del vehículo de emergencia dentro del carril y reducir a 15 mph por debajo del límite señalizado cuando ese límite es de 25 mph o mayor (aquí 45 - 15 = 30 mph). Fuente: Ala. Code 32-5A-58.2."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) y administra las pruebas de CDL en Alabama?","options":["El Departamento de Transporte de Alabama (ALDOT)","La Agencia de Aplicación de la Ley de Alabama (ALEA), División de Licencias de Conducir","El Departamento de Ingresos de Alabama, División de Vehículos Motorizados","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"Las CDL en Alabama son emitidas y evaluadas por la Agencia de Aplicación de la Ley de Alabama (ALEA), División de Licencias de Conducir. El Manual CDL de Alabama es publicado por ALEA, y las pruebas de conocimiento/habilidades se realizan en las oficinas de Licencias de Conducir Comerciales de ALEA. Fuente: Manual CDL de Alabama (ALEA), Introducción; División de Licencias de Conducir de ALEA."},"81":{"q":"¿Cómo programa un solicitante una prueba de conocimiento o de habilidades de CDL en Alabama?","options":["Acudiendo sin cita a cualquier oficina de placas/licencias del condado","Solicitando en línea a FMCSA, que asigna un centro de pruebas","Enviando una solicitud por correo a ALDOT y esperando una fecha programada","Haciendo una cita en una oficina de Licencias de Conducir Comerciales de ALEA a través del sistema de programación en línea en alea.gov"],"explanation":"El Manual CDL de Alabama indica a los solicitantes que hagan una cita para la prueba de conocimiento o de habilidades en una oficina de Licencias de Conducir Comerciales de ALEA; en 'Driver License' / 'Online Services' en alea.gov, los solicitantes usan 'Schedule DL Appointment'. Fuente: Manual CDL de Alabama (ALEA), página de Oficinas de Licencias de Conducir Comerciales."},"82":{"q":"En Alabama, ¿qué debe obtener y tener un solicitante antes de que se le permita tomar la prueba de habilidades de CDL por primera vez?","options":["Un endoso de Materiales Peligrosos","Una exención médica federal del DOT","Una cuenta del Plan Internacional de Registro (IRP)","Un Permiso de Aprendiz Comercial (CLP)"],"explanation":"Un solicitante de CDL por primera vez o que actualiza su licencia primero debe recibir un Permiso de Aprendiz Comercial (CLP) aprobando la(s) prueba(s) de conocimiento requerida(s). El CLP debe luego mantenerse antes de poder tomar la prueba de habilidades. Fuente: Manual CDL de Alabama (ALEA), Sección 1; Preguntas Frecuentes de CDL de ALEA."},"83":{"q":"Según las reglas de Alabama (y federales), ¿durante cuánto tiempo debe mantenerse un CLP antes de que el titular pueda tomar la prueba de habilidades de CDL?","options":["Al menos 7 días","Al menos 30 días","Al menos 14 días","Al menos 60 días"],"explanation":"Alabama sigue el requisito federal de que un CLP se mantenga durante un mínimo de 14 días antes de que el titular pueda tomar la prueba de habilidades de CDL. Fuente: Preguntas Frecuentes de CDL de ALEA; 49 CFR 383.25 según se aplica en Alabama."},"84":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Alabama, y se puede renovar?","options":["Válido por 180 días y se puede renovar una vez","Válido por 1 año y se puede renovar dos veces","Válido por 30 días y no es renovable","Válido por 360 días y no es renovable"],"explanation":"ALEA establece que el CLP es válido por 360 días y no es renovable; si vence, el solicitante debe volver a hacer la prueba para obtener un nuevo CLP. Fuente: Preguntas Frecuentes de CDL de ALEA."},"85":{"q":"Antes de hacer la prueba para una CDL por primera vez en Alabama, ¿qué capacitación debe completar un solicitante?","options":["Un curso de manejo defensivo aprobado por los tribunales de Alabama","Un curso de seguridad laboral de OSHA de 40 horas","Capacitación para Conductores de Nivel Inicial (ELDT) a través de un proveedor registrado en FMCSA","Un curso presencial administrado por ALEA que se imparte solo en la oficina de Montgomery"],"explanation":"La Capacitación para Conductores de Nivel Inicial (ELDT) es requerida para cualquier persona que obtenga una CDL por primera vez (y para ciertas actualizaciones/endosos). La capacitación debe completarse a través de un proveedor incluido en el Registro de Proveedores de Capacitación de FMCSA antes de hacer la prueba. Fuente: Materiales de Autocertificación/Preguntas Frecuentes de CDL de ALEA; regla ELDT de FMCSA vigente desde el 7 de febrero de 2022."},"86":{"q":"¿Qué prueba de conocimiento debe aprobar TODO solicitante de CDL de Alabama, independientemente de la clase de vehículo o los endosos?","options":["La prueba de frenos de aire","La prueba de vehículos combinados","La prueba de materiales peligrosos","La prueba de conocimientos generales"],"explanation":"El Manual CDL de Alabama enumera la prueba de conocimientos generales como la que toman todos los solicitantes; otras pruebas de conocimiento (frenos de aire, combinación, pasajeros, hazmat, tanque, dobles/triples, autobús escolar) dependen de la clase y los endosos solicitados. Fuente: Manual CDL de Alabama (ALEA), Sección 1.1.1 Pruebas de Conocimiento."},"87":{"q":"Según el Manual CDL de Alabama, ¿de cuáles tres segmentos consta la prueba de habilidades de CDL?","options":["Examen escrito, examen de la vista y prueba de manejo","Acoplamiento/desacoplamiento, retroceso y revisión de frenos de aire","Pre-viaje, manejo defensivo y manejo nocturno","Inspección del vehículo, control básico del vehículo y manejo en la vía"],"explanation":"El manual establece que la prueba de habilidades de CDL tiene tres segmentos: inspección del vehículo, control básico del vehículo y manejo en la vía. Fuente: Manual CDL de Alabama (ALEA), Sección 1.1.2 Pruebas de Habilidades."},"88":{"q":"¿En qué orden se deben tomar los tres segmentos de la prueba de habilidades de CDL en Alabama?","options":["En cualquier orden que el solicitante elija el día de la prueba","Primero en la vía, luego control básico, luego inspección del vehículo","En el orden indicado (inspección del vehículo, luego control básico del vehículo, luego en la vía), aprobando cada uno antes de pasar al siguiente","Primero control básico del vehículo, luego en la vía, luego inspección del vehículo"],"explanation":"El Manual CDL de Alabama establece: 'Debe tomar los segmentos en el orden indicado y debe aprobar cada uno antes de pasar al siguiente' — inspección del vehículo, control básico del vehículo, luego manejo en la vía. Fuente: Manual CDL de Alabama (ALEA), Sección 1.1.2."},"89":{"q":"¿Qué tipo de vehículo debe usar un solicitante para tomar la prueba de habilidades de CDL de Alabama?","options":["Un vehículo representativo de la clase/tipo para el cual el solicitante desea obtener la licencia","Cualquier automóvil de pasajeros, ya que solo se evalúan los hábitos de manejo","Un vehículo proporcionado de forma gratuita por el sitio de pruebas de ALEA","Cualquier vehículo comercial, sin importar la clase, siempre que tenga frenos de aire"],"explanation":"El manual requiere que la prueba de habilidades se tome en el tipo de vehículo para el cual el solicitante desea obtener la licencia; la clase de vehículo usado puede restringir la CDL emitida. No se puede usar un vehículo con componentes marcados o etiquetados. Fuente: Manual CDL de Alabama (ALEA), Sección 1.1.2."},"90":{"q":"Durante la prueba de habilidades de inspección del vehículo de la CDL de Alabama, ¿qué debe hacer el solicitante en cada elemento?","options":["Inspeccionar cada elemento en silencio mientras el examinador cronometra el proceso","Señalar o tocar y nombrar el elemento, y explicar al examinador qué se está inspeccionando y por qué","Escribir una descripción de cada elemento en un formulario de inspección","Solo enumerar verbalmente los elementos sin tocarlos ni señalarlos"],"explanation":"El manual establece que durante la prueba de Inspección del Vehículo debe señalar/tocar y nombrar el elemento que está inspeccionando y explicar al examinador qué está inspeccionando y por qué. Fuente: Manual CDL de Alabama (ALEA), Sección 1.1.2, Inspección del Vehículo."},"91":{"q":"¿Qué evalúa la parte de control básico del vehículo de la prueba de habilidades de CDL de Alabama?","options":["Conocimiento de las reglas de rotulación de materiales peligrosos","Habilidad para mover el vehículo hacia adelante, hacia atrás y girarlo dentro de un área definida","Capacidad para leer e interpretar señales de tránsito","Capacidad para completar un registro diario del conductor"],"explanation":"La prueba de control básico del vehículo mide la habilidad del solicitante para controlar el vehículo — moverlo hacia adelante, hacia atrás y girarlo dentro de un área definida y marcada, con el examinador explicando cómo se debe realizar cada ejercicio. Fuente: Manual CDL de Alabama (ALEA), Sección 1.1.2, Control Básico del Vehículo."},"92":{"q":"¿Qué documento necesita típicamente proporcionar un solicitante de CDL de Alabama como comprobante de su número de Seguro Social al solicitar?","options":["Comprobante del número de Seguro Social del solicitante (p. ej., tarjeta de Seguro Social)","Una declaración jurada notariada únicamente de un empleador actual","Una copia únicamente de la declaración de impuestos federales más reciente del solicitante","Una carta de asignación de número DOT de autotransportista"],"explanation":"Los solicitantes de CDL de Alabama deben presentar comprobante de su número de Seguro Social junto con el comprobante requerido de identidad/residencia y una licencia de conducir de Alabama (Clase D) válida. Fuente: Requisitos de documentos de la División de Licencias de Conducir de ALEA; materiales de solicitud de CDL de ALEA."},"93":{"q":"Las regulaciones federales adoptadas en Alabama requieren que los titulares de CDL de vehículos Clase A, B o C se autocertifiquen eligiendo entre cuántas categorías de operación comercial?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"La Declaración Jurada de Autocertificación de CDL de Alabama requiere que el conductor certifique una de cuatro categorías de operación. Fuente: Declaración Jurada de Autocertificación de CDL de ALEA (cita 49 CFR 383, 384, 390, 391); Manual CDL de Alabama Sección 1.2."},"94":{"q":"En la Declaración Jurada de Autocertificación de CDL de Alabama, ¿cuál de las cuatro categorías REQUIERE que el conductor lleve y presente un certificado del examinador médico del DOT?","options":["Interestatal Exceptuado","Interestatal No Exceptuado","Intraestatal Exceptuado","Intraestatal No Exceptuado (con una restricción K de exención médica de Alabama)"],"explanation":"La declaración jurada de Alabama enumera cuatro categorías: Interestatal No Exceptuado (sujeto a 49 CFR parte 391 — se requiere certificado médico del DOT), Interestatal Exceptuado, Intraestatal No Exceptuado e Intraestatal Exceptuado. Solo el Interestatal No Exceptuado requiere llevar/presentar una tarjeta médica del DOT; las otras tres solo presentan la declaración jurada. Fuente: Declaración Jurada de Autocertificación de CDL de ALEA."},"95":{"q":"Según el Manual CDL de Alabama, si un conductor opera tanto en comercio interestatal como intraestatal, ¿qué estatus de autocertificación debe elegir?","options":["Comercio intraestatal","Comercio intraestatal exceptuado","Comercio interestatal","El que realice con más frecuencia"],"explanation":"El manual establece que si opera tanto en comercio intraestatal como interestatal, debe elegir comercio interestatal al autocertificarse. Fuente: Manual CDL de Alabama (ALEA), Sección 1.2.1."},"96":{"q":"A partir del cambio vigente desde el 23 de junio de 2025, ¿cómo se transmite normalmente a ALEA el certificado del examinador médico del DOT de un titular de CDL de Alabama?","options":["El conductor debe enviar por correo la tarjeta de papel original a la oficina de sucesiones del condado","El examinador médico certificado lo presenta electrónicamente a FMCSA, que lo transmite al estado de registro del conductor","El conductor carga una tarjeta de papel escaneada en el portal de permisos de ALDOT","Los inspectores de ALDOT recogen la tarjeta en las estaciones de pesaje y la reenvían a ALEA"],"explanation":"A partir del 23 de junio de 2025, ALEA acepta certificaciones médicas del DOT solo de forma electrónica: el examinador médico certificado por FMCSA presenta el resultado electrónicamente a FMCSA, que lo reenvía al estado de registro del conductor. Ya no se aceptan tarjetas de papel ni cargas hechas por uno mismo; los conductores verifican su registro en alabamadl.alea.gov. Fuente: Comunicado de prensa de ALEA 'Big Changes for Alabama CDL Holders'; Preguntas Frecuentes de CDL de ALEA."},"97":{"q":"Si un titular de CDL de Alabama Interestatal No Exceptuado no mantiene un estatus médico 'certificado' vigente en su registro, ¿cuál es la consecuencia?","options":["Pasa a ser 'no certificado' y puede perder su CDL","Su CDL se reduce automáticamente a un CLP por 90 días","Recibe una advertencia escrita única sin efecto en la licencia","Nada, porque la tarjeta médica es opcional para los titulares de CDL"],"explanation":"El Manual CDL de Alabama advierte que un conductor que debe tener un estatus médico 'certificado' y no lo proporciona ni lo mantiene actualizado pasa a ser 'no certificado' y puede perder su CDL (la CDL puede ser reducida/cancelada). Fuente: Manual CDL de Alabama (ALEA), Sección 1.2 Requisitos de Documentación Médica."},"98":{"q":"En Alabama, ¿cuándo se requiere generalmente que esté en el registro la autocertificación de un titular de CDL (y la tarjeta médica, si corresponde) en relación con la renovación de la licencia comercial?","options":["Presentada a más tardar 10 días antes de renovar la licencia de conducir comercial","Presentada solo después de que se envíe por correo la licencia renovada","Presentada dentro de los 30 días posteriores al vencimiento de la licencia","Presentada solo una vez y nunca actualizada de nuevo"],"explanation":"La Declaración Jurada de Autocertificación de CDL de ALEA indica a los conductores que presenten la declaración jurada (y la tarjeta médica, si corresponde) a más tardar 10 días antes de renovar la licencia de conducir comercial; no devolver el formulario puede resultar en la cancelación de la CDL. Fuente: Declaración Jurada de Autocertificación de CDL de ALEA."},"99":{"q":"¿Cuál es el ciclo estándar de renovación/validez de una CDL de Alabama, y cuándo vence?","options":["Se renueva cada 2 años y vence al final del año","Se renueva cada 10 años y vence el 1 de enero","Se renueva en un ciclo de 8 años y vence en el cumpleaños del conductor","Nunca vence una vez que se emite una CDL por primera vez"],"explanation":"Alabama emite/renueva las licencias de conducir, incluidas las CDL, en un ciclo de 8 años, venciendo en el cumpleaños del conductor; una CDL puede renovarse hasta 180 días antes del vencimiento y no hay período de gracia. (La validación de la TSA de un endoso de Hazmat dura solo 5 años.) Fuente: División de Licencias de Conducir de ALEA; guía de renovación de CDL de Alabama."}},"hi":{"0":{"q":"Alabama के उन राजमार्गों पर जहाँ यातायात लेन 12 फीट या उससे अधिक चौड़ी हैं, किसी वाहन की उसके भार सहित अधिकतम कुल बाहरी चौड़ाई (दर्पण और सुरक्षा उपकरणों को छोड़कर) कितनी है?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Alabama Code 32-9-20(1) उन राजमार्गों पर अधिकतम चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है जिनकी लेन 12 फीट या अधिक चौड़ी हैं, भार सहित, परंतु दर्पण और सुरक्षा उपकरणों को छोड़कर। स्रोत: Alabama Code Section 32-9-20।"},"1":{"q":"Alabama के राजमार्गों पर किसी वाहन, सेमीट्रेलर, या ट्रेलर के लिए भार सहित अधिकतम कानूनी ऊँचाई क्या है?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"Alabama Code 32-9-20(2) किसी भी वाहन, सेमीट्रेलर, या ट्रेलर को भार सहित ऊँचाई में 13 1/2 feet (13 feet 6 inches) से अधिक होने से प्रतिबंधित करता है। स्रोत: Alabama Code Section 32-9-20।"},"2":{"q":"Alabama में, किसी एक (single) धुरी के पहियों द्वारा राजमार्ग पर डाला जाने वाला अधिकतम सकल भार कितना है?","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"Alabama Code 32-9-20(4) किसी एकल धुरी को 20,000 pounds तक सीमित करता है, जो 23 U.S.C. 127 के अंतर्गत संघीय मानक के अनुरूप है। स्रोत: Alabama Code Section 32-9-20।"},"3":{"q":"Alabama में Interstate Highway System पर एक टैंडम धुरी समूह पर अधिकतम स्वीकार्य भार कितना है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","38,000 pounds"],"explanation":"Alabama Code 32-9-20(4) Interstate Highway System पर टैंडम धुरी भार को 34,000 pounds तक सीमित करता है, जिसमें सभी प्रवर्तन सहनशीलताएँ शामिल हैं, और यह संघीय सीमा से मेल खाता है। स्रोत: Alabama Code Section 32-9-20।"},"4":{"q":"Alabama में Interstate Highway System पर किसी वाहन या वाहनों के संयोजन के लिए सभी प्रवर्तन सहनशीलताओं सहित अधिकतम कुल सकल भार कितना है?","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Alabama Code 32-9-20(4) Interstate System पर कुल सकल भार को 80,000 pounds तक सीमित करता है, जिसमें सभी प्रवर्तन सहनशीलताएँ शामिल हैं, जो 23 U.S.C. 127 के अनुरूप है। स्रोत: Alabama Code Section 32-9-20।"},"5":{"q":"Alabama के राजमार्गों पर किसी एकल (सीधे) वाहन की अधिकतम लंबाई कितनी है?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Alabama Code 32-9-20(3) कहता है कि कोई भी एकल वाहन लंबाई में 40 feet से अधिक नहीं होगा। स्रोत: Alabama Code Section 32-9-20।"},"6":{"q":"Alabama में एक ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में, सेमीट्रेलर की भार सहित अधिकतम लंबाई कितनी है?","options":["48 feet","53 feet","57 feet","65 feet"],"explanation":"Alabama Code 32-9-20(3) प्रावधान करता है कि एक ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में प्रयुक्त सेमीट्रेलर, भार सहित, 57 feet से अधिक नहीं होगा। स्रोत: Alabama Code Section 32-9-20।"},"7":{"q":"Alabama में उन राजमार्गों पर जिनकी यातायात लेन 12 फीट से कम चौड़ी हैं, किसी वाहन की उसके भार सहित अधिकतम कुल बाहरी चौड़ाई कितनी है?","options":["90 inches","96 inches","102 inches","108 inches"],"explanation":"Alabama Code 32-9-20(1) उन राजमार्गों पर अधिकतम चौड़ाई को घटाकर 96 inches कर देता है, भार सहित, जिनकी यातायात लेन 12 फीट से कम चौड़ी हैं। स्रोत: Alabama Code Section 32-9-20।"},"8":{"q":"Alabama में एक ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर (twin trailer) संयोजन में, प्रत्येक सेमीट्रेलर या ट्रेलर की भार सहित अधिकतम लंबाई कितनी है?","options":["27 feet","28 1/2 feet","30 feet","33 feet"],"explanation":"Alabama Code 32-9-20(3) एक ट्रक ट्रैक्टर-सेमीट्रेलर-ट्रेलर (twin) संयोजन में प्रत्येक सेमीट्रेलर या ट्रेलर को भार सहित 28 1/2 feet तक सीमित करता है। स्रोत: Alabama Code Section 32-9-20।"},"9":{"q":"Alabama के राजमार्गों पर सामान्यतः मोटर होम कहे जाने वाले मोटर वाहन की अधिकतम लंबाई कितनी है?","options":["40 feet","45 feet","53 feet","57 feet"],"explanation":"Alabama Code 32-9-20(3) प्रावधान करता है कि सामान्यतः मोटर होम कहे जाने वाले मोटर वाहन लंबाई में 45 feet से अधिक नहीं होंगे। स्रोत: Alabama Code Section 32-9-20।"},"10":{"q":"Alabama के राजमार्ग पर वन उत्पाद या culvert pipe ढोते समय, बिना परमिट के अधिकतम कानूनी भार चौड़ाई कितनी है?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"Alabama Code 32-9-20(1) विशेष रूप से कहता है कि किसी भी राजमार्ग पर वन उत्पाद या culvert pipe ढोने वाले किसी वाहन का भार चौड़ाई में 102 inches से अधिक नहीं होगा। स्रोत: Alabama Code Section 32-9-20।"},"11":{"q":"Alabama में टैंडम धुरियों के दो लगातार सेट प्रत्येक 34,000 pounds का सकल भार ढो सकते हैं, बशर्ते लगातार सेटों की पहली और अंतिम धुरियों के बीच की दूरी कम से कम कितने फीट हो?","options":["30 feet","34 feet","36 feet","41 feet"],"explanation":"Alabama Code 32-9-20(4) टैंडम धुरियों के दो लगातार सेटों को प्रत्येक 34,000 pounds ढोने की अनुमति देता है यदि पहली और अंतिम धुरियों के बीच की कुल दूरी 36 feet या अधिक हो, और कुल सकल भार 80,000 pounds से अधिक न हो। स्रोत: Alabama Code Section 32-9-20।"},"12":{"q":"दो या अधिक लगातार धुरियों के समूह पर अधिकतम स्वीकार्य सकल भार निर्धारित करने के लिए Alabama कौन सा सूत्र लागू करता है?","options":["संघीय ब्रिज सूत्र W = 500(LN/(N-1) + 12N + 36)","अश्वशक्ति-से-भार अनुपात सूत्र","अंतराल की परवाह किए बिना एक समान 80,000-pound नियम","रुकने-की-दूरी आनुपातिकता सूत्र"],"explanation":"Alabama Code 32-9-20(4)(c) संघीय ब्रिज सूत्र W = 500(LN/(N-1) + 12N + 36) अपनाता है, जहाँ W सकल भार है, L समूह की अत्यंत धुरियों के बीच की दूरी है, और N धुरियों की संख्या है। स्रोत: Alabama Code Section 32-9-20।"},"13":{"q":"धुरी और सकल भार सीमाओं के प्रवर्तन के लिए, Alabama निर्धारित भार को किस गुणक से गुणा करके गणना की गई एक स्केल (प्रवर्तन) सहनशीलता की अनुमति देता है?","options":["0.05 (5 percent)","0.10 (10 percent)","0.15 (15 percent)","0.20 (20 percent)"],"explanation":"Alabama Code 32-9-20(4)(d) उल्लंघन माने जाने से पहले निर्धारित भार को एक-दसवें (.10), यानी 10 percent, से गुणा करने के बराबर एक स्केल/प्रवर्तन सहनशीलता की अनुमति देता है। स्रोत: Alabama Code Section 32-9-20।"},"14":{"q":"Alabama कानून के अंतर्गत, किसी फार्म से और तक कृषि वस्तुओं के परिवहन के लिए विशेष रूप से प्रयुक्त दो और तीन धुरी वाले वाहनों को किस आवश्यकता के अनुरूप होने की आवश्यकता नहीं है?","options":["चौड़ाई और ऊँचाई सीमाएँ","एकल धुरी और सकल भार आवश्यकताएँ","प्रकाश और चिह्नांकन आवश्यकताएँ","संयोजनों के लिए लंबाई सीमाएँ"],"explanation":"Alabama Code 32-9-20(4)(j) किसी फार्म से और तक कृषि वस्तुओं के परिवहन के लिए विशेष रूप से प्रयुक्त दो- और तीन-धुरी वाले वाहनों को पैराग्राफ (4)a की एकल धुरी आवश्यकताओं और पैराग्राफ (4)c की सकल भार आवश्यकताओं से छूट देता है। स्रोत: Alabama Code Section 32-9-20।"},"15":{"q":"Alabama में किसी कार्यशील सहायक शक्ति इकाई (APU) या idle-reduction तकनीक का उपयोग करने वाले वाहन को सकल, धुरी, टैंडम, या ब्रिज सूत्र सीमाओं से ऊपर कितने अतिरिक्त भार की अनुमति है?","options":["250 pounds","400 pounds","550 pounds","1,000 pounds"],"explanation":"Alabama Code 32-9-20(b)(1) सहायक शक्ति या idle-reduction तकनीक का उपयोग करने वाले वाहनों के लिए 400 pounds तक अतिरिक्त (या वास्तविक प्रमाणित APU भार, जो भी कम हो) की अनुमति देता है, जो संघीय Energy Policy Act of 2005 के अनुरूप है। स्रोत: Alabama Code Section 32-9-20।"},"16":{"q":"एक Alabama वार्षिक oversize/overweight परमिट उस वाहन के संचालन को अधिकृत नहीं कर सकता जिसका कुल सकल भार किस आँकड़े से अधिक हो?","options":["100,000 pounds","120,000 pounds","150,000 pounds","200,000 pounds"],"explanation":"Alabama Code 32-9-29(b)(1) प्रावधान करता है कि एक वार्षिक परमिट उस वाहन को अधिकृत नहीं कर सकता जिसका कुल सकल भार 150,000 pounds से अधिक हो, और 100,000 pounds से अधिक सकल भार के लिए विभाग द्वारा अग्रिम रूटिंग आवश्यक है। स्रोत: Alabama Code Section 32-9-29।"},"17":{"q":"एक Alabama वार्षिक परमिट के अंतर्गत, एक अनुमत वाहन का एकल धुरी भार किस राशि से अधिक नहीं हो सकता?","options":["20,000 pounds","22,000 pounds","25,000 pounds","27,000 pounds"],"explanation":"Alabama Code 32-9-29(b)(1) एक वार्षिक oversize/overweight परमिट के अंतर्गत एकल धुरी भार को 22,000 pounds तक सीमित करता है, जिसमें सभी प्रवर्तन सहनशीलताएँ शामिल हैं। स्रोत: Alabama Code Section 32-9-29।"},"18":{"q":"एक Alabama वार्षिक oversize/overweight परमिट उस वाहन को अधिकृत नहीं कर सकता जिसकी ऊँचाई किस सीमा से अधिक हो?","options":["13 feet 6 inches","14 feet","15 feet 6 inches","16 feet"],"explanation":"Alabama Code 32-9-29(b)(1) प्रावधान करता है कि एक वार्षिक परमिट उस वाहन के संचालन को अधिकृत नहीं कर सकता जिसकी ऊँचाई 14 feet से अधिक हो। स्रोत: Alabama Code Section 32-9-29।"},"19":{"q":"Alabama कानून के अंतर्गत, राज्य राजमार्ग प्रणाली पर आवागमन के लिए oversize/overweight परमिट के संबंध में फार्म और कृषि वस्तुओं तथा उपकरणों की क्या स्थिति है?","options":["उन्हें एक विशेष वार्षिक फार्म परमिट की आवश्यकता है","वे परमिट प्राप्त करने की आवश्यकता से मुक्त हैं","उन्हें केवल एक single-trip परमिट की आवश्यकता है","उन्हें परमिट प्राप्त करना होगा परंतु कोई शुल्क नहीं देना होगा"],"explanation":"Alabama Code 32-9-29(f) कहता है कि फार्म और कृषि वस्तुएँ तथा उपकरण Alabama की राज्य राजमार्ग प्रणाली पर आवागमन के लिए परमिट प्राप्त करने की आवश्यकता से मुक्त हैं। स्रोत: Alabama Code Section 32-9-29।"},"20":{"q":"Alabama में, जब खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो, तो वाहनों के किसी संयोजन को कम से कम कितने gross combination weight rating (GCWR) पर संचालित करने के लिए Class A CDL आवश्यक है?","options":["16,001 pounds या अधिक","26,001 pounds या अधिक","10,001 pounds या अधिक","36,001 pounds या अधिक"],"explanation":"Alabama, Class A CDL को वाहनों के किसी ऐसे संयोजन के रूप में परिभाषित करता है जिसका GCWR 11,794 kilograms या अधिक (26,001 pounds या अधिक) हो, बशर्ते खींचे जाने वाले वाहन(नों) का GVWR 4,536 kg (10,000 lb) से अधिक हो। स्रोत: ALEA Driver License Division, CDL classes/endorsements पृष्ठ और Alabama CDL Manual।"},"21":{"q":"Alabama नियमों के अंतर्गत, कौन सा CDL वर्ग 26,001 pounds या अधिक GVWR वाले एकल वाहन को, या ऐसे वाहन जो 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींच रहा हो, को कवर करता है?","options":["Class A","Class C","Class B","Class D"],"explanation":"Alabama, Class B को किसी ऐसे एकल वाहन के रूप में परिभाषित करता है जिसका GVWR 11,794 kg या अधिक (26,001 lb या अधिक) हो, या कोई ऐसा वाहन जो 4,536 kg (10,000 lb) GVWR से अधिक न होने वाले वाहन को खींच रहा हो। स्रोत: ALEA CDL classes/endorsements पृष्ठ और Alabama CDL Manual।"},"22":{"q":"एक वाहन जो Class A या Class B भार सीमाओं को पूरा नहीं करता परंतु 16 या अधिक यात्रियों (चालक सहित) को ढोने के लिए डिज़ाइन किया गया हो, या जो placarded खतरनाक सामग्री ढोता हो, उसके लिए कौन सा Alabama CDL वर्ग आवश्यक है?","options":["Class C","Class B","Class A","Class M"],"explanation":"Alabama Class C कोई भी वाहन (या संयोजन) है जो Class A या B परिभाषा को पूरा नहीं करता परंतु चालक सहित 16 या अधिक यात्रियों के परिवहन के लिए डिज़ाइन किया गया हो, या 49 CFR part 172 subpart F के अंतर्गत placarding की आवश्यकता वाली खतरनाक सामग्री के परिवहन के लिए प्रयुक्त हो। स्रोत: ALEA CDL classes/endorsements पृष्ठ।"},"23":{"q":"Alabama में passenger या school bus endorsement और उपयुक्त CDL की आवश्यकता उत्पन्न होने से पहले किसी वाहन को कितने यात्रियों (चालक सहित) को ढोने के लिए डिज़ाइन किया जाना चाहिए?","options":["12 या अधिक","24 या अधिक","16 या अधिक","20 या अधिक"],"explanation":"Alabama (संघीय मानक का पालन करते हुए) Class C परिभाषा के लिए और passenger/school bus endorsement उद्देश्यों के लिए सीमा को चालक सहित 16 या अधिक यात्रियों पर निर्धारित करता है। स्रोत: ALEA CDL classes/endorsements पृष्ठ; Alabama CDL Manual।"},"24":{"q":"Alabama CDL पर, कौन सा endorsement code चालक को tank vehicle संचालित करने के लिए अधिकृत करता है?","options":["T","N","H","X"],"explanation":"Alabama संघीय endorsement codes का उपयोग करता है: N, Tank Vehicle (Tanker) endorsement है। स्रोत: ALEA CDL classes/endorsements पृष्ठ; Alabama CDL Manual।"},"25":{"q":"Alabama CDL पर 'T' endorsement किसके लिए अधिकृत करता है?","options":["खतरनाक सामग्री का परिवहन","एक tank vehicle चलाना","double और triple trailers संचालित करना","एक tow truck संचालित करना"],"explanation":"Alabama में, T endorsement double/triple trailers के संचालन को अधिकृत करता है और इसे केवल एक knowledge test पास करके प्राप्त किया जाता है (कोई skills test नहीं)। स्रोत: ALEA CDL classes/endorsements पृष्ठ; Alabama CDL Manual।"},"26":{"q":"Alabama CDL पर, कौन सा एकल endorsement code Tank Vehicle और Hazardous Materials के संयोजन को दर्शाता है?","options":["H","N","X","P"],"explanation":"Alabama संयुक्त Tank Vehicle/Hazardous Materials endorsement के लिए code X का उपयोग करता है; अकेले H, HazMat है और अकेले N, Tanker है। स्रोत: ALEA CDL classes/endorsements पृष्ठ।"},"27":{"q":"इससे पहले कि Alabama किसी CDL पर HazMat (H) endorsement जारी कर सके, आवेदक को संघीय Transportation Security Administration (TSA) से क्या प्राप्त करना होगा?","options":["एक Medical Examiner's Certificate","एक Determination of No Security Threat","डाक द्वारा एक FMCSA प्रशिक्षण प्रमाणपत्र","knowledge test की छूट"],"explanation":"कोई भी राज्य HazMat endorsement तब तक जारी या नवीनीकृत नहीं कर सकता जब तक TSA फिंगरप्रिंटिंग और एक security threat assessment के बाद एक Determination of No Security Threat न लौटाए। Alabama को यह TSA पृष्ठभूमि जाँच और HazMat knowledge test दोनों की आवश्यकता होती है। स्रोत: TSA/49 CFR 1572; ALEA HazMat endorsement आवश्यकताएँ।"},"28":{"q":"INTRASTATE (केवल Alabama के भीतर) वाणिज्यिक ड्राइविंग के लिए Alabama CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["21","19","18","16"],"explanation":"Alabama intrastate संचालन के लिए 18 वर्ष की आयु में CDL की अनुमति देता है; interstate संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: ALEA CDL FAQ; Alabama CDL Manual।"},"29":{"q":"Alabama CDL पर राज्य की सीमाओं के पार (interstate) एक वाणिज्यिक मोटर वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18","21","19","25"],"explanation":"Alabama में interstate वाणिज्यिक ड्राइविंग (और राज्य की सीमाओं के पार खतरनाक सामग्री या placardable भार का परिवहन) के लिए 21 वर्ष की न्यूनतम आयु आवश्यक है, जो संघीय नियमों के अनुरूप है। स्रोत: ALEA CDL FAQ; 49 CFR 391.11।"},"30":{"q":"एक Commercial Learner Permit (CLP) जारी होने के बाद, CDL skills (road) test देने की अनुमति मिलने से पहले एक Alabama आवेदक को CLP को कितने समय तक धारण करना होगा?","options":["30 days","14 days","10 days","60 days"],"explanation":"Alabama द्वारा अपनाया गया संघीय कानून आवश्यक करता है कि CDL skills test दिए जाने से पहले CLP को कम से कम 14 days तक धारण किया जाए। स्रोत: ALEA CDL FAQ; 49 CFR 383.25।"},"31":{"q":"एक Alabama Commercial Learner Permit (CLP) कितने समय तक वैध रहता है, और क्या इसे नवीनीकृत किया जा सकता है?","options":["180 days, और इसे एक बार नवीनीकृत किया जा सकता है","360 days, और इसे नवीनीकृत नहीं किया जा सकता","1 year, और इसे प्रतिवर्ष नवीनीकृत किया जा सकता है","90 days, और इसे नवीनीकृत नहीं किया जा सकता"],"explanation":"एक Alabama CLP 360 days के लिए वैध होता है और इसे नवीनीकृत नहीं किया जा सकता; यदि यह समाप्त हो जाता है, तो आवेदक को सभी लिखित परीक्षाएँ फिर से देनी होंगी और एक नए CLP के लिए भुगतान करना होगा। स्रोत: ALEA CDL FAQ।"},"32":{"q":"Commercial Learner Permit या CDL के लिए आवेदन करने से पहले एक Alabama आवेदक के पास पहले से किस प्रकार का आधार चालक लाइसेंस होना चाहिए?","options":["एक वैध Alabama Class D चालक लाइसेंस","एक वैध Alabama Class M मोटरसाइकिल लाइसेंस","केवल एक learner's permit","किसी पूर्व लाइसेंस की आवश्यकता नहीं है"],"explanation":"Alabama आवेदकों से CLP या CDL के लिए आवेदन करने से पहले एक वैध Alabama Class D (नियमित) चालक लाइसेंस धारण करने की आवश्यकता रखता है। स्रोत: ALEA CDL FAQ; Document Requirements पृष्ठ।"},"33":{"q":"Alabama में वाणिज्यिक चालक लाइसेंस कौन सी एजेंसी जारी करती है?","options":["Alabama Department of Transportation (ALDOT)","काउंटी प्रोबेट कार्यालय","Alabama Law Enforcement Agency (ALEA) Driver License Division","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"Alabama में CDLs, Alabama Law Enforcement Agency (ALEA) द्वारा उसके Driver License Division के माध्यम से जारी किए जाते हैं, न कि किसी अलग DMV या ALDOT द्वारा। स्रोत: ALEA Driver License Division।"},"34":{"q":"पहली बार Alabama CDL से पहले आवश्यक Entry-Level Driver Training (ELDT) किसी ऐसे प्रदाता द्वारा प्रदान की जानी चाहिए जो कहाँ सूचीबद्ध हो?","options":["केवल ALEA approved-school सूची","FMCSA Training Provider Registry (TPR)","कोई भी निजी ट्रकिंग कंपनी","Alabama Community College System registry"],"explanation":"Feb 7, 2022 से, पहली बार के CDL आवेदकों (और कुछ upgrades/endorsements) को FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से ELDT पूरी करनी होगी, जिसे Alabama द्वारा परीक्षण की अनुमति देने से पहले समापन अपलोड करना होगा। स्रोत: ALEA CDL FAQ; 49 CFR part 380।"},"35":{"q":"Alabama में परीक्षण से पहले कौन सी CDL कार्रवाई के लिए, अपने आप में, Entry-Level Driver Training (ELDT) की आवश्यकता नहीं होती?","options":["पहली बार CDL प्राप्त करना","Class B से Class A में upgrade करना","समान वर्ग और endorsements के साथ CDL का नवीनीकरण करना","पहला HazMat (H) endorsement प्राप्त करना"],"explanation":"ELDT पहली बार के CDLs, वर्ग upgrades, और पहली बार के S, P, या H endorsements पर लागू होता है। एक साधारण नवीनीकरण जो वर्ग को upgrade नहीं करता या कोई कवर किया गया endorsement नहीं जोड़ता, ELDT की आवश्यकता उत्पन्न नहीं करता। स्रोत: 49 CFR part 380; ALEA CDL FAQ।"},"36":{"q":"एक Alabama CDL आवेदक जो interstate वाणिज्य में गाड़ी चलाता है और जिसे संघीय चिकित्सा मानकों को पूरा करना आवश्यक है, किस श्रेणी के अंतर्गत self-certify करता है?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Non-Excepted Interstate श्रेणी उन चालकों पर लागू होती है जो interstate वाणिज्य में संचालन करते हैं और जिन्हें एक वैध DOT Medical Examiner's Certificate बनाए रखना आवश्यक है। Alabama, 49 CFR 383 के अनुसार चार श्रेणियों में से एक में self-certification की आवश्यकता रखता है। स्रोत: ALEA self-certification आवश्यकताएँ; 49 CFR 383.71।"},"37":{"q":"एक Alabama CDL धारक को कितनी चिकित्सा self-certification श्रेणियों में से चुनना होगा, और किसके लिए एक वर्तमान DOT medical card रखना आवश्यक है?","options":["दो श्रेणियाँ; केवल interstate वाली को medical card की आवश्यकता है","चार श्रेणियाँ; Non-Excepted Interstate श्रेणी के लिए एक वर्तमान DOT medical card आवश्यक है","तीन श्रेणियाँ; किसी को भी medical card की आवश्यकता नहीं है","चार श्रेणियाँ; Excepted Intrastate श्रेणी के लिए एक वर्तमान DOT medical card आवश्यक है"],"explanation":"Alabama चार संघीय श्रेणियों (Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, Excepted Intrastate) का उपयोग करता है। Non-Excepted Interstate प्रमाणित करने वाले चालकों को एक FMCSA-प्रमाणित परीक्षक से DOT Medical Examiner's Certificate प्रदान करना और बनाए रखना होगा। स्रोत: ALEA self-certification; 49 CFR 383.71।"},"38":{"q":"Alabama CDL या CLP के लिए आवेदन करते समय, एक आवेदक को कौन सा दस्तावेज़ समूह प्रदान करना होगा?","options":["केवल एक Social Security card","पहचान का प्रमाण, Social Security number का प्रमाण, Alabama निवास का प्रमाण, और (यदि U.S. नागरिक नहीं है तो) वैध उपस्थिति का प्रमाण","केवल एक पासपोर्ट और दो उपयोगिता बिल","पहचान का प्रमाण और एक हाई स्कूल डिप्लोमा"],"explanation":"ALEA को पहचान का प्राथमिक प्रमाण, SSN का प्रलेखित प्रमाण, Alabama निवास का प्रमाण, और गैर-नागरिकों के लिए वैध उपस्थिति का प्रमाण आवश्यक है; एक ही दस्तावेज़ दो आवश्यकताओं के लिए नहीं गिना जा सकता। स्रोत: ALEA Document Requirements and Fees पृष्ठ।"},"39":{"q":"चूँकि 16 या अधिक यात्रियों को ढोने वाली एक school bus एक passenger vehicle भी है, इसलिए Alabama School Bus (S) endorsement के अतिरिक्त क्या आवश्यक करता है?","options":["एक अलग Class A CDL","Passenger (P) endorsement","Tanker (N) endorsement","Doubles/Triples (T) endorsement"],"explanation":"Alabama, School Bus (S) endorsement के साथ Passenger (P) endorsement आवश्यक करता है; आवेदक General Knowledge, Passenger, और School Bus knowledge परीक्षाएँ तथा एक प्रतिनिधि बस में एक skills test पास करते हैं। स्रोत: ALEA CDL classes/endorsements; Alabama CDL Manual।"},"40":{"q":"Alabama में, सबसे कम रक्त अल्कोहल सांद्रता (BAC) क्या है जो किसी वाणिज्यिक मोटर वाहन को संचालित करना अवैध बना देती है?","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"Alabama संघीय CMV मानक का पालन करता है: यदि आपका BAC 0.04% या अधिक है तो CMV संचालित करना अवैध है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51।"},"41":{"q":"Alabama के implied consent नियम के अंतर्गत, उस व्यक्ति के बारे में क्या मान लिया जाता है जो Alabama की सड़कों पर एक वाणिज्यिक मोटर वाहन चलाता है?","options":["उन्होंने अल्कोहल परीक्षण के लिए सहमति दे दी है","उन्हें एक अलग सहमति कार्ड साथ रखना होगा","वे सुनवाई के अधिकार का त्याग कर देते हैं","वे केवल तभी सहमति देते हैं जब स्पष्ट रूप से अक्षम हों"],"explanation":"Alabama CDL Manual कहता है कि यदि आप एक CMV संचालित करते हैं तो माना जाएगा कि आपने अल्कोहल परीक्षण के लिए अपनी सहमति दे दी है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; Ala. Code Title 32।"},"42":{"q":"Alabama में, किसी पहले गंभीर अपराध, जैसे CMV DUI या अल्कोहल परीक्षण से इनकार करने (जब placarded hazmat न ढोया जा रहा हो) के लिए, एक CDL धारक कितने समय के लिए CDL खो देगा?","options":["60 days","120 days","कम से कम 1 year","कम से कम 3 years"],"explanation":"एक पहला गंभीर अपराध (DUI, CMV में 0.04+ BAC, परीक्षण से इनकार, घटनास्थल छोड़ना, आदि) के परिणामस्वरूप कम से कम एक वर्ष के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51।"},"43":{"q":"Alabama में, एक चालक खतरनाक सामग्री के लिए placarded किए गए CMV को संचालित करते समय पहला गंभीर अपराध करता है। अयोग्यता कितने समय की है?","options":["कम से कम 1 year","कम से कम 2 years","कम से कम 3 years","आजीवन"],"explanation":"यदि कोई पहला गंभीर अपराध खतरनाक सामग्री के लिए placarded किए गए CMV को संचालित करते समय होता है, तो अयोग्यता एक के बजाय कम से कम तीन वर्ष की होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51।"},"44":{"q":"Alabama में, एक दूसरे गंभीर अपराध (जैसे एक दूसरा CMV DUI) के लिए अयोग्यता क्या है?","options":["1 year","3 years","10 years","आजीवन"],"explanation":"एक दूसरे गंभीर अपराध के परिणामस्वरूप जीवन भर के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51।"},"45":{"q":"Alabama में, एक CMV संचालित करते समय अल्कोहल परीक्षण कराने से इनकार करना किस प्रकार के उल्लंघन के रूप में माना जाता है?","options":["एक गंभीर यातायात उल्लंघन (60-day नियम)","एक गंभीर अपराध (कम से कम 1-year हानि)","केवल जुर्माने के साथ एक मामूली उल्लंघन","एक out-of-service order उल्लंघन"],"explanation":"रक्त अल्कोहल परीक्षण कराने से इनकार करना Alabama में एक गंभीर अपराध के रूप में सूचीबद्ध है, जो पहले अपराध के लिए कम से कम एक वर्ष की अयोग्यता वहन करता है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51।"},"46":{"q":"Alabama CDL Manual में निम्नलिखित में से किसे एक गंभीर (SERIOUS) यातायात उल्लंघन के रूप में सूचीबद्ध किया गया है?","options":["सीमा से 5 mph अधिक गाड़ी चलाना","अत्यधिक तेज़ गति (पोस्ट की गई सीमा से 15 mph या अधिक)","एक समाप्त पंजीकरण स्टिकर","एक जली हुई taillight"],"explanation":"गंभीर यातायात उल्लंघनों में अत्यधिक तेज़ गति शामिल है, जिसे पोस्ट की गई सीमा से 15 mph या अधिक के रूप में परिभाषित किया गया है, साथ ही लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, और बहुत करीब से पीछा करना। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.3।"},"47":{"q":"Alabama में, एक CDL धारक को तीन वर्ष की अवधि के भीतर एक CMV में दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता क्या है?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"तीन वर्ष की अवधि के भीतर एक CMV में दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 60 days के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51।"},"48":{"q":"Alabama में, एक CDL धारक को तीन वर्ष की अवधि के भीतर एक CMV में तीन गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता क्या है?","options":["कम से कम 60 days","कम से कम 90 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"तीन वर्ष की अवधि के भीतर एक CMV में तीन या अधिक गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 120 days के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.3; 49 CFR 383.51।"},"49":{"q":"Alabama में, एक out-of-service order के पहले उल्लंघन के लिए अयोग्यता क्या है?","options":["कम से कम 30 days","कम से कम 90 days","कम से कम 180 days","कम से कम 1 year"],"explanation":"एक out-of-service order के पहले उल्लंघन के परिणामस्वरूप कम से कम 90 days के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51।"},"50":{"q":"Alabama में, एक चालक दस वर्ष की अवधि के भीतर दो out-of-service order उल्लंघन करता है। अयोग्यता क्या है?","options":["कम से कम 120 days","कम से कम 1 year","कम से कम 3 years","कम से कम 5 years"],"explanation":"दस वर्ष की अवधि के भीतर दो out-of-service order उल्लंघनों के परिणामस्वरूप कम से कम एक वर्ष के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51।"},"51":{"q":"Alabama में, एक चालक दस वर्ष की अवधि के भीतर तीन या अधिक out-of-service order उल्लंघन करता है। अयोग्यता क्या है?","options":["कम से कम 1 year","कम से कम 2 years","कम से कम 3 years","आजीवन"],"explanation":"दस वर्ष की अवधि के भीतर तीन या अधिक out-of-service order उल्लंघनों के परिणामस्वरूप कम से कम तीन वर्ष के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.4; 49 CFR 383.51।"},"52":{"q":"Alabama में, एक CMV में पहले railroad-highway grade crossing उल्लंघन के लिए अयोग्यता क्या है?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"एक पहले railroad-highway grade crossing उल्लंघन के परिणामस्वरूप कम से कम 60 days के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51।"},"53":{"q":"Alabama में, एक CDL धारक को तीन वर्ष की अवधि के भीतर एक दूसरा railroad-highway grade crossing उल्लंघन मिलता है। अयोग्यता क्या है?","options":["कम से कम 60 days","कम से कम 120 days","कम से कम 6 months","कम से कम 1 year"],"explanation":"तीन वर्ष की अवधि के भीतर एक दूसरे railroad-highway grade crossing उल्लंघन के परिणामस्वरूप कम से कम 120 days के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51।"},"54":{"q":"Alabama में, एक CDL धारक को तीन वर्ष की अवधि के भीतर एक तीसरा railroad-highway grade crossing उल्लंघन मिलता है। अयोग्यता क्या है?","options":["कम से कम 120 days","कम से कम 180 days","कम से कम 1 year","कम से कम 3 years"],"explanation":"तीन वर्ष की अवधि के भीतर एक तीसरे railroad-highway grade crossing उल्लंघन के परिणामस्वरूप कम से कम एक वर्ष के लिए CDL की हानि होती है। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.5; 49 CFR 383.51।"},"55":{"q":"Alabama में, यदि किसी CMV चालक के पास अल्कोहल की कोई भी पता लगाने योग्य मात्रा पाई जाती है जो अभी भी 0.04% से कम है, तो क्या होता है?","options":["कुछ नहीं, यह कानूनी सीमा के अंदर है","24 घंटे के लिए out-of-service","तत्काल 1-year अयोग्यता","एक आजीवन प्रतिबंध"],"explanation":"0.04% से कम अल्कोहल की किसी भी पता लगाने योग्य मात्रा वाले एक CMV चालक को 24 घंटे के लिए out-of-service रखा जाएगा। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2।"},"56":{"q":"Alabama में, एक CMV चलाते समय हाथ में पकड़े जाने वाले मोबाइल फोन के उपयोग के लिए कितनी दोषसिद्धियों के बाद एक चालक का CDL अयोग्य हो जाता है?","options":["एक दोषसिद्धि","दो या अधिक दोषसिद्धियाँ","चार या अधिक दोषसिद्धियाँ","छह या अधिक दोषसिद्धियाँ"],"explanation":"एक CMV संचालित करते समय हाथ में पकड़े जाने वाले मोबाइल फोन के उपयोग पर राज्य कानून की दो या अधिक दोषसिद्धियों के बाद एक CDL अयोग्य हो जाता है: 3 वर्ष के भीतर दूसरे अपराध के लिए 60 days और 3 वर्ष के भीतर तीन या अधिक के लिए 120 days। स्रोत: Alabama CDL Manual (ALEA), Section 2.9.4।"},"57":{"q":"Alabama CDL Manual के नियमों के अंतर्गत, एक CMV चलाते समय texting प्रतिबंधित है। चालक की दोषसिद्धियाँ किस राशि तक का civil penalty वहन कर सकती हैं?","options":["$500 तक","$1,000 तक","$2,750 तक","$11,000 तक"],"explanation":"एक CMV चालक द्वारा प्रत्येक texting या हाथ में पकड़े जाने वाले फोन के उल्लंघन पर $2,750 तक का civil penalty लगता है (नियोक्ताओं पर $11,000 तक जुर्माना लग सकता है)। स्रोत: Alabama CDL Manual (ALEA), Sections 2.9.4 and 2.9.5; 49 CFR 392।"},"58":{"q":"Alabama में, नियंत्रित पदार्थों से जुड़े किसी अपराध (felony) को करने के लिए एक CMV का उपयोग करने पर क्या दंड होता है?","options":["एक 60-day अयोग्यता","एक 1-year अयोग्यता","एक 3-year अयोग्यता","जीवन भर के लिए CDL की हानि"],"explanation":"नियंत्रित पदार्थों से जुड़े किसी felony को करने के लिए एक CMV का उपयोग करने पर जीवन भर के लिए CDL की हानि होती है, जिसमें कोई पुनर्बहाली नहीं होती। स्रोत: Alabama CDL Manual (ALEA), Section 1.3.2; 49 CFR 383.51।"},"59":{"q":"Alabama CDL Manual के अंतर्गत इनमें से कौन सा एक गंभीर अपराध के बजाय एक गंभीर यातायात उल्लंघन (SERIOUS traffic violation) है?","options":["0.04% BAC के साथ एक CMV चलाना","एक रासायनिक अल्कोहल परीक्षण से इनकार करना","किसी वाहन का बहुत करीब से पीछा करना","एक दुर्घटना के घटनास्थल को छोड़ना"],"explanation":"किसी वाहन का बहुत करीब से पीछा करना एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध है (जो 60/120-day नियम की ओर गिना जाता है), जबकि DUI, परीक्षण से इनकार, और घटनास्थल छोड़ना गंभीर अपराध हैं जो कम से कम एक वर्ष की अयोग्यता वहन करते हैं। स्रोत: Alabama CDL Manual (ALEA), Sections 1.3.2 and 1.3.3।"},"60":{"q":"जब अलबामा में प्लेकार्ड लगे खतरनाक-सामग्री वाहन को रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग पर रुकना पड़े, तो चालक को सबसे नज़दीकी रेल से कितनी दूरी पर रुकना चाहिए?","options":["10 feet से कम नहीं और 25 feet से अधिक नहीं","15 feet से कम नहीं और 50 feet से अधिक नहीं","25 feet से कम नहीं और 75 feet से अधिक नहीं","5 feet से कम नहीं और 15 feet से अधिक नहीं"],"explanation":"अलबामा में प्लेकार्ड लगे HazMat वाहन को सबसे नज़दीकी रेल से 15 से 50 feet पहले रुकना आवश्यक है, फिर तभी आगे बढ़ना है जब कोई ट्रेन नहीं आ रही हो और वह बिना रुके पटरियों को पार कर सके। स्रोत: Alabama (ALEA) CDL Manual, Section 9.6 Railroad Crossings; Ala. Code 32-5A-150।"},"61":{"q":"अलबामा के Move Over Act के तहत, जब किसी बहु-लेन राजमार्ग पर कोई चालक चमकती रोशनी दिखा रहे रुके हुए आपातकालीन या कानून प्रवर्तन वाहन के सबसे नज़दीकी लेन को सुरक्षित रूप से खाली नहीं कर सकता, तो चालक को क्या करना चाहिए?","options":["गति को निर्धारित गति सीमा से कम से कम 10 mph नीचे धीमा करें","गति को निर्धारित गति सीमा से कम से कम 20 mph नीचे धीमा करें","जब तक आपातकालीन वाहन चला न जाए तब तक पूरी तरह रुक जाएँ","गति को निर्धारित गति सीमा से कम से कम 15 mph नीचे धीमा करें"],"explanation":"अलबामा के Move Over Act के तहत, जो चालक सुरक्षित रूप से लेन नहीं बदल सकता उसे निर्धारित गति सीमा से कम से कम 15 mph कम गति पर धीमा होना चाहिए। स्रोत: Ala. Code 32-5A-58.2 (Moving Over or Reducing Speed When Approaching Emergency Vehicles)।"},"62":{"q":"अलबामा में किसी इंटरस्टेट राजमार्ग पर अधिकतम गति सीमा क्या है (जब तक अन्यथा निर्दिष्ट या अधिकृत न हो)?","options":["65 mph","75 mph","80 mph","70 mph"],"explanation":"अलबामा कानून इंटरस्टेट राजमार्गों पर अधिकतम गति 70 mph निर्धारित करता है; चार या अधिक लेन वाले अन्य राजमार्गों पर अधिकतम 65 mph है। स्रोत: Ala. Code 32-5A-171 (Maximum Limits)।"},"63":{"q":"अलबामा में, यदि किसी वाणिज्यिक वाहन को एकतरफ़ा या विभाजित राजमार्ग पर रुकना पड़े, तो तीन आपातकालीन चेतावनी उपकरण कहाँ रखे जाने चाहिए?","options":["आती हुई यातायात की ओर 10 feet, 50 feet, और 150 feet पर","आती हुई यातायात की ओर 25 feet, 100 feet, और 250 feet पर","आती हुई यातायात की ओर 10 feet, 100 feet, और 200 feet पर","आती हुई यातायात की ओर 5 feet, 75 feet, और 100 feet पर"],"explanation":"एकतरफ़ा या विभाजित राजमार्ग पर, अलबामा निर्देश देता है कि चेतावनी उपकरण आती हुई यातायात की ओर 10 feet, 100 feet, और 200 feet पर रखे जाएँ। स्रोत: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices for Stopped Vehicles।"},"64":{"q":"अलबामा के स्कूल बस कानून के तहत, जब अपने दृश्य संकेत चालू रखे हुए रुकी एक स्कूल बस के सामने आते या उससे आगे निकलते वाहन के चालक को कब पूरी तरह रुकना चाहिए?","options":["केवल बस के पीछे से आते समय, कभी सामने से नहीं","केवल जब बस चालक के समान सड़क की ओर हो","केवल यदि सड़क पर बच्चे स्पष्ट रूप से मौजूद हों","किसी सामान्य दो-लेन या अविभाजित सड़क पर किसी भी दिशा से आते समय"],"explanation":"अलबामा में किसी भी दिशा से स्कूल बस के सामने आते या उससे आगे निकलते चालक को रुकना आवश्यक है, जब बस अपने दृश्य संकेत चालू रखकर बच्चों को चढ़ाने या उतारने के लिए रुकी हो, सिवाय किसी विभाजित राजमार्ग के जैसा कि क़ानून में परिभाषित है। स्रोत: Ala. Code 32-5A-154।"},"65":{"q":"कौन-सी स्थिति बच्चों को चढ़ाने या उतारने के लिए रुकी हुई स्कूल बस के लिए रुकने में अलबामा के एकमात्र अपवाद का वर्णन करती है?","options":["30 mph या उससे कम की निर्धारित गति सीमा वाले किसी भी शहर में गाड़ी चलाना","जब भी चालक बस से 100 feet से अधिक दूर हो","किसी विभाजित राजमार्ग की विपरीत सड़क से बस के सामने आना जो दो या अधिक विरोधी लेनों में अलग की गई हो","कोई भी चार-लेन सड़क, चाहे विभाजित हो या नहीं"],"explanation":"अलबामा किसी चालक को रुकने से केवल तभी छूट देता है जब वह किसी विभाजित राजमार्ग की विपरीत सड़क पर रुकी स्कूल बस के सामने आए, जिसमें चार या अधिक लेनें हों और जो कम से कम दो लेन यातायात को विपरीत दिशाओं में चलने की अनुमति देती हो। किसी अविभाजित बहु-लेन सड़क पर, सभी चालकों को फिर भी रुकना होगा। स्रोत: Ala. Code 32-5A-154।"},"66":{"q":"अलबामा में यात्रियों को ले जाने वाली बस को रेलमार्ग-राजमार्ग क्रॉसिंग पर सबसे नज़दीकी रेल से कितनी दूरी पर रुकना चाहिए?","options":["10 और 40 feet के बीच","20 और 60 feet के बीच","5 और 25 feet के बीच","15 और 50 feet के बीच"],"explanation":"अलबामा में यात्री ले जाने वाली बस को सबसे नज़दीकी रेल से 15 और 50 feet पहले रुकना आवश्यक है, दोनों दिशाओं में सुनना और देखना है, फिर तभी पार करना है जब यह पटरियों पर रुके बिना किया जा सके। स्रोत: Alabama (ALEA) CDL Manual, Section 4.3.5 Railroad-Highway Crossing Stops।"},"67":{"q":"दोनों दिशाओं में यातायात ले जाने वाली किसी दो-लेन अलबामा सड़क पर, जब कोई CMV रुका हो तो चेतावनी उपकरण कहाँ रखे जाते हैं?","options":["वाहन के 10 feet के भीतर, और 200 feet आगे और 200 feet पीछे","वाहन के 25 feet के भीतर, और 150 feet आगे और पीछे","तीनों केवल वाहन के 100 feet पीछे रखे जाते हैं","वाहन के 10 feet के भीतर, और 100 feet आगे और 100 feet पीछे"],"explanation":"दोनों दिशाओं में यातायात ले जाने वाली दो-लेन सड़क पर, अलबामा निर्देश देता है कि एक उपकरण वाहन के 10 feet के भीतर और एक 100 feet पीछे और एक 100 feet आगे, कंधे पर या लेन में रखा जाए। स्रोत: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices।"},"68":{"q":"अलबामा के Move Over Act के उल्लंघन के लिए जुर्माना क्या है?","options":["$100","$500","$200","$50"],"explanation":"अलबामा के Move Over कानून का उल्लंघन एक दुष्कर्म है जो दो सौ डॉलर ($200) के जुर्माने से दंडनीय है। स्रोत: Ala. Code 32-5A-58.2।"},"69":{"q":"कानून प्रवर्तन और आपातकालीन वाहनों के अलावा, चेतावनी/चमकती रोशनी दिखा रहे इनमें से कौन-से रुके हुए वाहन भी अलबामा की Move Over आवश्यकताओं को सक्रिय करते हैं?","options":["एक कचरा, अपशिष्ट, मलबा, या पुनर्चक्रण संग्रह वाहन","खतरे की बत्तियाँ चालू किए हुए कोई भी निजी स्वामित्व वाली यात्री कार","बच्चों को चढ़ाने वाली एक स्कूल बस","किसी शहर की सड़क पर दोहरी-पार्क की गई एक डिलीवरी वैन"],"explanation":"अलबामा ने Move Over Act का विस्तार कर wreckers, उपयोगिता सेवा वाहनों, रखरखाव/निर्माण/सर्वेक्षण वाहनों, और चमकती रोशनी दिखा रहे कचरा, अपशिष्ट, मलबा, या पुनर्चक्रण संग्रह वाहनों को शामिल किया है। स्रोत: Ala. Code 32-5A-58.2।"},"70":{"q":"अलबामा में किसी राजमार्ग (इंटरस्टेट के अलावा) पर जिसमें चार या अधिक यातायात लेनें हों, अधिकतम गति सीमा क्या है?","options":["70 mph","65 mph","60 mph","55 mph"],"explanation":"अलबामा चार या अधिक लेन वाले गैर-इंटरस्टेट राजमार्गों पर गति को 65 mph तक सीमित करता है, जबकि इंटरस्टेट को 70 mph तक सीमित किया जाता है। स्रोत: Ala. Code 32-5A-171।"},"71":{"q":"अलबामा के लेन-उपयोग नियम के तहत, यातायात की सामान्य गति से कम पर चल रहे किसी वाणिज्यिक वाहन को कहाँ चलाया जाना चाहिए?","options":["हर समय बीच की लेन में","दाहिनी ओर की लेन में, या सड़क के दाहिने किनारे के जितना संभव हो उतना पास","किसी भी लेन में, क्योंकि ट्रक लेन नियमों से छूट प्राप्त हैं","बाईं लेन में ताकि दाहिनी लेनें विलय के लिए खाली रहें"],"explanation":"अलबामा में यातायात की सामान्य गति से धीमे चल रहे किसी भी वाहन को दाहिनी ओर रखना आवश्यक है (दाहिनी ओर की लेन या जितना संभव हो उतना दाहिने किनारे के पास), सिवाय आगे निकलते, पास करते, या बाएँ मुड़ने की तैयारी करते समय के। स्रोत: Ala. Code 32-5A-80 (Driving on Right Side of Roadway)।"},"72":{"q":"यदि अलबामा में कोई रुका हुआ CMV किसी पहाड़ी या मोड़ पर हो जो आते हुए चालकों की दृष्टि को रोकता हो, तो चालक को सबसे पिछले चेतावनी उपकरण के साथ क्या करना चाहिए?","options":["इसे और पीछे ले जाएँ ताकि यातायात को कम से कम 500 feet दूर से चेतावनी मिले","रुकावट की परवाह किए बिना इसे ठीक 200 feet पीछे छोड़ दें","इसे हटा दें और केवल वाहन के चार-तरफ़ा फ़्लैशर पर निर्भर रहें","तीनों उपकरण सीधे पिछले बम्पर के पीछे रखें"],"explanation":"जब कोई पहाड़ी, मोड़, या अन्य रुकावट चालकों को वाहन को 500 feet के भीतर देखने से रोके, तो अलबामा निर्देश देता है कि सबसे पिछले त्रिकोण को सड़क पर पीछे ले जाया जाए ताकि चेतावनी रुकावट से परे प्रदान की जा सके। स्रोत: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices।"},"73":{"q":"अलबामा में रुकी हुई स्कूल बस को गैरकानूनी रूप से पास करने की पहली दोषसिद्धि के लिए जुर्माने की सीमा क्या है?","options":["$150 से कम नहीं और $300 से अधिक नहीं","$50 से कम नहीं और $100 से अधिक नहीं","$500 से कम नहीं और $1,000 से अधिक नहीं","बिना किसी सीमा के एक निश्चित $250"],"explanation":"अलबामा में रुकी हुई स्कूल बस को अवैध रूप से पास करने की पहली दोषसिद्धि पर $150 से कम नहीं और $300 से अधिक नहीं का जुर्माना लगता है, और बार-बार के अपराधों के लिए कड़े जुर्माने, सामुदायिक सेवा, और लाइसेंस निलंबन होता है। स्रोत: Ala. Code 32-5A-154।"},"74":{"q":"अलबामा में हर रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग पर किन वाहनों को पूरी तरह रुकना आवश्यक है?","options":["10,000 pounds से अधिक के सभी वाणिज्यिक वाहन बिना किसी अपवाद के","यात्रियों को ले जाने वाली बसें और खतरनाक सामग्री के लिए प्लेकार्ड लगे वाहन","केवल खाली टैंक ट्रक","केवल किसी भी प्रकार के ट्रेलर को खींचने वाले वाहन"],"explanation":"अलबामा में यात्रियों को ले जाने वाली बसों और प्लेकार्ड लगे HazMat वाहनों (भरे या खाली HazMat कार्गो टैंक और किसी भी मात्रा में क्लोरीन ले जाने वाले वाहनों सहित) को ग्रेड क्रॉसिंग पर रुकना आवश्यक है; सामान्य CMV को रुकना आवश्यक नहीं है जब तक कि परिस्थितियाँ इसकी माँग न करें। स्रोत: Alabama (ALEA) CDL Manual, Sections 2.15 and 9.6।"},"75":{"q":"अलबामा में ALDOT से ओवरसाइज़ परमिट आवश्यक होने से पहले अधिकतम कानूनी लोड की चौड़ाई क्या है?","options":["8 feet 0 inches","10 feet 0 inches","8 feet 6 inches","9 feet 6 inches"],"explanation":"अलबामा की मानक कानूनी अधिकतम लोड चौड़ाई 8 feet 6 inches (102 inches) है; इससे चौड़ी किसी भी चीज़ के लिए Alabama Department of Transportation (ALDOT) से ओवरसाइज़ परमिट आवश्यक है। स्रोत: ALDOT Oversize/Overweight Permit regulations।"},"76":{"q":"अलबामा में ओवरसाइज़ परमिट आवश्यक होने से पहले अधिकतम कानूनी लोड की ऊँचाई क्या है?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"अलबामा कानूनी अधिकतम वाहन/लोड ऊँचाई 13 feet 6 inches निर्धारित करता है; इससे अधिक के लोड के लिए ALDOT ओवरसाइज़ परमिट आवश्यक है, और 15 feet 6 inches से अधिक ऊँचाई के लिए सामने एक ऊँचाई-पोल एस्कॉर्ट आवश्यक है। स्रोत: ALDOT Oversize/Overweight Permit regulations।"},"77":{"q":"अलबामा के पहाड़ी इलाके की किसी लंबी, खड़ी ढलान पर, भगोड़े-वाहन एस्केप रैंप का उचित उद्देश्य क्या है?","options":["ढीली, नरम सामग्री की एक परत का उपयोग कर ऐसे वाहन को रोकना जिसके ब्रेक विफल हो गए हों","ट्रकों के स्वेच्छा से अपने ब्रेक ठंडा करने के लिए एक पक्का विश्राम क्षेत्र प्रदान करना","ढलान से नीचे उतरने वाले सभी CMV के लिए एक अनिवार्य निरीक्षण लेन के रूप में कार्य करना","चढ़ाई पर तेज़ वाहनों को धीमे ट्रकों से आगे निकलने देना"],"explanation":"एस्केप रैंप खड़ी ढलानों पर बनाए जाते हैं ताकि ढीली, नरम सामग्री की एक लंबी परत का उपयोग कर भगोड़े वाहनों को सुरक्षित रूप से रोका जा सके; चालकों को अपने मार्ग पर रैंप के स्थान पता होने चाहिए। अलबामा के Lookout/Sand Mountain के पास I-59 की ढलानों में ऐसे रैंप हैं। स्रोत: Alabama (ALEA) CDL Manual, Section 2.16 Mountain Driving / Escape Ramps।"},"78":{"q":"किसी सड़क या कंधे पर रुकने वाले अलबामा CMV चालक को कितने मिनटों के भीतर आवश्यक आपातकालीन चेतावनी उपकरण रखने चाहिए?","options":["10 minutes","5 minutes","15 minutes","30 minutes"],"explanation":"यदि अलबामा में किसी CMV को सड़क या कंधे पर रुकना पड़े, तो चालक को दस मिनट के भीतर आपातकालीन चेतावनी उपकरण रखने होंगे। स्रोत: Alabama (ALEA) CDL Manual, Section 2.8 Warning Devices for Stopped Vehicles।"},"79":{"q":"किसी दो-लेन अलबामा सड़क पर रुके हुए आपातकालीन वाहन के पास आते समय जहाँ हटकर जाना असंभव हो और निर्धारित सीमा 45 mph हो, तो चालक को क्या करना चाहिए?","options":["निर्धारित सीमा बनाए रखें लेकिन चार-तरफ़ा फ़्लैशर चालू करें","यात्रा लेन में पूरी तरह रुक जाएँ","लेन के भीतर जितना संभव हो उतनी दूर हटें और निर्धारित सीमा से 15 mph नीचे (30 mph) धीमा करें","निर्धारित सीमा की परवाह किए बिना ठीक 20 mph तक धीमा करें"],"explanation":"किसी दो-लेन अलबामा सड़क पर, चालक को लेन के भीतर आपातकालीन वाहन से जितना संभव हो उतनी दूर हटना चाहिए और जब वह सीमा 25 mph या अधिक हो तो निर्धारित सीमा से 15 mph नीचे धीमा होना चाहिए (यहाँ 45 - 15 = 30 mph)। स्रोत: Ala. Code 32-5A-58.2।"},"80":{"q":"अलबामा में Commercial Driver Licenses (CDLs) कौन-सी एजेंसी जारी करती है और CDL परीक्षण का प्रशासन करती है?","options":["The Alabama Department of Transportation (ALDOT)","The Alabama Law Enforcement Agency (ALEA), Driver License Division","The Alabama Department of Revenue, Motor Vehicle Division","The Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"अलबामा में CDLs को Alabama Law Enforcement Agency (ALEA), Driver License Division द्वारा जारी और परीक्षण किया जाता है। Alabama CDL Manual को ALEA द्वारा प्रकाशित किया जाता है, और ज्ञान/कौशल परीक्षण ALEA Commercial Driver License कार्यालयों में आयोजित किया जाता है। स्रोत: Alabama CDL Manual (ALEA), Introduction; ALEA Driver License Division।"},"81":{"q":"अलबामा में कोई आवेदक CDL ज्ञान या कौशल परीक्षण कैसे निर्धारित करता है?","options":["बिना अपॉइंटमेंट के किसी भी काउंटी टैग/लाइसेंस कार्यालय में जाकर","FMCSA को ऑनलाइन आवेदन करके, जो एक परीक्षण केंद्र नियुक्त करता है","ALDOT को एक लिखित अनुरोध मेल करके और एक निर्धारित तिथि की प्रतीक्षा करके","alea.gov पर ऑनलाइन शेड्यूलिंग सिस्टम के माध्यम से ALEA Commercial Driver License कार्यालय में अपॉइंटमेंट लेकर"],"explanation":"Alabama CDL Manual आवेदकों को निर्देश देता है कि वे किसी ALEA Commercial Driver License कार्यालय में ज्ञान या कौशल परीक्षण के लिए अपॉइंटमेंट लें; alea.gov पर 'Driver License' / 'Online Services' के अंतर्गत, आवेदक 'Schedule DL Appointment' का उपयोग करते हैं। स्रोत: Alabama CDL Manual (ALEA), Commercial Driver License Offices page।"},"82":{"q":"अलबामा में, पहली बार CDL कौशल परीक्षण देने की अनुमति मिलने से पहले किसी आवेदक को क्या प्राप्त करना और रखना चाहिए?","options":["एक Hazardous Materials endorsement","एक संघीय DOT चिकित्सा छूट","एक International Registration Plan (IRP) खाता","एक Commercial Learner's Permit (CLP)"],"explanation":"पहली बार या उन्नयन करने वाले CDL आवेदक को पहले आवश्यक ज्ञान परीक्षण उत्तीर्ण करके एक Commercial Learner's Permit (CLP) जारी किया जाना चाहिए। कौशल परीक्षण देने से पहले CLP को धारण किया जाना चाहिए। स्रोत: Alabama CDL Manual (ALEA), Section 1; ALEA CDL FAQ।"},"83":{"q":"अलबामा (और संघीय) नियमों के तहत, CDL कौशल परीक्षण देने से पहले एक CLP को कितने समय तक धारण किया जाना चाहिए?","options":["कम से कम 7 days","कम से कम 30 days","कम से कम 14 days","कम से कम 60 days"],"explanation":"अलबामा संघीय आवश्यकता का पालन करता है कि CDL कौशल परीक्षण देने से पहले एक CLP को न्यूनतम 14 days तक धारण किया जाए। स्रोत: ALEA CDL FAQ; अलबामा में लागू 49 CFR 383.25।"},"84":{"q":"अलबामा का Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है, और क्या इसका नवीनीकरण किया जा सकता है?","options":["180 days तक वैध और एक बार नवीनीकृत किया जा सकता है","1 year तक वैध और दो बार नवीनीकृत किया जा सकता है","30 days तक वैध और नवीनीकरण योग्य नहीं","360 days तक वैध और नवीनीकरण योग्य नहीं"],"explanation":"ALEA बताता है कि CLP 360 days तक वैध है और नवीनीकरण योग्य नहीं है; यदि यह समाप्त हो जाता है, तो आवेदक को एक नए CLP के लिए फिर से परीक्षण देना होगा। स्रोत: ALEA CDL FAQ।"},"85":{"q":"अलबामा में पहली बार CDL के लिए परीक्षण देने से पहले, किसी आवेदक को कौन-सा प्रशिक्षण पूरा करना चाहिए?","options":["अलबामा अदालतों द्वारा अनुमोदित एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक 40-hour OSHA कार्यस्थल-सुरक्षा पाठ्यक्रम","किसी FMCSA-पंजीकृत प्रदाता के माध्यम से Entry-Level Driver Training (ELDT)","एक ALEA-प्रशासित कक्षा पाठ्यक्रम जो केवल Montgomery कार्यालय में आयोजित होता है"],"explanation":"पहली बार CDL प्राप्त करने वाले किसी भी व्यक्ति के लिए (और कुछ उन्नयनों/एंडोर्समेंट के लिए) Entry-Level Driver Training (ELDT) आवश्यक है। परीक्षण से पहले प्रशिक्षण को FMCSA Training Provider Registry में सूचीबद्ध एक प्रदाता के माध्यम से पूरा किया जाना चाहिए। स्रोत: ALEA CDL Self-Certification/FAQ materials; FMCSA ELDT rule effective Feb. 7, 2022।"},"86":{"q":"वाहन वर्ग या एंडोर्समेंट की परवाह किए बिना, हर अलबामा CDL आवेदक को कौन-सा ज्ञान परीक्षण उत्तीर्ण करना चाहिए?","options":["एयर ब्रेक परीक्षण","संयोजन वाहन परीक्षण","खतरनाक सामग्री परीक्षण","सामान्य ज्ञान परीक्षण"],"explanation":"Alabama CDL Manual सामान्य ज्ञान परीक्षण को उस परीक्षण के रूप में सूचीबद्ध करता है जो सभी आवेदकों द्वारा लिया जाता है; अन्य ज्ञान परीक्षण (एयर ब्रेक, संयोजन, यात्री, hazmat, टैंक, doubles/triples, स्कूल बस) वर्ग और माँगे गए एंडोर्समेंट पर निर्भर करते हैं। स्रोत: Alabama CDL Manual (ALEA), Section 1.1.1 Knowledge Tests।"},"87":{"q":"Alabama CDL Manual के अनुसार, CDL कौशल परीक्षण में कौन-से तीन खंड होते हैं?","options":["लिखित परीक्षा, नेत्र परीक्षा, और सड़क परीक्षण","कपलिंग/अनकपलिंग, बैकिंग, और एयर-ब्रेक जाँच","Pre-trip, रक्षात्मक ड्राइविंग, और रात्रि ड्राइविंग","वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग"],"explanation":"मैनुअल बताता है कि CDL कौशल परीक्षण में तीन खंड होते हैं: वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग। स्रोत: Alabama CDL Manual (ALEA), Section 1.1.2 Skills Tests।"},"88":{"q":"अलबामा में तीन CDL कौशल-परीक्षण खंडों को किस क्रम में लिया जाना चाहिए?","options":["परीक्षण के दिन आवेदक जो भी क्रम चुने उसमें","पहले सड़क पर, फिर बुनियादी नियंत्रण, फिर वाहन निरीक्षण","सूचीबद्ध क्रम में (वाहन निरीक्षण, फिर बुनियादी वाहन नियंत्रण, फिर सड़क पर), अगले पर जाने से पहले प्रत्येक को उत्तीर्ण करते हुए","पहले बुनियादी वाहन नियंत्रण, फिर सड़क पर, फिर वाहन निरीक्षण"],"explanation":"Alabama CDL Manual बताता है: 'आपको खंडों को सूचीबद्ध क्रम में लेना चाहिए और अगले पर जाने से पहले प्रत्येक को उत्तीर्ण करना चाहिए' — वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, फिर सड़क पर ड्राइविंग। स्रोत: Alabama CDL Manual (ALEA), Section 1.1.2।"},"89":{"q":"अलबामा CDL कौशल परीक्षण देने के लिए किसी आवेदक को किस प्रकार का वाहन उपयोग करना चाहिए?","options":["उस वर्ग/प्रकार का प्रतिनिधि वाहन जिसके लिए आवेदक लाइसेंस प्राप्त करना चाहता है","कोई भी यात्री कार, क्योंकि केवल ड्राइविंग आदतों का मूल्यांकन किया जाता है","ALEA परीक्षण स्थल द्वारा निःशुल्क प्रदान किया गया एक वाहन","कोई भी वाणिज्यिक वाहन, वर्ग की परवाह किए बिना, जब तक उसमें एयर ब्रेक हों"],"explanation":"मैनुअल आवश्यक करता है कि कौशल परीक्षण उस प्रकार के वाहन में दिया जाए जिसके लिए आवेदक लाइसेंस प्राप्त करना चाहता है; उपयोग किए गए वाहन का वर्ग जारी किए गए CDL को सीमित कर सकता है। चिह्नित या लेबल वाले घटकों वाले वाहन का उपयोग नहीं किया जा सकता। स्रोत: Alabama CDL Manual (ALEA), Section 1.1.2।"},"90":{"q":"अलबामा CDL वाहन-निरीक्षण कौशल परीक्षण के दौरान, आवेदक को प्रत्येक वस्तु पर क्या करना आवश्यक है?","options":["प्रत्येक वस्तु का चुपचाप निरीक्षण करना जबकि परीक्षक प्रक्रिया का समय मापता है","वस्तु की ओर इशारा करना या उसे छूना और उसका नाम बताना, और परीक्षक को समझाना कि क्या निरीक्षण किया जा रहा है और क्यों","एक निरीक्षण फ़ॉर्म पर प्रत्येक वस्तु का विवरण लिखना","वस्तुओं को छुए या इशारा किए बिना केवल मौखिक रूप से सूचीबद्ध करना"],"explanation":"मैनुअल बताता है कि Vehicle Inspection परीक्षण के दौरान आपको जिस वस्तु का निरीक्षण कर रहे हैं उसकी ओर इशारा करना/उसे छूना और नाम बताना चाहिए और परीक्षक को समझाना चाहिए कि आप क्या निरीक्षण कर रहे हैं और क्यों। स्रोत: Alabama CDL Manual (ALEA), Section 1.1.2, Vehicle Inspection।"},"91":{"q":"अलबामा CDL कौशल परीक्षण का बुनियादी वाहन नियंत्रण भाग किसका मूल्यांकन करता है?","options":["खतरनाक-सामग्री प्लेकार्डिंग नियमों का ज्ञान","वाहन को आगे, पीछे ले जाने और एक निर्धारित क्षेत्र के भीतर मोड़ने का कौशल","राजमार्ग संकेतों को पढ़ने और व्याख्या करने की क्षमता","एक दैनिक चालक लॉग पूरा करने की क्षमता"],"explanation":"बुनियादी वाहन नियंत्रण परीक्षण वाहन को नियंत्रित करने में आवेदक के कौशल को मापता है — इसे आगे, पीछे ले जाना और एक निर्धारित, चिह्नित क्षेत्र के भीतर मोड़ना, जहाँ परीक्षक बताता है कि प्रत्येक अभ्यास कैसे किया जाना है। स्रोत: Alabama CDL Manual (ALEA), Section 1.1.2, Basic Vehicle Control।"},"92":{"q":"अलबामा CDL आवेदक को आवेदन करते समय अपने Social Security नंबर के प्रमाण के रूप में आमतौर पर कौन-सा दस्तावेज़ प्रदान करना होता है?","options":["आवेदक के Social Security नंबर का प्रमाण (उदा., Social Security कार्ड)","केवल किसी वर्तमान नियोक्ता से एक नोटरीकृत हलफनामा","केवल आवेदक के सबसे हालिया संघीय कर रिटर्न की एक प्रति","एक मोटर-कैरियर DOT नंबर नियुक्ति पत्र"],"explanation":"अलबामा CDL आवेदकों को पहचान/निवास के आवश्यक प्रमाण और एक वैध Alabama (Class D) चालक लाइसेंस के साथ अपने Social Security नंबर का प्रमाण प्रस्तुत करना चाहिए। स्रोत: ALEA Driver License Division document requirements; ALEA CDL application materials।"},"93":{"q":"अलबामा में अपनाए गए संघीय नियमों के अनुसार Class A, B, या C वाहनों के CDL धारकों को वाणिज्यिक संचालन की कितनी श्रेणियों में से चुनकर स्व-प्रमाणन करना आवश्यक है?","options":["चार","दो","तीन","पाँच"],"explanation":"अलबामा का CDL Self-Certification Affidavit चालक को संचालन की चार श्रेणियों में से एक को प्रमाणित करना आवश्यक करता है। स्रोत: ALEA CDL Self-Certification Affidavit (cites 49 CFR 383, 384, 390, 391); Alabama CDL Manual Section 1.2।"},"94":{"q":"Alabama CDL Self-Certification Affidavit पर, चार श्रेणियों में से कौन-सी एक श्रेणी चालक को एक DOT चिकित्सा परीक्षक का प्रमाणपत्र रखने और प्रस्तुत करने के लिए आवश्यक करती है?","options":["Excepted Interstate","Non-excepted Interstate","Excepted Intrastate","Non-excepted Intrastate (अलबामा चिकित्सा छूट K प्रतिबंध के साथ)"],"explanation":"अलबामा हलफनामा चार श्रेणियाँ सूचीबद्ध करता है: Non-excepted Interstate (49 CFR part 391 के अधीन — DOT चिकित्सा प्रमाणपत्र आवश्यक), Excepted Interstate, Non-excepted Intrastate, और Excepted Intrastate। केवल Non-excepted Interstate को एक DOT चिकित्सा कार्ड रखने/प्रस्तुत करने की आवश्यकता है; अन्य तीन केवल हलफनामा प्रस्तुत करते हैं। स्रोत: ALEA CDL Self-Certification Affidavit।"},"95":{"q":"Alabama CDL Manual के अनुसार, यदि कोई चालक अंतरराज्यीय और राज्य-आंतरिक दोनों वाणिज्य में संचालन करता है, तो उसे कौन-सा स्व-प्रमाणन दर्जा चुनना चाहिए?","options":["Intrastate commerce","Excepted intrastate commerce","Interstate commerce","जो भी वे सबसे अधिक बार करते हैं"],"explanation":"मैनुअल बताता है कि यदि आप राज्य-आंतरिक और अंतरराज्यीय दोनों वाणिज्य में संचालन करते हैं, तो स्व-प्रमाणन करते समय आपको interstate commerce चुनना चाहिए। स्रोत: Alabama CDL Manual (ALEA), Section 1.2.1।"},"96":{"q":"June 23, 2025 से प्रभावी परिवर्तन के अनुसार, किसी अलबामा CDL धारक का DOT चिकित्सा परीक्षक प्रमाणपत्र सामान्य रूप से ALEA को कैसे प्रेषित किया जाता है?","options":["चालक को मूल कागज़ी कार्ड को काउंटी प्रोबेट कार्यालय में मेल करना चाहिए","प्रमाणित चिकित्सा परीक्षक इसे इलेक्ट्रॉनिक रूप से FMCSA को प्रस्तुत करता है, जो इसे चालक के रिकॉर्ड के राज्य को प्रेषित करता है","चालक ALDOT permit पोर्टल पर एक स्कैन किया हुआ कागज़ी कार्ड अपलोड करता है","ALDOT निरीक्षक वज़न स्टेशनों पर कार्ड एकत्र करते हैं और इसे ALEA को अग्रेषित करते हैं"],"explanation":"June 23, 2025 से प्रभावी, ALEA केवल इलेक्ट्रॉनिक रूप से DOT चिकित्सा प्रमाणन स्वीकार करता है: FMCSA-प्रमाणित चिकित्सा परीक्षक परिणाम इलेक्ट्रॉनिक रूप से FMCSA को प्रस्तुत करता है, जो इसे चालक के रिकॉर्ड के राज्य को अग्रेषित करता है। कागज़ी कार्ड और स्व-अपलोड अब स्वीकार नहीं किए जाते; चालक alabamadl.alea.gov पर अपना रिकॉर्ड सत्यापित करते हैं। स्रोत: ALEA news release 'Big Changes for Alabama CDL Holders'; ALEA CDL FAQ।"},"97":{"q":"यदि कोई Non-excepted Interstate अलबामा CDL धारक एक वर्तमान 'certified' चिकित्सा दर्जा फ़ाइल पर रखने में विफल रहता है, तो इसका परिणाम क्या होता है?","options":["वे 'not-certified' हो जाते हैं और अपना CDL खो सकते हैं","उनका CDL स्वचालित रूप से 90 days के लिए एक CLP में अवनत हो जाता है","उन्हें बिना किसी लाइसेंस प्रभाव के एक बार की लिखित चेतावनी मिलती है","कुछ नहीं, क्योंकि चिकित्सा कार्ड CDL धारकों के लिए वैकल्पिक है"],"explanation":"Alabama CDL Manual चेतावनी देता है कि एक चालक जिसके लिए 'certified' चिकित्सा दर्जा आवश्यक है और जो इसे प्रदान करने और अद्यतित रखने में विफल रहता है, वह 'not-certified' हो जाता है और अपना CDL खो सकता है (CDL को अवनत/रद्द किया जा सकता है)। स्रोत: Alabama CDL Manual (ALEA), Section 1.2 Medical Documentation Requirements।"},"98":{"q":"अलबामा में, वाणिज्यिक लाइसेंस के नवीनीकरण के संबंध में किसी CDL धारक का स्व-प्रमाणन (और चिकित्सा कार्ड, यदि लागू हो) आम तौर पर कब फ़ाइल पर होना आवश्यक है?","options":["वाणिज्यिक चालक लाइसेंस के नवीनीकरण से 10 days से पहले प्रस्तुत किया जाए","नवीनीकृत लाइसेंस मेल किए जाने के बाद ही प्रस्तुत किया जाए","लाइसेंस समाप्त होने के 30 days के भीतर प्रस्तुत किया जाए","केवल एक बार प्रस्तुत किया जाए और फिर कभी अद्यतित नहीं किया जाए"],"explanation":"ALEA CDL Self-Certification Affidavit चालकों को निर्देश देता है कि वे वाणिज्यिक चालक लाइसेंस के नवीनीकरण से 10 days से पहले हलफनामा (और चिकित्सा कार्ड, यदि लागू हो) प्रस्तुत करें; फ़ॉर्म वापस करने में विफलता CDL रद्द होने का परिणाम दे सकती है। स्रोत: ALEA CDL Self-Certification Affidavit।"},"99":{"q":"अलबामा CDL के लिए मानक नवीनीकरण/वैधता चक्र क्या है, और यह कब समाप्त होता है?","options":["इसे हर 2 years में नवीनीकृत किया जाता है और वर्ष के अंत में समाप्त होता है","इसे हर 10 years में नवीनीकृत किया जाता है और January 1 को समाप्त होता है","इसे 8-year चक्र पर नवीनीकृत किया जाता है और चालक के जन्मदिन पर समाप्त होता है","एक बार CDL पहली बार जारी होने के बाद यह कभी समाप्त नहीं होता"],"explanation":"अलबामा चालक लाइसेंस, CDLs सहित, को 8-year चक्र पर जारी/नवीनीकृत करता है, जो चालक के जन्मदिन पर समाप्त होता है; एक CDL को समाप्ति से 180 days पहले तक नवीनीकृत किया जा सकता है और कोई छूट अवधि नहीं है। (एक Hazmat endorsement का TSA सत्यापन केवल 5 years तक चलता है।) स्रोत: ALEA Driver License Division; Alabama CDL renewal guidance।"}},"ar":{"0":{"q":"على الطرق السريعة في ألاباما التي يبلغ عرض مساراتها المرورية 12 قدمًا أو أكثر، ما هو الحد الأقصى لإجمالي العرض الخارجي للمركبة، بما في ذلك حمولتها (باستثناء المرايا وأجهزة السلامة)؟","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"يحدد قانون ألاباما 32-9-20(1) الحد الأقصى للعرض بـ 102 inches (8 feet 6 inches)، بما في ذلك الحمولة، على الطرق السريعة التي يبلغ عرض مساراتها 12 feet أو أكثر، باستثناء المرايا وأجهزة السلامة. المصدر: Alabama Code Section 32-9-20."},"1":{"q":"ما هو الحد الأقصى القانوني للارتفاع، بما في ذلك الحمولة، لمركبة أو نصف مقطورة أو مقطورة على الطرق السريعة في ألاباما؟","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"يحظر قانون ألاباما 32-9-20(2) على أي مركبة أو نصف مقطورة أو مقطورة أن يتجاوز ارتفاعها 13 1/2 feet (13 feet 6 inches)، بما في ذلك الحمولة. المصدر: Alabama Code Section 32-9-20."},"2":{"q":"في ألاباما، ما هو الحد الأقصى للوزن الإجمالي المفروض على الطريق السريع من قبل عجلات أي محور واحد (مفرد)؟","options":["18,000 pounds","20,000 pounds","22,000 pounds","24,000 pounds"],"explanation":"يحدد قانون ألاباما 32-9-20(4) وزن أي محور مفرد بـ 20,000 pounds، بما يتوافق مع المعيار الفيدرالي بموجب 23 U.S.C. 127. المصدر: Alabama Code Section 32-9-20."},"3":{"q":"ما هو الحد الأقصى المسموح به للوزن على مجموعة محاور مزدوجة (تانديم) على نظام الطرق السريعة بين الولايات في ألاباما؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","38,000 pounds"],"explanation":"يحدد قانون ألاباما 32-9-20(4) وزن المحور المزدوج على نظام الطرق السريعة بين الولايات بـ 34,000 pounds، بما في ذلك جميع هوامش التسامح في التطبيق، بما يطابق الحد الفيدرالي. المصدر: Alabama Code Section 32-9-20."},"4":{"q":"ما هو الحد الأقصى لإجمالي الوزن الكلي لمركبة أو مجموعة مركبات على نظام الطرق السريعة بين الولايات في ألاباما، بما في ذلك جميع هوامش التسامح في التطبيق؟","options":["73,280 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"يحدد قانون ألاباما 32-9-20(4) سقف الوزن الإجمالي الكلي بـ 80,000 pounds، بما في ذلك جميع هوامش التسامح في التطبيق، على نظام الطرق بين الولايات، بما يتوافق مع 23 U.S.C. 127. المصدر: Alabama Code Section 32-9-20."},"5":{"q":"ما هو الحد الأقصى لطول مركبة مفردة (مستقيمة) على الطرق السريعة في ألاباما؟","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"ينص قانون ألاباما 32-9-20(3) على أنه لا يجوز أن يتجاوز طول أي مركبة مفردة 40 feet. المصدر: Alabama Code Section 32-9-20."},"6":{"q":"في مجموعة جرار شاحنة ونصف مقطورة في ألاباما، ما هو الحد الأقصى لطول نصف المقطورة، بما في ذلك الحمولة؟","options":["48 feet","53 feet","57 feet","65 feet"],"explanation":"ينص قانون ألاباما 32-9-20(3) على أن نصف المقطورة، بما في ذلك الحمولة، المستخدمة في مجموعة جرار شاحنة ونصف مقطورة لا يجوز أن يتجاوز طولها 57 feet. المصدر: Alabama Code Section 32-9-20."},"7":{"q":"على الطرق السريعة التي يقل عرض مساراتها المرورية عن 12 feet في ألاباما، ما هو الحد الأقصى لإجمالي العرض الخارجي للمركبة، بما في ذلك الحمولة؟","options":["90 inches","96 inches","102 inches","108 inches"],"explanation":"يخفّض قانون ألاباما 32-9-20(1) الحد الأقصى للعرض إلى 96 inches، بما في ذلك الحمولة، على الطرق السريعة التي يقل عرض مساراتها المرورية عن 12 feet. المصدر: Alabama Code Section 32-9-20."},"8":{"q":"في مجموعة جرار شاحنة ونصف مقطورة ومقطورة (مقطورتان توأم) في ألاباما، ما هو الحد الأقصى لطول كل نصف مقطورة أو مقطورة، بما في ذلك الحمولة؟","options":["27 feet","28 1/2 feet","30 feet","33 feet"],"explanation":"يحدد قانون ألاباما 32-9-20(3) طول كل نصف مقطورة أو مقطورة في مجموعة جرار شاحنة ونصف مقطورة ومقطورة (توأم) بـ 28 1/2 feet، بما في ذلك الحمولة. المصدر: Alabama Code Section 32-9-20."},"9":{"q":"ما هو الحد الأقصى لطول المركبة الآلية المعروفة عادةً بالمنزل المتنقل (موتور هوم) على الطرق السريعة في ألاباما؟","options":["40 feet","45 feet","53 feet","57 feet"],"explanation":"ينص قانون ألاباما 32-9-20(3) على أن المركبات الآلية المعروفة عادةً بالمنازل المتنقلة لا يجوز أن يتجاوز طولها 45 feet. المصدر: Alabama Code Section 32-9-20."},"10":{"q":"عند نقل المنتجات الحرجية أو أنابيب المجاري على طريق سريع في ألاباما، ما هو الحد الأقصى القانوني لعرض الحمولة دون تصريح؟","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"ينص قانون ألاباما 32-9-20(1) تحديدًا على أنه لا يجوز لأي مركبة تنقل منتجات حرجية أو أنابيب مجاري على أي طريق سريع أن تحمل حمولة يتجاوز عرضها 102 inches. المصدر: Alabama Code Section 32-9-20."},"11":{"q":"يجوز لمجموعتين متتاليتين من المحاور المزدوجة في ألاباما أن تحمل كل منهما حمولة إجمالية قدرها 34,000 pounds شريطة ألا تقل المسافة بين المحور الأول والمحور الأخير من المجموعتين المتتاليتين عن كم قدمًا؟","options":["30 feet","34 feet","36 feet","41 feet"],"explanation":"يسمح قانون ألاباما 32-9-20(4) لمجموعتين متتاليتين من المحاور المزدوجة بأن تحمل كل منهما 34,000 pounds إذا كانت المسافة الإجمالية بين المحور الأول والأخير 36 feet أو أكثر، مع ألا يتجاوز الوزن الإجمالي الكلي 80,000 pounds. المصدر: Alabama Code Section 32-9-20."},"12":{"q":"ما هي المعادلة التي تطبقها ألاباما لتحديد الحد الأقصى المسموح به للوزن الإجمالي على مجموعة من محورين متتاليين أو أكثر؟","options":["معادلة الجسر الفيدرالية W = 500(LN/(N-1) + 12N + 36)","معادلة نسبة القدرة الحصانية إلى الوزن","قاعدة ثابتة قدرها 80,000-pound بصرف النظر عن التباعد","معادلة تناسب مسافة التوقف"],"explanation":"يعتمد قانون ألاباما 32-9-20(4)(c) معادلة الجسر الفيدرالية W = 500(LN/(N-1) + 12N + 36)، حيث W هو الوزن الإجمالي، وL هي المسافة بين المحاور الطرفية للمجموعة، وN هو عدد المحاور. المصدر: Alabama Code Section 32-9-20."},"13":{"q":"لأغراض تطبيق حدود وزن المحور والوزن الإجمالي، تسمح ألاباما بهامش تسامح في الموازين (في التطبيق) يُحسب بضرب الوزن المقرر في أي عامل؟","options":["0.05 (5 percent)","0.10 (10 percent)","0.15 (15 percent)","0.20 (20 percent)"],"explanation":"يسمح قانون ألاباما 32-9-20(4)(d) بهامش تسامح في الموازين/التطبيق يساوي الوزن المقرر مضروبًا في عُشر (.10)، أي 10 percent، قبل اعتبار حدوث مخالفة. المصدر: Alabama Code Section 32-9-20."},"14":{"q":"بموجب قانون ألاباما، المركبات ذات المحورين والثلاثة محاور المستخدمة حصريًا لنقل السلع الزراعية من المزرعة وإليها ليست مطالبة بالامتثال لأي متطلب؟","options":["حدود العرض والارتفاع","متطلبات المحور المفرد والوزن الإجمالي","متطلبات الإضاءة ووضع العلامات","حدود الطول للمجموعات المركبة"],"explanation":"يعفي قانون ألاباما 32-9-20(4)(j) المركبات ذات المحورين والثلاثة محاور المستخدمة حصريًا لنقل السلع الزراعية من المزرعة وإليها من متطلبات المحور المفرد الواردة في الفقرة (4)a ومتطلبات الوزن الإجمالي الواردة في الفقرة (4)c. المصدر: Alabama Code Section 32-9-20."},"15":{"q":"المركبة التي تستخدم وحدة طاقة مساعدة (APU) عاملة أو تقنية للحد من التشغيل الخامل في ألاباما يُسمح لها بكم من الوزن الإضافي فوق حدود الوزن الإجمالي أو المحور أو المحور المزدوج أو معادلة الجسر؟","options":["250 pounds","400 pounds","550 pounds","1,000 pounds"],"explanation":"يسمح قانون ألاباما 32-9-20(b)(1) بما يصل إلى 400 pounds إضافية (أو الوزن المعتمد الفعلي لوحدة الطاقة المساعدة، أيهما أقل) للمركبات التي تستخدم الطاقة المساعدة أو تقنية الحد من التشغيل الخامل، بما يعكس قانون سياسة الطاقة الفيدرالي لعام 2005. المصدر: Alabama Code Section 32-9-20."},"16":{"q":"لا يجوز للتصريح السنوي لزيادة الحجم/الوزن في ألاباما أن يجيز تشغيل مركبة يتجاوز وزنها الإجمالي الكلي أي رقم؟","options":["100,000 pounds","120,000 pounds","150,000 pounds","200,000 pounds"],"explanation":"ينص قانون ألاباما 32-9-29(b)(1) على أنه لا يجوز للتصريح السنوي أن يجيز مركبة يتجاوز وزنها الإجمالي الكلي 150,000 pounds، وأن الأوزان الإجمالية التي تزيد عن 100,000 pounds تتطلب تحديد مسار مسبق من قبل الإدارة. المصدر: Alabama Code Section 32-9-29."},"17":{"q":"بموجب تصريح سنوي في ألاباما، لا يجوز أن يتجاوز وزن المحور المفرد للمركبة المرخّص لها أي مقدار؟","options":["20,000 pounds","22,000 pounds","25,000 pounds","27,000 pounds"],"explanation":"يحدد قانون ألاباما 32-9-29(b)(1) سقف وزن المحور المفرد بموجب تصريح سنوي لزيادة الحجم/الوزن بـ 22,000 pounds، بما في ذلك جميع هوامش التسامح في التطبيق. المصدر: Alabama Code Section 32-9-29."},"18":{"q":"لا يجوز للتصريح السنوي لزيادة الحجم/الوزن في ألاباما أن يجيز مركبة يتجاوز ارتفاعها أي حد؟","options":["13 feet 6 inches","14 feet","15 feet 6 inches","16 feet"],"explanation":"ينص قانون ألاباما 32-9-29(b)(1) على أنه لا يجوز للتصريح السنوي أن يجيز تشغيل مركبة يتجاوز ارتفاعها 14 feet. المصدر: Alabama Code Section 32-9-29."},"19":{"q":"بموجب قانون ألاباما، ما هو الوضع القانوني للسلع والمعدات الزراعية والمزرعية فيما يتعلق بتصاريح زيادة الحجم/الوزن للتنقل على نظام الطرق السريعة بالولاية؟","options":["تتطلب تصريحًا سنويًا خاصًا للمزارع","معفاة من متطلب الحصول على التصاريح","تتطلب تصريح رحلة واحدة فقط","يجب أن تحصل على تصريح ولكن دون دفع رسوم"],"explanation":"ينص قانون ألاباما 32-9-29(f) على أن السلع والمعدات الزراعية والمزرعية معفاة من متطلب الحصول على تصاريح للتنقل على نظام الطرق السريعة بولاية ألاباما. المصدر: Alabama Code Section 32-9-29."},"20":{"q":"في ألاباما، تُشترط رخصة CDL من الفئة A لتشغيل أي مجموعة مركبات يبلغ تصنيف وزنها الإجمالي المركّب (GCWR) على الأقل أي قيمة، عندما يتجاوز التصنيف الإجمالي لوزن المركبة (GVWR) للوحدة المقطورة 10,000 pounds؟","options":["16,001 pounds or more","26,001 pounds or more","10,001 pounds or more","36,001 pounds or more"],"explanation":"تُعرّف ألاباما رخصة CDL من الفئة A بأنها أي مجموعة مركبات يبلغ تصنيف وزنها الإجمالي المركّب (GCWR) 11,794 kilograms أو أكثر (26,001 pounds or more)، شريطة أن يتجاوز التصنيف الإجمالي لوزن المركبة (GVWR) للمركبة (المركبات) المقطورة 4,536 kg (10,000 lb). المصدر: ALEA Driver License Division، صفحة فئات/تظهيرات CDL ودليل Alabama CDL."},"21":{"q":"بموجب قواعد ألاباما، أي فئة من رخص CDL تشمل مركبة مفردة يبلغ تصنيفها الإجمالي لوزن المركبة (GVWR) 26,001 pounds أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تصنيف وزنها الإجمالي (GVWR) 10,000 pounds؟","options":["Class A","Class C","Class B","Class D"],"explanation":"تُعرّف ألاباما الفئة B بأنها أي مركبة مفردة يبلغ تصنيفها الإجمالي لوزن المركبة (GVWR) 11,794 kg أو أكثر (26,001 lb or more)، أو أي مركبة من هذا القبيل تقطر مركبة لا يتجاوز تصنيف وزنها الإجمالي (GVWR) 4,536 kg (10,000 lb). المصدر: صفحة فئات/تظهيرات CDL لدى ALEA ودليل Alabama CDL."},"22":{"q":"المركبة التي لا تستوفي حدود الوزن للفئة A أو الفئة B ولكنها مصممة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق)، أو تنقل مواد خطرة تستوجب وضع لافتات تحذيرية، تتطلب أي فئة من رخص CDL في ألاباما؟","options":["Class C","Class B","Class A","Class M"],"explanation":"الفئة C في ألاباما هي أي مركبة (أو مجموعة) لا تستوفي تعريف الفئة A أو B ولكنها مصممة لنقل 16 راكبًا أو أكثر بمن فيهم السائق، أو تُستخدم لنقل مواد خطرة تستوجب وضع لافتات تحذيرية بموجب 49 CFR part 172 subpart F. المصدر: صفحة فئات/تظهيرات CDL لدى ALEA."},"23":{"q":"كم عدد الركاب (بمن فيهم السائق) الذي يجب أن تكون المركبة مصممة لنقله قبل أن يُشترط تظهير الركاب أو الحافلة المدرسية ورخصة CDL المناسبة في ألاباما؟","options":["12 or more","24 or more","16 or more","20 or more"],"explanation":"تضع ألاباما (تبعًا للمعيار الفيدرالي) العتبة عند 16 راكبًا أو أكثر بمن فيهم السائق لتعريف الفئة C ولأغراض تظهير الركاب/الحافلة المدرسية. المصدر: صفحة فئات/تظهيرات CDL لدى ALEA؛ دليل Alabama CDL."},"24":{"q":"على رخصة CDL في ألاباما، أي رمز تظهير يجيز للسائق تشغيل مركبة صهريجية؟","options":["T","N","H","X"],"explanation":"تستخدم ألاباما رموز التظهير الفيدرالية: N هو تظهير المركبة الصهريجية (الناقلة). المصدر: صفحة فئات/تظهيرات CDL لدى ALEA؛ دليل Alabama CDL."},"25":{"q":"ماذا يجيز تظهير 'T' على رخصة CDL في ألاباما؟","options":["نقل المواد الخطرة","قيادة مركبة صهريجية","تشغيل المقطورات المزدوجة والثلاثية","تشغيل شاحنة قطر"],"explanation":"في ألاباما، يجيز تظهير T تشغيل المقطورات المزدوجة/الثلاثية ويُحصل عليه باجتياز اختبار معرفي فقط (دون اختبار مهارات). المصدر: صفحة فئات/تظهيرات CDL لدى ALEA؛ دليل Alabama CDL."},"26":{"q":"على رخصة CDL في ألاباما، أي رمز تظهير مفرد يمثّل الجمع بين المركبة الصهريجية والمواد الخطرة معًا؟","options":["H","N","X","P"],"explanation":"تستخدم ألاباما الرمز X لتظهير المركبة الصهريجية/المواد الخطرة مجتمعًا؛ أما H وحده فهو HazMat وN وحده فهو الناقلة (الصهريجية). المصدر: صفحة فئات/تظهيرات CDL لدى ALEA."},"27":{"q":"قبل أن تتمكن ألاباما من إصدار تظهير المواد الخطرة (H) على رخصة CDL، يجب أن يحصل مقدم الطلب على ماذا من إدارة أمن النقل الفيدرالية (TSA)؟","options":["شهادة فاحص طبي","قرار بعدم وجود تهديد أمني","شهادة تدريب من FMCSA بالبريد","إعفاء من الاختبار المعرفي"],"explanation":"لا يجوز لأي ولاية أن تصدر أو تجدد تظهير المواد الخطرة ما لم تُصدر TSA قرارًا بعدم وجود تهديد أمني بعد أخذ البصمات وإجراء تقييم للتهديد الأمني. تتطلب ألاباما هذا الفحص الأمني من TSA إضافة إلى الاختبار المعرفي للمواد الخطرة. المصدر: TSA/49 CFR 1572؛ متطلبات تظهير HazMat لدى ALEA."},"28":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ألاباما للقيادة التجارية داخل الولاية (داخل ألاباما فقط)؟","options":["21","19","18","16"],"explanation":"تسمح ألاباما برخصة CDL في سن 18 للتشغيل داخل الولاية؛ أما التشغيل بين الولايات فيتطلب سن 21. المصدر: الأسئلة الشائعة عن CDL لدى ALEA؛ دليل Alabama CDL."},"29":{"q":"ما هو الحد الأدنى للعمر المطلوب لقيادة مركبة تجارية آلية عبر حدود الولايات (بين الولايات) برخصة CDL من ألاباما؟","options":["18","21","19","25"],"explanation":"تتطلب القيادة التجارية بين الولايات (ونقل المواد الخطرة أو الحمولات المستوجبة للافتات عبر حدود الولايات) حدًا أدنى للعمر قدره 21 في ألاباما، بما يتوافق مع القواعد الفيدرالية. المصدر: الأسئلة الشائعة عن CDL لدى ALEA؛ 49 CFR 391.11."},"30":{"q":"بعد إصدار تصريح متعلّم تجاري (CLP)، كم يجب أن يحتفظ مقدم الطلب في ألاباما بتصريح CLP قبل أن يُسمح له بإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["30 days","14 days","10 days","60 days"],"explanation":"يتطلب القانون الفيدرالي المعتمد من ألاباما الاحتفاظ بتصريح CLP لمدة 14 days على الأقل قبل إمكانية إجراء اختبار مهارات CDL. المصدر: الأسئلة الشائعة عن CDL لدى ALEA؛ 49 CFR 383.25."},"31":{"q":"ما هي مدة صلاحية تصريح المتعلّم التجاري (CLP) في ألاباما، وهل يمكن تجديده؟","options":["180 days، ويمكن تجديده مرة واحدة","360 days، ولا يمكن تجديده","1 year، ويمكن تجديده سنويًا","90 days، ولا يمكن تجديده"],"explanation":"تصريح CLP في ألاباما صالح لمدة 360 days وغير قابل للتجديد؛ وإذا انتهت صلاحيته، فيجب على مقدم الطلب إعادة جميع الاختبارات التحريرية ودفع رسوم تصريح CLP جديد. المصدر: الأسئلة الشائعة عن CDL لدى ALEA."},"32":{"q":"ما نوع رخصة القيادة الأساسية التي يجب أن يحملها مقدم الطلب في ألاباما بالفعل قبل التقدم للحصول على تصريح متعلّم تجاري أو رخصة CDL؟","options":["رخصة قيادة سارية من الفئة Class D في ألاباما","رخصة دراجة نارية سارية من الفئة Class M في ألاباما","تصريح متعلّم فقط","لا يلزم وجود رخصة سابقة"],"explanation":"تتطلب ألاباما من مقدمي الطلبات حمل رخصة قيادة سارية من الفئة Class D (العادية) في ألاباما قبل التقدم للحصول على تصريح CLP أو رخصة CDL. المصدر: الأسئلة الشائعة عن CDL لدى ALEA؛ صفحة متطلبات الوثائق."},"33":{"q":"أي جهة تصدر رخص القيادة التجارية في ألاباما؟","options":["إدارة النقل بولاية ألاباما (ALDOT)","مكتب توثيق المقاطعة","قسم رخص القيادة التابع لوكالة إنفاذ القانون بولاية ألاباما (ALEA)","الإدارة الفيدرالية لسلامة ناقلي البضائع (FMCSA)"],"explanation":"تُصدر رخص CDL في ألاباما من قبل وكالة إنفاذ القانون بولاية ألاباما (ALEA) عبر قسم رخص القيادة التابع لها، وليس عبر دائرة مركبات منفصلة أو ALDOT. المصدر: ALEA Driver License Division."},"34":{"q":"تدريب السائق المبتدئ (ELDT) المطلوب قبل الحصول على رخصة CDL لأول مرة في ألاباما يجب أن يقدّمه مزوّد مدرج أين؟","options":["قائمة المدارس المعتمدة لدى ALEA فقط","سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","أي شركة نقل خاصة بالشاحنات","سجل نظام كليات المجتمع بولاية ألاباما"],"explanation":"منذ Feb 7, 2022، يجب على المتقدمين لرخصة CDL لأول مرة (وبعض الترقيات/التظهيرات) إكمال تدريب ELDT من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA، الذي يجب أن يرفع بيانات الإكمال قبل أن تسمح ألاباما بالاختبار. المصدر: الأسئلة الشائعة عن CDL لدى ALEA؛ 49 CFR part 380."},"35":{"q":"أي إجراء متعلق برخصة CDL لا يتطلب بحد ذاته تدريب السائق المبتدئ (ELDT) قبل الاختبار في ألاباما؟","options":["الحصول على رخصة CDL لأول مرة","الترقية من الفئة Class B إلى الفئة Class A","تجديد رخصة CDL بنفس الفئة والتظهيرات","الحصول على أول تظهير للمواد الخطرة (H)"],"explanation":"ينطبق ELDT على رخص CDL لأول مرة، وترقيات الفئة، والحصول لأول مرة على تظهيرات S أو P أو H. أما التجديد البسيط الذي لا يرقّي الفئة ولا يضيف تظهيرًا مشمولًا فلا يستوجب ELDT. المصدر: 49 CFR part 380؛ الأسئلة الشائعة عن CDL لدى ALEA."},"36":{"q":"مقدم طلب رخصة CDL في ألاباما الذي يقود في التجارة بين الولايات والمطالب باستيفاء المعايير الطبية الفيدرالية يصدّق ذاتيًا تحت أي فئة؟","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"تنطبق فئة Non-Excepted Interstate على السائقين العاملين في التجارة بين الولايات الذين يجب أن يحافظوا على شهادة فاحص طبي سارية من DOT. تتطلب ألاباما التصديق الذاتي ضمن واحدة من أربع فئات وفق 49 CFR 383. المصدر: متطلبات التصديق الذاتي لدى ALEA؛ 49 CFR 383.71."},"37":{"q":"كم عدد فئات التصديق الطبي الذاتي التي يجب أن يختار منها حامل رخصة CDL في ألاباما، وأيها يتطلب الاحتفاظ ببطاقة طبية سارية من DOT؟","options":["فئتان؛ فئة التجارة بين الولايات فقط هي التي تحتاج بطاقة طبية","أربع فئات؛ فئة Non-Excepted Interstate تتطلب بطاقة طبية سارية من DOT","ثلاث فئات؛ لا تتطلب أي منها بطاقة طبية","أربع فئات؛ فئة Excepted Intrastate تتطلب بطاقة طبية سارية من DOT"],"explanation":"تستخدم ألاباما الفئات الفيدرالية الأربع (Non-Excepted Interstate، Excepted Interstate، Non-Excepted Intrastate، Excepted Intrastate). يجب على السائقين الذين يصدّقون ضمن Non-Excepted Interstate تقديم شهادة فاحص طبي من DOT والاحتفاظ بها، صادرة عن فاحص معتمد من FMCSA. المصدر: التصديق الذاتي لدى ALEA؛ 49 CFR 383.71."},"38":{"q":"عند التقدم للحصول على رخصة CDL أو تصريح CLP في ألاباما، أي مجموعة من الوثائق يجب أن يقدّمها مقدم الطلب؟","options":["بطاقة الضمان الاجتماعي فقط","إثبات الهوية، وإثبات رقم الضمان الاجتماعي، وإثبات الإقامة في ألاباما، و(إن لم يكن مواطنًا أمريكيًا) إثبات الوجود القانوني","جواز سفر وفاتورتي خدمات فقط","إثبات الهوية وشهادة الثانوية العامة"],"explanation":"تتطلب ALEA إثباتًا أساسيًا للهوية، وإثباتًا موثقًا لرقم الضمان الاجتماعي، وإثبات الإقامة في ألاباما، وإثبات الوجود القانوني لغير المواطنين؛ ولا يجوز أن تُحتسب الوثيقة نفسها لاستيفاء متطلبين. المصدر: صفحة متطلبات الوثائق والرسوم لدى ALEA."},"39":{"q":"بما أن الحافلة المدرسية التي تنقل 16 شخصًا أو أكثر تُعدّ أيضًا مركبة ركاب، فماذا تتطلب ألاباما إضافة إلى تظهير الحافلة المدرسية (S)؟","options":["رخصة CDL منفصلة من الفئة Class A","تظهير الركاب (P)","تظهير الناقلة الصهريجية (N)","تظهير المقطورات المزدوجة/الثلاثية (T)"],"explanation":"تتطلب ألاباما تظهير الركاب (P) مع تظهير الحافلة المدرسية (S)؛ ويجتاز المتقدمون اختبارات المعرفة العامة والركاب والحافلة المدرسية إضافة إلى اختبار مهارات في حافلة ممثّلة. المصدر: فئات/تظهيرات CDL لدى ALEA؛ دليل Alabama CDL."},"40":{"q":"في ألاباما، ما هو أدنى تركيز للكحول في الدم (BAC) يجعل قيادة مركبة تجارية آلية أمرًا غير قانوني؟","options":["0.02%","0.04%","0.08%","0.10%"],"explanation":"تتبع ألاباما المعيار الفيدرالي للمركبات التجارية الآلية: من غير القانوني تشغيل مركبة تجارية آلية إذا كان تركيز الكحول في دمك 0.04% أو أكثر. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ 49 CFR 383.51."},"41":{"q":"بموجب قاعدة الموافقة الضمنية في ألاباما، ما الذي يُفترض بشأن الشخص الذي يقود مركبة تجارية آلية على طرق ألاباما؟","options":["أنه قد منح موافقته على اختبار الكحول","أنه يجب أن يحمل بطاقة موافقة منفصلة","أنه يتنازل عن الحق في جلسة استماع","أنه يوافق فقط إذا كان مختلًّا بشكل ظاهر"],"explanation":"ينص دليل Alabama CDL على أنك إذا شغّلت مركبة تجارية آلية فسوف تُعدّ قد منحت موافقتك على اختبار الكحول. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ Ala. Code Title 32."},"42":{"q":"في ألاباما، كم سيخسر حامل رخصة CDL رخصته عن أول مخالفة كبرى، مثل القيادة تحت تأثير الكحول بمركبة تجارية آلية أو رفض اختبار الكحول (عند عدم نقل مواد خطرة تحمل لافتات تحذيرية)؟","options":["60 days","120 days","At least 1 year","At least 3 years"],"explanation":"ينتج عن أول مخالفة كبرى (القيادة تحت تأثير الكحول، أو تركيز BAC قدره 0.04+ في مركبة تجارية آلية، أو رفض الاختبار، أو مغادرة موقع الحادث، وغيرها) خسارة رخصة CDL لمدة عام واحد على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ 49 CFR 383.51."},"43":{"q":"في ألاباما، يرتكب سائق أول مخالفة كبرى أثناء تشغيل مركبة تجارية آلية تحمل لافتات تحذيرية للمواد الخطرة. كم تبلغ مدة سحب الأهلية؟","options":["At least 1 year","At least 2 years","At least 3 years","Lifetime"],"explanation":"إذا وقعت أول مخالفة كبرى أثناء تشغيل مركبة تجارية آلية تحمل لافتات تحذيرية للمواد الخطرة، فإن سحب الأهلية يكون لمدة ثلاث سنوات على الأقل بدلًا من سنة واحدة. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ 49 CFR 383.51."},"44":{"q":"في ألاباما، ما هو سحب الأهلية عن مخالفة كبرى ثانية (مثل قيادة ثانية تحت تأثير الكحول بمركبة تجارية آلية)؟","options":["1 year","3 years","10 years","Lifetime"],"explanation":"ينتج عن مخالفة كبرى ثانية خسارة رخصة CDL مدى الحياة. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ 49 CFR 383.51."},"45":{"q":"في ألاباما، يُعامَل رفض الخضوع لاختبار الكحول أثناء تشغيل مركبة تجارية آلية على أنه أي نوع من المخالفات؟","options":["مخالفة مرورية خطيرة (قاعدة الـ 60-day)","مخالفة كبرى (خسارة لا تقل عن سنة واحدة)","مخالفة بسيطة بغرامة فقط","مخالفة أمر إيقاف عن الخدمة"],"explanation":"يُدرَج رفض الخضوع لاختبار الكحول في الدم كمخالفة كبرى في ألاباما، ويستتبع سحب أهلية لا يقل عن سنة واحدة عن أول مخالفة. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ 49 CFR 383.51."},"46":{"q":"أي مما يلي مُدرَج كمخالفة مرورية خطيرة في دليل Alabama CDL؟","options":["القيادة بسرعة 5 mph فوق الحد","السرعة المفرطة (15 mph أو أكثر فوق الحد المعلن)","ملصق تسجيل منتهي الصلاحية","ضوء خلفي محترق"],"explanation":"تشمل المخالفات المرورية الخطيرة السرعة المفرطة، المعرّفة بأنها 15 mph أو أكثر فوق الحد المعلن، إضافة إلى القيادة المتهورة، وتغيير المسار بشكل غير صحيح، والاقتراب الزائد من المركبة الأمامية. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.3."},"47":{"q":"في ألاباما، يُدان حامل رخصة CDL بمخالفتين مروريتين خطيرتين بمركبة تجارية آلية خلال فترة ثلاث سنوات. كم يبلغ سحب الأهلية؟","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان بمركبة تجارية آلية خلال فترة ثلاث سنوات إلى خسارة رخصة CDL لمدة 60 days على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.3؛ 49 CFR 383.51."},"48":{"q":"في ألاباما، يُدان حامل رخصة CDL بثلاث مخالفات مرورية خطيرة بمركبة تجارية آلية خلال فترة ثلاث سنوات. كم يبلغ سحب الأهلية؟","options":["At least 60 days","At least 90 days","At least 120 days","At least 1 year"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة أو أكثر بمركبة تجارية آلية خلال فترة ثلاث سنوات إلى خسارة رخصة CDL لمدة 120 days على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.3؛ 49 CFR 383.51."},"49":{"q":"في ألاباما، ما هو سحب الأهلية عن أول مخالفة لأمر الإيقاف عن الخدمة؟","options":["At least 30 days","At least 90 days","At least 180 days","At least 1 year"],"explanation":"تؤدي أول مخالفة لأمر الإيقاف عن الخدمة إلى خسارة رخصة CDL لمدة 90 days على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.4؛ 49 CFR 383.51."},"50":{"q":"في ألاباما، يرتكب سائق مخالفتين لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات. كم يبلغ سحب الأهلية؟","options":["At least 120 days","At least 1 year","At least 3 years","At least 5 years"],"explanation":"تؤدي مخالفتان لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات إلى خسارة رخصة CDL لمدة سنة واحدة على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.4؛ 49 CFR 383.51."},"51":{"q":"في ألاباما، يرتكب سائق ثلاث مخالفات أو أكثر لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات. كم يبلغ سحب الأهلية؟","options":["At least 1 year","At least 2 years","At least 3 years","Lifetime"],"explanation":"تؤدي ثلاث مخالفات أو أكثر لأمر الإيقاف عن الخدمة خلال فترة عشر سنوات إلى خسارة رخصة CDL لمدة ثلاث سنوات على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.4؛ 49 CFR 383.51."},"52":{"q":"في ألاباما، ما هو سحب الأهلية عن أول مخالفة لمعبر السكة الحديدية مع الطريق السريع بمركبة تجارية آلية؟","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية مع الطريق السريع إلى خسارة رخصة CDL لمدة 60 days على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.5؛ 49 CFR 383.51."},"53":{"q":"في ألاباما، يتلقى حامل رخصة CDL مخالفة ثانية لمعبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات. كم يبلغ سحب الأهلية؟","options":["At least 60 days","At least 120 days","At least 6 months","At least 1 year"],"explanation":"تؤدي مخالفة ثانية لمعبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات إلى خسارة رخصة CDL لمدة 120 days على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.5؛ 49 CFR 383.51."},"54":{"q":"في ألاباما، يتلقى حامل رخصة CDL مخالفة ثالثة لمعبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات. كم يبلغ سحب الأهلية؟","options":["At least 120 days","At least 180 days","At least 1 year","At least 3 years"],"explanation":"تؤدي مخالفة ثالثة لمعبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات إلى خسارة رخصة CDL لمدة سنة واحدة على الأقل. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.5؛ 49 CFR 383.51."},"55":{"q":"في ألاباما، ماذا يحدث إذا وُجد لدى سائق مركبة تجارية آلية أي كمية قابلة للكشف من الكحول لا تزال دون 0.04%؟","options":["لا شيء، فهو دون الحد القانوني","الإيقاف عن الخدمة لمدة 24 hours","سحب أهلية فوري لمدة 1-year","حظر مدى الحياة"],"explanation":"يُوضع سائق المركبة التجارية الآلية الذي لديه أي كمية قابلة للكشف من الكحول دون 0.04% خارج الخدمة لمدة 24 hours. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2."},"56":{"q":"في ألاباما، بعد كم عدد من الإدانات لاستخدام هاتف محمول باليد أثناء قيادة مركبة تجارية آلية تُسحب أهلية رخصة CDL للسائق؟","options":["إدانة واحدة","إدانتان أو أكثر","أربع إدانات أو أكثر","ست إدانات أو أكثر"],"explanation":"تُسحب أهلية رخصة CDL بعد إدانتين أو أكثر بموجب قانون ولاية بشأن استخدام الهاتف المحمول باليد أثناء تشغيل مركبة تجارية آلية: 60 days عن المخالفة الثانية خلال 3 سنوات و120 days عن ثلاث مخالفات أو أكثر خلال 3 سنوات. المصدر: دليل Alabama CDL (ALEA)، القسم 2.9.4."},"57":{"q":"بموجب القواعد الواردة في دليل Alabama CDL، يُحظر إرسال الرسائل النصية أثناء قيادة مركبة تجارية آلية. ويمكن أن تستتبع إدانات السائق غرامة مدنية تصل إلى أي مبلغ؟","options":["Up to $500","Up to $1,000","Up to $2,750","Up to $11,000"],"explanation":"تخضع كل مخالفة لإرسال رسائل نصية أو استخدام هاتف باليد من قبل سائق مركبة تجارية آلية لغرامة مدنية تصل إلى $2,750 (وقد يُغرّم أصحاب العمل بما يصل إلى $11,000). المصدر: دليل Alabama CDL (ALEA)، القسمان 2.9.4 و2.9.5؛ 49 CFR 392."},"58":{"q":"في ألاباما، يؤدي استخدام مركبة تجارية آلية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة إلى أي عقوبة؟","options":["سحب أهلية لمدة 60-day","سحب أهلية لمدة 1-year","سحب أهلية لمدة 3-year","خسارة رخصة CDL مدى الحياة"],"explanation":"يؤدي استخدام مركبة تجارية آلية لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة إلى خسارة رخصة CDL مدى الحياة، دون إعادة إصدار. المصدر: دليل Alabama CDL (ALEA)، القسم 1.3.2؛ 49 CFR 383.51."},"59":{"q":"أي من هذه المخالفات تُعدّ مخالفة مرورية خطيرة بموجب دليل Alabama CDL وليست مخالفة كبرى؟","options":["قيادة مركبة تجارية آلية بتركيز BAC قدره 0.04%","رفض اختبار كيميائي للكحول","الاقتراب الزائد من مركبة أمامية","مغادرة موقع الحادث"],"explanation":"يُدرَج الاقتراب الزائد من المركبة الأمامية كمخالفة مرورية خطيرة (تُحتسب ضمن قاعدة الـ 60/120-day)، بينما القيادة تحت تأثير الكحول ورفض الاختبار ومغادرة موقع الحادث هي مخالفات كبرى تستتبع سحب أهلية لا يقل عن سنة واحدة. المصدر: دليل Alabama CDL (ALEA)، القسمان 1.3.2 و1.3.3."},"60":{"q":"عندما يجب على مركبة تحمل لافتات مواد خطرة أن تتوقف عند تقاطع سكة حديد مع طريق سريع في ولاية ألاباما، على أي مسافة من أقرب قضيب سكة حديدية يجب على السائق التوقف؟","options":["ليس أقل من 10 أقدام وليس أكثر من 25 قدمًا","ليس أقل من 15 قدمًا وليس أكثر من 50 قدمًا","ليس أقل من 25 قدمًا وليس أكثر من 75 قدمًا","ليس أقل من 5 أقدام وليس أكثر من 15 قدمًا"],"explanation":"تشترط ولاية ألاباما على المركبة التي تحمل لافتات مواد خطرة (HazMat) أن تتوقف على مسافة تتراوح بين 15 و50 قدمًا قبل أقرب قضيب سكة حديدية، ثم تتابع السير فقط عندما لا يكون هناك قطار قادم وعندما يمكنها عبور القضبان دون توقف. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 9.6 تقاطعات السكك الحديدية؛ Ala. Code 32-5A-150."},"61":{"q":"بموجب قانون \"Move Over\" في ولاية ألاباما، عندما لا يستطيع سائق على طريق سريع متعدد المسارات إخلاء المسار الأقرب لمركبة طوارئ أو مركبة إنفاذ قانون متوقفة تُظهر أضواء وامضة بشكل آمن، فماذا يجب على السائق أن يفعل؟","options":["التباطؤ إلى سرعة أقل بـ 10 ميل في الساعة على الأقل من حد السرعة المُعلن","التباطؤ إلى سرعة أقل بـ 20 ميل في الساعة على الأقل من حد السرعة المُعلن","التوقف تمامًا حتى تغادر مركبة الطوارئ","التباطؤ إلى سرعة أقل بـ 15 ميل في الساعة على الأقل من حد السرعة المُعلن"],"explanation":"بموجب قانون \"Move Over\" في ولاية ألاباما، يجب على السائق الذي لا يستطيع تغيير المسار بأمان أن يتباطأ إلى سرعة أقل بـ 15 ميل في الساعة على الأقل من حد السرعة المُعلن. المصدر: Ala. Code 32-5A-58.2 (التحرك جانبًا أو تخفيض السرعة عند الاقتراب من مركبات الطوارئ)."},"62":{"q":"ما هو الحد الأقصى لسرعة القيادة على طريق سريع بين الولايات في ألاباما (ما لم يُعلن أو يُصرّح بخلاف ذلك)؟","options":["65 ميل في الساعة","75 ميل في الساعة","80 ميل في الساعة","70 ميل في الساعة"],"explanation":"يحدد قانون ألاباما الحد الأقصى للسرعة على الطرق السريعة بين الولايات بـ 70 ميل في الساعة؛ وعلى الطرق السريعة الأخرى التي تضم أربعة مسارات أو أكثر يكون الحد الأقصى 65 ميل في الساعة. المصدر: Ala. Code 32-5A-171 (الحدود القصوى)."},"63":{"q":"في ألاباما، إذا اضطرت مركبة تجارية إلى التوقف على طريق باتجاه واحد أو طريق مقسّم، فأين يجب وضع أجهزة التحذير الثلاثة من الطوارئ؟","options":["على بُعد 10 أقدام و50 قدمًا و150 قدمًا باتجاه حركة المرور القادمة","على بُعد 25 قدمًا و100 قدم و250 قدمًا باتجاه حركة المرور القادمة","على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","على بُعد 5 أقدام و75 قدمًا و100 قدم باتجاه حركة المرور القادمة"],"explanation":"على طريق باتجاه واحد أو طريق مقسّم، توجّه ولاية ألاباما بوضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 2.8 أجهزة التحذير للمركبات المتوقفة."},"64":{"q":"بموجب قانون الحافلات المدرسية في ولاية ألاباما، متى يجب على سائق مركبة تقابل أو تتجاوز حافلة مدرسية متوقفة تعمل إشاراتها المرئية أن يتوقف توقفًا تامًا؟","options":["فقط عند الاقتراب من خلف الحافلة، وليس من الأمام أبدًا","فقط عندما تكون الحافلة على نفس جانب الطريق الذي يسير عليه السائق","فقط إذا كان الأطفال ظاهرين بشكل مرئي على الطريق","عند الاقتراب من أي من الاتجاهين على طريق عادي ذي مسارين أو طريق غير مقسّم"],"explanation":"تشترط ولاية ألاباما على السائق الذي يقابل أو يتجاوز حافلة مدرسية من أي من الاتجاهين أن يتوقف عندما تكون الحافلة قد توقفت لتحميل أو إنزال الأطفال مع تشغيل إشارتها المرئية، باستثناء الطريق المقسّم كما هو محدد في القانون. المصدر: Ala. Code 32-5A-154."},"65":{"q":"أي موقف يصف الاستثناء الوحيد في ولاية ألاباما من التوقف عند حافلة مدرسية متوقفة تقوم بتحميل أو إنزال الأطفال؟","options":["القيادة في أي مدينة يكون فيها حد السرعة المُعلن 30 ميل في الساعة أو أقل","في أي وقت يكون فيه السائق على بُعد أكثر من 100 قدم من الحافلة","مقابلة الحافلة من الجانب المقابل للطريق على طريق مقسّم منفصل إلى مسارين متقابلين أو أكثر","أي طريق ذي أربعة مسارات، سواء كان مقسّمًا أم لا"],"explanation":"تُعفي ولاية ألاباما السائق من التوقف فقط عند مقابلة حافلة مدرسية متوقفة على الجانب المقابل للطريق على طريق مقسّم يضم أربعة مسارات أو أكثر يسمح بمسارين على الأقل من حركة المرور بالسير في اتجاهين متقابلين. أما على طريق متعدد المسارات غير مقسّم، فيجب على جميع السائقين التوقف. المصدر: Ala. Code 32-5A-154."},"66":{"q":"يجب على حافلة تنقل ركابًا في ألاباما أن تتوقف على أي مسافة من أقرب قضيب سكة حديدية عند تقاطع سكة حديد مع طريق سريع؟","options":["بين 10 و40 قدمًا","بين 20 و60 قدمًا","بين 5 و25 قدمًا","بين 15 و50 قدمًا"],"explanation":"تشترط ولاية ألاباما على الحافلة التي تنقل ركابًا أن تتوقف على مسافة بين 15 و50 قدمًا قبل أقرب قضيب سكة حديدية، وأن تُصغي وتنظر في كلا الاتجاهين، ثم تعبر فقط عندما يمكن القيام بذلك دون توقف على القضبان. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 4.3.5 التوقف عند تقاطعات السكك الحديدية مع الطرق السريعة."},"67":{"q":"على طريق ذي مسارين في ألاباما ينقل حركة المرور في كلا الاتجاهين، أين تُوضع أجهزة التحذير عند توقف مركبة تجارية ميكانيكية (CMV)؟","options":["على بُعد 10 أقدام من المركبة، و200 قدم إلى الأمام و200 قدم إلى الخلف","على بُعد 25 قدمًا من المركبة، و150 قدمًا إلى الأمام والخلف","توضع الأجهزة الثلاثة جميعها على بُعد 100 قدم خلف المركبة فقط","على بُعد 10 أقدام من المركبة، و100 قدم إلى الأمام و100 قدم إلى الخلف"],"explanation":"على طريق ذي مسارين ينقل حركة المرور في كلا الاتجاهين، توجّه ولاية ألاباما بوضع جهاز واحد على بُعد 10 أقدام من المركبة وواحد على بُعد 100 قدم خلفها وواحد على بُعد 100 قدم أمامها، على الكتف أو في المسار. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 2.8 أجهزة التحذير."},"68":{"q":"ما هي الغرامة المقررة لمخالفة قانون \"Move Over\" في ولاية ألاباما؟","options":["$100","$500","$200","$50"],"explanation":"تُعد مخالفة قانون \"Move Over\" في ولاية ألاباما جنحة يعاقب عليها بغرامة مقدارها مئتا دولار ($200). المصدر: Ala. Code 32-5A-58.2."},"69":{"q":"إلى جانب مركبات إنفاذ القانون ومركبات الطوارئ، أي من المركبات المتوقفة التالية التي تُظهر أضواء تحذير/وامضة يُفعّل أيضًا متطلبات قانون \"Move Over\" في ولاية ألاباما؟","options":["مركبة جمع القمامة أو النفايات أو المخلفات أو إعادة التدوير","أي سيارة ركاب مملوكة لشخص خاص مع تشغيل أضواء الخطر","حافلة مدرسية تقوم بإقلال الأطفال","شاحنة توصيل متوقفة بشكل مزدوج في شارع داخل المدينة"],"explanation":"وسّعت ولاية ألاباما قانون \"Move Over\" ليشمل شاحنات السحب ومركبات خدمات المرافق ومركبات الصيانة/الإنشاء/المسح، وكذلك مركبات جمع القمامة أو النفايات أو المخلفات أو إعادة التدوير التي تُظهر أضواء وامضة. المصدر: Ala. Code 32-5A-58.2."},"70":{"q":"ما هو الحد الأقصى لسرعة القيادة في ألاباما على طريق سريع (غير الطريق بين الولايات) يضم أربعة مسارات مرور أو أكثر؟","options":["70 ميل في الساعة","65 ميل في الساعة","60 ميل في الساعة","55 ميل في الساعة"],"explanation":"تحدد ولاية ألاباما السرعة على الطرق السريعة غير الواقعة بين الولايات التي تضم أربعة مسارات أو أكثر بـ 65 ميل في الساعة، بينما تُحدد الطرق بين الولايات بـ 70 ميل في الساعة. المصدر: Ala. Code 32-5A-171."},"71":{"q":"بموجب قاعدة استخدام المسارات في ولاية ألاباما، أين يجب أن تُقاد مركبة تجارية تسير بسرعة أقل من السرعة الطبيعية لحركة المرور؟","options":["في المسار الأوسط في جميع الأوقات","في المسار الأيمن، أو أقرب ما يمكن عمليًا إلى الحافة اليمنى للطريق","في أي مسار، لأن الشاحنات مُعفاة من قواعد المسارات","في المسار الأيسر لإبقاء المسارات اليمنى خالية للاندماج"],"explanation":"تشترط ولاية ألاباما على أي مركبة تسير أبطأ من السرعة الطبيعية لحركة المرور أن تلتزم اليمين (المسار الأيمن أو أقرب ما يمكن عمليًا إلى الحافة اليمنى)، باستثناء حالات تجاوز مركبة أخرى أو التهيؤ لانعطاف يساري. المصدر: Ala. Code 32-5A-80 (القيادة على الجانب الأيمن من الطريق)."},"72":{"q":"إذا كانت مركبة تجارية ميكانيكية (CMV) متوقفة في ألاباما على تلة أو منعطف يحجب رؤية السائقين القادمين، فماذا يجب على السائق أن يفعل بجهاز التحذير الخلفي؟","options":["تحريكه إلى الخلف أكثر بحيث يُحذَّر المرور على بُعد 500 قدم على الأقل","تركه على بُعد 200 قدم بالضبط إلى الخلف بصرف النظر عن العائق","إزالته والاعتماد فقط على أضواء الطوارئ الرباعية للمركبة","وضع الأجهزة الثلاثة جميعها خلف المصد الخلفي مباشرة"],"explanation":"عندما تمنع تلة أو منعطف أو عائق آخر السائقين من رؤية المركبة على بُعد 500 قدم، توجّه ولاية ألاباما بتحريك المثلث الخلفي إلى الخلف على الطريق بحيث يُوفَّر التحذير خلف العائق. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 2.8 أجهزة التحذير."},"73":{"q":"ما هو نطاق الغرامة لأول إدانة بتجاوز حافلة مدرسية متوقفة بشكل غير قانوني في ولاية ألاباما؟","options":["ليس أقل من $150 وليس أكثر من $300","ليس أقل من $50 وليس أكثر من $100","ليس أقل من $500 وليس أكثر من $1,000","مبلغ ثابت قدره $250 بدون نطاق"],"explanation":"تترتب على أول إدانة بتجاوز حافلة مدرسية متوقفة بشكل غير قانوني في ولاية ألاباما غرامة لا تقل عن $150 ولا تزيد عن $300، مع غرامات أشد وخدمة مجتمعية وتعليق للرخصة في حالات التكرار. المصدر: Ala. Code 32-5A-154."},"74":{"q":"ما هي المركبات المُلزمة بالتوقف توقفًا تامًا عند كل تقاطع سكة حديد مع طريق سريع في ولاية ألاباما؟","options":["جميع المركبات التجارية التي يزيد وزنها عن 10,000 رطل دون استثناء","الحافلات التي تنقل ركابًا والمركبات التي تحمل لافتات مواد خطرة","شاحنات الصهاريج الفارغة فقط","المركبات التي تسحب مقطورة من أي نوع فقط"],"explanation":"تشترط ولاية ألاباما على الحافلات التي تنقل ركابًا والمركبات التي تحمل لافتات مواد خطرة (HazMat) (بما في ذلك صهاريج شحن المواد الخطرة المحمّلة أو الفارغة والمركبات التي تنقل أي كمية من الكلور) أن تتوقف عند تقاطعات السكك الحديدية؛ أما المركبات التجارية الميكانيكية العادية فليست مُلزمة بالتوقف ما لم تستدعِ الظروف ذلك. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسمان 2.15 و9.6."},"75":{"q":"ما هو الحد الأقصى القانوني لعرض الحمولة في ألاباما قبل أن يصبح تصريح الحمولة الزائدة الحجم من ALDOT مطلوبًا؟","options":["8 أقدام و0 بوصة","10 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و6 بوصات"],"explanation":"الحد الأقصى القانوني القياسي لعرض الحمولة في ألاباما هو 8 أقدام و6 بوصات (102 inches)؛ وأي عرض أكبر من ذلك يتطلب تصريح حمولة زائدة الحجم من إدارة النقل في ولاية ألاباما (ALDOT). المصدر: لوائح تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لـ ALDOT."},"76":{"q":"ما هو الحد الأقصى القانوني لارتفاع الحمولة في ألاباما قبل أن يصبح تصريح الحمولة الزائدة الحجم مطلوبًا؟","options":["13 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و0 بوصة","12 قدمًا و6 بوصات"],"explanation":"تحدد ولاية ألاباما الحد الأقصى القانوني لارتفاع المركبة/الحمولة بـ 13 قدمًا و6 بوصات؛ والحمولات التي تتجاوز ذلك تتطلب تصريح حمولة زائدة الحجم من ALDOT، والارتفاعات التي تزيد عن 15 قدمًا و6 بوصات تتطلب مرافقة بعمود قياس ارتفاع أمامي. المصدر: لوائح تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لـ ALDOT."},"77":{"q":"على منحدر طويل وشديد الانحدار في التضاريس الجبلية في ألاباما، ما هو الغرض الصحيح من منحدر هروب المركبات الجامحة؟","options":["إيقاف مركبة تعطّلت مكابحها باستخدام طبقة من المواد السائبة والناعمة","توفير منطقة استراحة مرصوفة للشاحنات لتبريد مكابحها طواعية","العمل كمسار فحص إلزامي لجميع المركبات التجارية الميكانيكية النازلة على المنحدر","السماح للمركبات الأسرع بتجاوز الشاحنات البطيئة أثناء الصعود"],"explanation":"تُبنى منحدرات الهروب على المنحدرات الشديدة لإيقاف المركبات الجامحة بأمان باستخدام طبقة طويلة من المواد السائبة والناعمة؛ وينبغي على السائقين معرفة مواقع هذه المنحدرات على مسارهم. تتضمن منحدرات I-59 في ألاباما بالقرب من Lookout/Sand Mountain منحدرات هروب من هذا النوع. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 2.16 القيادة في الجبال / منحدرات الهروب."},"78":{"q":"خلال كم دقيقة يجب على سائق مركبة تجارية ميكانيكية (CMV) في ألاباما يتوقف على طريق أو كتف أن يضع أجهزة التحذير المطلوبة من الطوارئ؟","options":["10 دقائق","5 دقائق","15 دقيقة","30 دقيقة"],"explanation":"إذا اضطرت مركبة تجارية ميكانيكية (CMV) إلى التوقف على طريق أو كتف في ألاباما، فيجب على السائق وضع أجهزة التحذير من الطوارئ خلال عشر دقائق. المصدر: دليل CDL الخاص بـ ALEA في ألاباما، القسم 2.8 أجهزة التحذير للمركبات المتوقفة."},"79":{"q":"عند الاقتراب من مركبة طوارئ متوقفة على طريق ذي مسارين في ألاباما حيث يستحيل التحرك جانبًا ويكون حد السرعة المُعلن 45 ميل في الساعة، فماذا يجب على السائق أن يفعل؟","options":["الحفاظ على الحد المُعلن مع تشغيل أضواء الطوارئ الرباعية","التوقف توقفًا تامًا في مسار السير","التحرك بعيدًا قدر الإمكان داخل المسار والتباطؤ إلى 15 ميل في الساعة أقل من الحد المُعلن (30 ميل في الساعة)","التباطؤ إلى 20 ميل في الساعة بالضبط بصرف النظر عن الحد المُعلن"],"explanation":"على طريق ذي مسارين في ألاباما، يجب على السائق أن يتحرك بعيدًا قدر الإمكان عن مركبة الطوارئ داخل المسار وأن يتباطأ إلى 15 ميل في الساعة أقل من الحد المُعلن عندما يكون ذلك الحد 25 ميل في الساعة أو أكثر (هنا 45 - 15 = 30 ميل في الساعة). المصدر: Ala. Code 32-5A-58.2."},"80":{"q":"ما هي الجهة التي تُصدر رخص القيادة التجارية (CDLs) وتدير اختبارات CDL في ولاية ألاباما؟","options":["إدارة النقل في ولاية ألاباما (ALDOT)","وكالة إنفاذ القانون في ولاية ألاباما (ALEA)، قسم رخص القيادة","إدارة الإيرادات في ولاية ألاباما، قسم المركبات الآلية","الإدارة الفيدرالية لسلامة الناقلين بالمركبات الآلية (FMCSA)"],"explanation":"تُصدر رخص CDL في ألاباما وتُختبر من قبل وكالة إنفاذ القانون في ولاية ألاباما (ALEA)، قسم رخص القيادة. ويُنشر دليل CDL الخاص بألاباما من قِبل ALEA، ويُجرى اختبار المعرفة/المهارات في مكاتب رخص القيادة التجارية التابعة لـ ALEA. المصدر: دليل CDL الخاص بألاباما (ALEA)، المقدمة؛ قسم رخص القيادة في ALEA."},"81":{"q":"كيف يحجز مقدم الطلب موعدًا لاختبار المعرفة أو المهارات الخاص بـ CDL في ولاية ألاباما؟","options":["بالحضور دون موعد مسبق إلى أي مكتب لوحات/رخص في المقاطعة","بالتقديم عبر الإنترنت إلى FMCSA، التي تخصص له مركز اختبار","بإرسال طلب خطي بالبريد إلى ALDOT وانتظار تحديد موعد","بحجز موعد في مكتب رخص القيادة التجارية التابع لـ ALEA عبر نظام الحجز الإلكتروني على alea.gov"],"explanation":"يوجّه دليل CDL الخاص بألاباما مقدمي الطلبات إلى حجز موعد لاختبار المعرفة أو المهارات في مكتب رخص القيادة التجارية التابع لـ ALEA؛ وضمن \"Driver License\" / \"Online Services\" على alea.gov، يستخدم مقدمو الطلبات خيار \"Schedule DL Appointment\". المصدر: دليل CDL الخاص بألاباما (ALEA)، صفحة مكاتب رخص القيادة التجارية."},"82":{"q":"في ألاباما، ما الذي يجب على مقدم الطلب الحصول عليه والاحتفاظ به قبل أن يُسمح له بإجراء اختبار مهارات CDL لأول مرة؟","options":["تصديق المواد الخطرة (Hazardous Materials)","إعفاء طبي فيدرالي من DOT","حساب خطة التسجيل الدولية (IRP)","تصريح متعلّم القيادة التجارية (CLP)"],"explanation":"يجب على مقدم طلب CDL لأول مرة أو الراغب في الترقية أن يُصدر له أولًا تصريح متعلّم القيادة التجارية (CLP) عن طريق اجتياز اختبار(ات) المعرفة المطلوبة. ويجب بعد ذلك الاحتفاظ بـ CLP قبل إجراء اختبار المهارات. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1؛ الأسئلة الشائعة حول CDL لدى ALEA."},"83":{"q":"بموجب قواعد ولاية ألاباما (والقواعد الفيدرالية)، كم يجب الاحتفاظ بـ CLP قبل أن يتمكن حامله من إجراء اختبار مهارات CDL؟","options":["7 أيام على الأقل","30 يومًا على الأقل","14 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"تتبع ولاية ألاباما الاشتراط الفيدرالي بأن يُحتفظ بـ CLP لمدة 14 يومًا كحد أدنى قبل أن يتمكن حامله من إجراء اختبار مهارات CDL. المصدر: الأسئلة الشائعة حول CDL لدى ALEA؛ 49 CFR 383.25 كما هو مطبّق في ألاباما."},"84":{"q":"ما هي مدة صلاحية تصريح متعلّم القيادة التجارية (CLP) في ألاباما، وهل يمكن تجديده؟","options":["صالح لمدة 180 يومًا ويمكن تجديده مرة واحدة","صالح لمدة سنة واحدة ويمكن تجديده مرتين","صالح لمدة 30 يومًا وغير قابل للتجديد","صالح لمدة 360 يومًا وغير قابل للتجديد"],"explanation":"تذكر ALEA أن CLP صالح لمدة 360 يومًا وغير قابل للتجديد؛ وإذا انتهت صلاحيته، يجب على مقدم الطلب إعادة الاختبار للحصول على CLP جديد. المصدر: الأسئلة الشائعة حول CDL لدى ALEA."},"85":{"q":"قبل إجراء اختبار CDL لأول مرة في ألاباما، ما هو التدريب الذي يجب على مقدم الطلب إكماله؟","options":["دورة قيادة دفاعية معتمدة من محاكم ولاية ألاباما","دورة سلامة في مكان العمل من OSHA مدتها 40 ساعة","تدريب السائق المبتدئ (ELDT) من خلال مزوّد مسجّل لدى FMCSA","دورة صفية تديرها ALEA تُعقد فقط في مكتب Montgomery"],"explanation":"تدريب السائق المبتدئ (ELDT) مطلوب لأي شخص يحصل على CDL لأول مرة (ولبعض الترقيات/التصديقات). ويجب إكمال التدريب من خلال مزوّد مُدرج في سجل مزوّدي التدريب لدى FMCSA قبل الاختبار. المصدر: مواد التصديق الذاتي/الأسئلة الشائعة حول CDL لدى ALEA؛ قاعدة ELDT الخاصة بـ FMCSA السارية اعتبارًا من 7 فبراير 2022."},"86":{"q":"ما هو اختبار المعرفة الذي يجب على كل مقدم طلب CDL في ألاباما اجتيازه، بصرف النظر عن فئة المركبة أو التصديقات؟","options":["اختبار المكابح الهوائية","اختبار المركبات المركّبة","اختبار المواد الخطرة","اختبار المعرفة العامة"],"explanation":"يُدرج دليل CDL الخاص بألاباما اختبار المعرفة العامة باعتباره الاختبار الذي يجريه جميع مقدمي الطلبات؛ أما اختبارات المعرفة الأخرى (المكابح الهوائية، المركبات المركّبة، نقل الركاب، المواد الخطرة، الصهاريج، المقطورات المزدوجة/الثلاثية، الحافلات المدرسية) فتعتمد على الفئة والتصديقات المطلوبة. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.1.1 اختبارات المعرفة."},"87":{"q":"وفقًا لدليل CDL الخاص بألاباما، يتألف اختبار مهارات CDL من أي من المراحل الثلاث التالية؟","options":["الاختبار الكتابي، فحص النظر، واختبار الطريق","الوصل/الفصل، الرجوع للخلف، وفحص المكابح الهوائية","الفحص قبل الرحلة، القيادة الدفاعية، والقيادة الليلية","فحص المركبة، التحكم الأساسي بالمركبة، والقيادة على الطريق"],"explanation":"يذكر الدليل أن اختبار مهارات CDL يتكون من ثلاث مراحل: فحص المركبة، والتحكم الأساسي بالمركبة، والقيادة على الطريق. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.1.2 اختبارات المهارات."},"88":{"q":"بأي ترتيب يجب إجراء مراحل اختبار مهارات CDL الثلاث في ألاباما؟","options":["بأي ترتيب يختاره مقدم الطلب في يوم الاختبار","القيادة على الطريق أولًا، ثم التحكم الأساسي، ثم فحص المركبة","بالترتيب المُدرج (فحص المركبة، ثم التحكم الأساسي بالمركبة، ثم القيادة على الطريق)، مع اجتياز كل مرحلة قبل الانتقال إلى التالية","التحكم الأساسي بالمركبة أولًا، ثم القيادة على الطريق، ثم فحص المركبة"],"explanation":"ينص دليل CDL الخاص بألاباما على ما يلي: \"يجب عليك إجراء المراحل بالترتيب المُدرج ويجب اجتياز كل مرحلة قبل الانتقال إلى التالية\" — فحص المركبة، ثم التحكم الأساسي بالمركبة، ثم القيادة على الطريق. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.1.2."},"89":{"q":"ما نوع المركبة التي يجب على مقدم الطلب استخدامها لإجراء اختبار مهارات CDL في ألاباما؟","options":["مركبة ممثّلة للفئة/النوع الذي يرغب مقدم الطلب في الحصول على رخصة له","أي سيارة ركاب، لأنه يتم تقييم عادات القيادة فقط","مركبة يوفّرها موقع اختبار ALEA مجانًا","أي مركبة تجارية، بصرف النظر عن الفئة، طالما أنها مزوّدة بمكابح هوائية"],"explanation":"يشترط الدليل أن يُجرى اختبار المهارات في نوع المركبة التي يرغب مقدم الطلب في الحصول على رخصة لها؛ ويمكن أن تُقيّد فئة المركبة المستخدمة رخصة CDL الصادرة. ولا يمكن استخدام مركبة تحمل مكوّنات موسومة أو معلّمة. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.1.2."},"90":{"q":"خلال اختبار مهارات فحص المركبة الخاص بـ CDL في ألاباما، ما المطلوب من مقدم الطلب فعله عند كل عنصر؟","options":["فحص كل عنصر بصمت بينما يقيس الفاحص الوقت المستغرق","الإشارة إلى العنصر أو لمسه وتسميته، وشرح ما يتم فحصه ولماذا للفاحص","كتابة وصف لكل عنصر على نموذج فحص","ذكر العناصر شفهيًا فقط دون لمسها أو الإشارة إليها"],"explanation":"يذكر الدليل أنه خلال اختبار فحص المركبة يجب عليك الإشارة إلى العنصر الذي تفحصه/لمسه وتسميته وشرح ما تفحصه ولماذا للفاحص. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.1.2، فحص المركبة."},"91":{"q":"ماذا يقيّم جزء التحكم الأساسي بالمركبة من اختبار مهارات CDL في ألاباما؟","options":["معرفة قواعد وضع لافتات المواد الخطرة","المهارة في تحريك المركبة إلى الأمام والخلف وإدارتها داخل منطقة محددة","القدرة على قراءة وتفسير لافتات الطرق السريعة","القدرة على إكمال سجل قيادة يومي"],"explanation":"يقيس اختبار التحكم الأساسي بالمركبة مهارة مقدم الطلب في التحكم بالمركبة — تحريكها إلى الأمام والخلف وإدارتها داخل منطقة محددة ومعلّمة، مع شرح الفاحص لكيفية تنفيذ كل تمرين. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.1.2، التحكم الأساسي بالمركبة."},"92":{"q":"ما هي الوثيقة التي يحتاج مقدم طلب CDL في ألاباما عادةً إلى تقديمها كإثبات لرقم الضمان الاجتماعي الخاص به عند التقديم؟","options":["إثبات رقم الضمان الاجتماعي لمقدم الطلب (مثل بطاقة الضمان الاجتماعي)","إفادة موثّقة من صاحب عمل حالي فقط","نسخة من أحدث إقرار ضريبي فيدرالي لمقدم الطلب فقط","خطاب تخصيص رقم DOT لناقل بالمركبات"],"explanation":"يجب على مقدمي طلبات CDL في ألاباما تقديم إثبات لرقم الضمان الاجتماعي الخاص بهم إلى جانب الإثبات المطلوب للهوية/الإقامة ورخصة قيادة سارية في ألاباما (من الفئة Class D). المصدر: متطلبات الوثائق لقسم رخص القيادة في ALEA؛ مواد طلب CDL لدى ALEA."},"93":{"q":"تشترط اللوائح الفيدرالية المعتمدة في ألاباما على حاملي CDL لمركبات الفئة A أو B أو C التصديق الذاتي بالاختيار من بين كم فئة من فئات التشغيل التجاري؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"تشترط إفادة التصديق الذاتي لـ CDL في ألاباما على السائق التصديق على واحدة من أربع فئات للتشغيل. المصدر: إفادة التصديق الذاتي لـ CDL لدى ALEA (تستشهد بـ 49 CFR 383, 384, 390, 391)؛ دليل CDL الخاص بألاباما القسم 1.2."},"94":{"q":"في إفادة التصديق الذاتي لـ CDL في ألاباما، أي واحدة من الفئات الأربع تتطلب من السائق حمل وتقديم شهادة فاحص طبي معتمد من DOT؟","options":["Excepted Interstate (مُستثناة بين الولايات)","Non-excepted Interstate (غير مُستثناة بين الولايات)","Excepted Intrastate (مُستثناة داخل الولاية)","Non-excepted Intrastate (غير مُستثناة داخل الولاية، مع قيد إعفاء طبي K في ألاباما)"],"explanation":"تُدرج إفادة ألاباما أربع فئات: Non-excepted Interstate (خاضعة لـ 49 CFR part 391 — شهادة طبية من DOT مطلوبة)، وExcepted Interstate، وNon-excepted Intrastate، وExcepted Intrastate. وحدها فئة Non-excepted Interstate تتطلب حمل/تقديم بطاقة طبية من DOT؛ أما الفئات الثلاث الأخرى فتقدّم الإفادة فقط. المصدر: إفادة التصديق الذاتي لـ CDL لدى ALEA."},"95":{"q":"وفقًا لدليل CDL الخاص بألاباما، إذا كان السائق يعمل في التجارة بين الولايات وداخل الولاية معًا، فأي حالة تصديق ذاتي يجب أن يختارها؟","options":["التجارة داخل الولاية (Intrastate)","التجارة المُستثناة داخل الولاية (Excepted intrastate)","التجارة بين الولايات (Interstate)","أيهما يؤديه في الأغلب"],"explanation":"يذكر الدليل أنه إذا كنت تعمل في التجارة داخل الولاية وبين الولايات معًا، فيجب عليك اختيار التجارة بين الولايات (interstate) عند التصديق الذاتي. المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.2.1."},"96":{"q":"اعتبارًا من التغيير الساري في 23 يونيو 2025، كيف تُنقل عادةً شهادة الفاحص الطبي من DOT لحامل CDL في ألاباما إلى ALEA؟","options":["يجب على السائق إرسال البطاقة الورقية الأصلية بالبريد إلى مكتب قضاء التركات في المقاطعة","يقدّمها الفاحص الطبي المعتمد إلكترونيًا إلى FMCSA، التي تنقلها إلى ولاية تسجيل السائق","يرفع السائق نسخة ممسوحة ضوئيًا من البطاقة الورقية على بوابة تصاريح ALDOT","يجمع مفتشو ALDOT البطاقة عند محطات الوزن ويحيلونها إلى ALEA"],"explanation":"اعتبارًا من 23 يونيو 2025، تقبل ALEA التصديقات الطبية من DOT إلكترونيًا فقط: يقدّم الفاحص الطبي المعتمد من FMCSA النتيجة إلكترونيًا إلى FMCSA، التي تحيلها إلى ولاية تسجيل السائق. ولم تعد البطاقات الورقية والرفع الذاتي مقبولة؛ ويتحقق السائقون من سجلهم على alabamadl.alea.gov. المصدر: بيان صحفي لـ ALEA بعنوان \"Big Changes for Alabama CDL Holders\"؛ الأسئلة الشائعة حول CDL لدى ALEA."},"97":{"q":"إذا أخفق حامل CDL من فئة Non-excepted Interstate في ألاباما في الاحتفاظ بحالة طبية \"معتمدة\" (certified) سارية في الملف، فما هي العاقبة؟","options":["يصبح \"غير معتمد\" (not-certified) وقد يفقد رخصة CDL الخاصة به","تُخفَّض رخصة CDL تلقائيًا إلى CLP لمدة 90 يومًا","يتلقى تحذيرًا خطيًا لمرة واحدة دون أي تأثير على الرخصة","لا شيء، لأن البطاقة الطبية اختيارية لحاملي CDL"],"explanation":"يحذّر دليل CDL الخاص بألاباما من أن السائق المطالَب بحالة طبية \"معتمدة\" والذي يخفق في توفيرها والحفاظ على تحديثها يصبح \"غير معتمد\" وقد يفقد رخصة CDL (يمكن تخفيض/إلغاء رخصة CDL). المصدر: دليل CDL الخاص بألاباما (ALEA)، القسم 1.2 متطلبات التوثيق الطبي."},"98":{"q":"في ألاباما، متى يكون مطلوبًا عمومًا أن يكون التصديق الذاتي لحامل CDL (والبطاقة الطبية، إن وُجدت) في الملف بالنسبة لتجديد الرخصة التجارية؟","options":["يُقدّم في موعد أقصاه 10 أيام قبل تجديد رخصة القيادة التجارية","يُقدّم فقط بعد إرسال الرخصة المجدّدة بالبريد","يُقدّم خلال 30 يومًا بعد انتهاء صلاحية الرخصة","يُقدّم مرة واحدة فقط ولا يُحدّث مجددًا أبدًا"],"explanation":"توجّه إفادة التصديق الذاتي لـ CDL لدى ALEA السائقين إلى تقديم الإفادة (والبطاقة الطبية، إن وُجدت) في موعد أقصاه 10 أيام قبل تجديد رخصة القيادة التجارية؛ والإخفاق في إعادة النموذج قد يؤدي إلى إلغاء رخصة CDL. المصدر: إفادة التصديق الذاتي لـ CDL لدى ALEA."},"99":{"q":"ما هي دورة التجديد/الصلاحية القياسية لرخصة CDL في ألاباما، ومتى تنتهي صلاحيتها؟","options":["تُجدّد كل سنتين وتنتهي صلاحيتها في نهاية السنة","تُجدّد كل 10 سنوات وتنتهي صلاحيتها في 1 يناير","تُجدّد وفق دورة مدتها 8 سنوات وتنتهي صلاحيتها في يوم ميلاد السائق","لا تنتهي صلاحيتها أبدًا بمجرد إصدار CDL لأول مرة"],"explanation":"تُصدر/تُجدّد ولاية ألاباما رخص القيادة، بما في ذلك رخص CDL، وفق دورة مدتها 8 سنوات، تنتهي صلاحيتها في يوم ميلاد السائق؛ ويمكن تجديد رخصة CDL في وقت مبكر يصل إلى 180 يومًا قبل انتهاء الصلاحية ولا توجد فترة سماح. (يستمر تحقق TSA لتصديق المواد الخطرة (Hazmat) لمدة 5 سنوات فقط.) المصدر: قسم رخص القيادة في ALEA؛ إرشادات تجديد CDL في ألاباما."}}};
